/* AUTO-GENERATED — Ohio Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["OH"] = {"code":"OH","name":"Ohio","agency":"Ohio BMV","agencyShort":"BMV","handbook":"https://dam.assets.ohio.gov/image/upload/publicsafety.ohio.gov/hsy7605.pdf","links":{},"en":[{"q":"On Ohio highways, what is the maximum legal width of a vehicle, including its load, without a special hauling permit?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","8 feet 2 inches (98 inches)"],"answer":1,"explanation":"Ohio Revised Code 5577.05 sets the maximum vehicle width at 102 inches (8 feet 6 inches), including load. Anything wider requires an ODOT special hauling permit.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and load on Ohio highways without a permit?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","14 feet 6 inches"],"answer":2,"explanation":"Per Ohio Revised Code 5577.05, the maximum height is 13 feet 6 inches (13.5 feet), with or without load. The driver is responsible for clearing overpasses and structures.","handbook":"","hbref":""},{"q":"In Ohio, what is the maximum length of a semitrailer operated in a tractor-semitrailer combination without a permit?","options":["48 feet","53 feet","57 feet","45 feet"],"answer":1,"explanation":"Ohio Revised Code 5577.05 allows a semitrailer up to 53 feet long when operated in a commercial tractor-semitrailer combination, consistent with the federal national network standard.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of a vehicle and load that may be carried on Ohio highways without a special hauling permit?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"answer":1,"explanation":"Ohio Revised Code 5577.04 limits the maximum overall gross weight imposed on the road surface to 80,000 pounds, the same as the federal Interstate limit.","handbook":"","hbref":""},{"q":"Under Ohio law, the weight on any single axle of a vehicle may not exceed what amount?","options":["18,000 pounds","22,400 pounds","20,000 pounds","24,000 pounds"],"answer":2,"explanation":"Ohio Revised Code 5577.04 caps the maximum single axle weight at 20,000 pounds, matching the federal single-axle standard.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group on Ohio's interstate system?","options":["32,000 pounds","36,000 pounds","38,000 pounds","34,000 pounds"],"answer":3,"explanation":"Ohio Revised Code 5577.04 sets the maximum tandem axle weight at 34,000 pounds, consistent with the federal tandem-axle limit.","handbook":"","hbref":""},{"q":"What is the maximum length of any single (non-trailer) vehicle other than a bus or recreational vehicle on Ohio highways without a permit?","options":["40 feet","50 feet","45 feet","53 feet"],"answer":1,"explanation":"Ohio Revised Code 5577.05 limits a single vehicle (other than specially listed vehicles such as buses) to 50 feet in length.","handbook":"","hbref":""},{"q":"Which Ohio state agency issues oversize/overweight special hauling permits for travel on state, federal, and interstate highways?","options":["The Ohio Bureau of Motor Vehicles (BMV)","The Ohio State Highway Patrol","The Public Utilities Commission of Ohio (PUCO)","The Ohio Department of Transportation (ODOT)"],"answer":3,"explanation":"The Ohio Department of Transportation (ODOT) issues special hauling permits, processed electronically through the Ohio Hauling Permit System (ODOT Special Hauling Permits).","handbook":"","hbref":""},{"q":"In a tractor-semitrailer-trailer (double) combination on Ohio highways, what is the maximum length of each semitrailer or trailer without a permit?","options":["28 feet 6 inches","33 feet","27 feet","30 feet"],"answer":0,"explanation":"Ohio Revised Code 5577.05 limits each semitrailer or trailer to 28 feet 6 inches when operated in a commercial tractor-semitrailer-trailer or tractor-semitrailer-semitrailer combination.","handbook":"","hbref":""},{"q":"A truck combination on an Ohio highway is too heavy for legal limits. Which type of permit must the operator obtain before traveling?","options":["A wide-load endorsement on the CDL","An ODOT special hauling permit","A federal FMCSA overweight waiver","A county-issued road bond certificate"],"answer":1,"explanation":"Per ODOT, any vehicle or load exceeding Ohio's legal size or weight limits must obtain a special hauling permit from ODOT before operating on state, federal, or interstate highways.","handbook":"","hbref":""},{"q":"On Ohio highways, what is the maximum length for combinations of vehicles not otherwise specifically provided for (e.g., a general tractor-semitrailer-trailer combination)?","options":["60 feet","75 feet","65 feet","70 feet"],"answer":2,"explanation":"Ohio Revised Code 5577.05 sets a maximum of 65 feet for any other combination of vehicles not otherwise specified.","handbook":"","hbref":""},{"q":"The federal bridge formula adopted in Ohio law for multiple-axle groups is W = 500((LN/(N-1)) + 12N + 36). In this formula, what does 'L' represent?","options":["The legal load rating of the bridge","The distance in feet between the extreme (first and last) axles of the group","The length of the longest trailer in the combination","The total licensed gross weight of the vehicle"],"answer":1,"explanation":"In the bridge formula stated in Ohio Revised Code 5577.04(C), L is the distance in feet between the front and rearmost axles of the group, N is the number of axles, and W is the maximum allowable gross weight.","handbook":"","hbref":""},{"q":"Under Ohio's special weight provisions, by what percentage may a qualifying farm, log, coal, or solid-waste truck exceed the normal weight limits when hauling from production to the first point of delivery?","options":["5 percent","10 percent","7.5 percent","12.5 percent"],"answer":2,"explanation":"Ohio Revised Code 5577.042 allows qualifying farm, log, coal, and solid-waste haul vehicles to exceed the weight provisions by no more than 7.5 percent under the described conditions.","handbook":"","hbref":""},{"q":"During which months does Ohio's 7.5 percent weight variance for farm trucks, log trucks, and farm machinery NOT apply?","options":["February and March","January and February","March and April","November and December"],"answer":0,"explanation":"Ohio Revised Code 5577.042 specifies that the 7.5 percent variance does not apply during February and March for farm trucks, log trucks, or farm machinery (the seasonal frost/thaw period).","handbook":"","hbref":""},{"q":"Ohio's 7.5 percent agricultural/forest-products weight variance under ORC 5577.042 does NOT apply on which roadways?","options":["County roads","Interstate highways","Township roads","Municipal streets"],"answer":1,"explanation":"Ohio Revised Code 5577.042 states the 7.5 percent variance does not apply on interstate highways (or on roads subject to specially reduced maximum weights).","handbook":"","hbref":""},{"q":"Under ODOT rules, a load is classified as a 'superload' when its gross weight exceeds which amount?","options":["80,000 pounds","100,000 pounds","120,000 pounds","150,000 pounds"],"answer":2,"explanation":"Per ODOT's Operational Guide, a superload is any vehicle/load with a gross weight over 120,000 pounds (or width over 14 feet or height over 14 feet 6 inches), requiring additional review such as bridge/structural analysis.","handbook":"","hbref":""},{"q":"On Ohio's non-interstate (general highway) system, two successive axles spaced more than 4 feet apart may carry up to 34,000 pounds plus 1,000 pounds per additional foot, but not more than what maximum?","options":["38,000 pounds","42,000 pounds","44,000 pounds","40,000 pounds"],"answer":3,"explanation":"Ohio Revised Code 5577.04 provides that on the non-interstate system, two successive axles more than 4 feet apart may carry 34,000 pounds plus 1,000 pounds per foot over 4 feet, up to a maximum of 40,000 pounds.","handbook":"","hbref":""},{"q":"Per ODOT escort rules, a vehicle/load wider than what dimension requires one lead (front) escort vehicle on a two-lane Ohio highway?","options":["12 feet","13 feet","11 feet","10 feet"],"answer":1,"explanation":"Per ODOT's permit escort requirements, one lead escort is required for any vehicle/load with an overall width greater than 13 feet; loads over 14 feet 6 inches wide require both a lead and a rear escort.","handbook":"","hbref":""},{"q":"Under ODOT permit rules, an oversize load less than 12 feet wide is generally permitted to travel during what daily window?","options":["Only between 9:00 a.m. and 3:00 p.m.","From 30 minutes before sunrise to 30 minutes after sunset","From one hour after sunrise to one hour before sunset","Only during full daylight hours, sunrise to sunset"],"answer":1,"explanation":"Per ODOT, oversize loads under 12 feet wide may travel seven days a week (excluding holidays) from 30 minutes before sunrise to 30 minutes after sunset; loads 12 feet wide or wider must follow the specific times stated on the permit.","handbook":"","hbref":""},{"q":"On Ohio's interstate system, two consecutive sets of tandem axles may each carry 34,000 pounds provided the distance between the first and last axles of the two sets is at least how many feet?","options":["30 feet","40 feet","36 feet","34 feet"],"answer":2,"explanation":"Ohio Revised Code 5577.04 allows two consecutive sets of tandem axles to carry 34,000 pounds each only when the overall distance between the first and last axles of the consecutive sets is 36 feet or more.","handbook":"","hbref":""},{"q":"In Ohio, which CDL class is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, provided the towed unit has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Ohio's Class A CDL covers combination vehicles with a GCWR of 26,001 lbs or more where the towed unit's GVWR exceeds 10,000 lbs. Source: Ohio BMV CDL Classes page (bmv.ohio.gov/dl-cdl-classes.aspx) and 49 CFR 383.91 as adopted in Ohio.","handbook":"","hbref":""},{"q":"An Ohio driver operates a single straight truck with a GVWR of 30,000 pounds that does not tow any trailer over 10,000 pounds. Which CDL class is appropriate?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"Ohio's Class B CDL covers any single vehicle with a GVWR of 26,001 lbs or more, and may tow a trailer not exceeding 10,000 lbs GVWR. Source: Ohio BMV CDL Classes page (bmv.ohio.gov/dl-cdl-classes.aspx).","handbook":"","hbref":""},{"q":"Under Ohio rules, a vehicle that does not meet the weight thresholds for Class A or B but is designed to transport 16 or more passengers (including the driver) or hazardous materials requiring placards falls under which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"Ohio's Class C CDL applies to vehicles under the Class A/B weight thresholds that carry 16+ persons (including the driver) or placardable hazardous materials. Source: Ohio BMV CDL Classes page (bmv.ohio.gov/dl-cdl-classes.aspx).","handbook":"","hbref":""},{"q":"What is the minimum age to be issued an Ohio CDL restricted to INTRASTATE (within-Ohio) commercial driving only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Ohio issues an intrastate-only CDL beginning at age 18; drivers under 21 are limited to commerce within Ohio. Source: Ohio BMV CDL eligibility (bmv.ohio.gov) and ORC 4506.10.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in INTERSTATE commerce on an Ohio CDL?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Interstate commercial driving requires the driver to be at least 21. Ohio drivers aged 18-20 hold an intrastate-only CDL. Source: Ohio BMV CDL eligibility and 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Which endorsement letter is required on an Ohio CDL to transport hazardous materials in amounts that require the vehicle to be placarded?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement X"],"answer":0,"explanation":"The H (HazMat) endorsement authorizes transport of placardable hazardous materials. Source: Ohio BMV CDL Classes/endorsements page and 49 CFR 383.93.","handbook":"","hbref":""},{"q":"An Ohio driver who hauls liquids or gases in bulk in a permanently mounted tank must hold which endorsement?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement S"],"answer":1,"explanation":"The N (Tank Vehicle) endorsement is required to operate a tank vehicle carrying liquid or gaseous materials in bulk. Source: Ohio BMV endorsement information and 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which Ohio CDL endorsement is required to pull double or triple trailers?","options":["Endorsement P","Endorsement S","Endorsement T","Endorsement D"],"answer":2,"explanation":"The T endorsement authorizes operation of double/triple trailer combinations and is obtained by passing the doubles/triples knowledge test. Source: Ohio BMV endorsement information and 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which endorsement does an Ohio CDL holder need to drive a commercial vehicle designed to carry 16 or more passengers including the driver (other than a school bus)?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"answer":1,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to carry 16 or more people including the driver. Source: Ohio BMV endorsement information and 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In Ohio, before a driver can be issued the School Bus (S) endorsement, which other endorsement must they also obtain?","options":["The H (HazMat) endorsement","The N (Tanker) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"answer":2,"explanation":"Federal and Ohio rules require the S (School Bus) endorsement to be paired with the P (Passenger) endorsement, since a school bus carries passengers. Source: Ohio BMV endorsement information and 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Before being granted the HazMat (H) endorsement, an Ohio CDL applicant must pass which additional screening beyond the written HazMat knowledge test?","options":["A TSA security threat assessment including fingerprinting","A second road skills test in a tank vehicle","An eye exam administered by the BMV","A defensive-driving classroom course"],"answer":0,"explanation":"The HazMat endorsement requires a Transportation Security Administration (TSA) security threat assessment with fingerprint-based background check, in addition to the knowledge test. Source: Ohio BMV HazMat information and 49 CFR 1572.","handbook":"","hbref":""},{"q":"A driver must obtain an Ohio Commercial Learner's Permit (CLP) and hold it for a minimum period before being allowed to take the CDL skills (road) test. What is that minimum holding period?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"Federal rule adopted by Ohio requires the CLP be held at least 14 days before the applicant may take the CDL skills test. Source: Ohio BMV CDL process and 49 CFR 383.25.","handbook":"","hbref":""},{"q":"When operating a commercial vehicle on an Ohio Commercial Learner's Permit (CLP), the permit holder must be accompanied by what?","options":["Any licensed driver age 25 or older","A CDL holder with the proper class/endorsements seated next to them","A BMV examiner only","No one, if driving during daylight hours"],"answer":1,"explanation":"A CLP holder may operate a CMV only when accompanied by a person who holds a valid CDL of the appropriate class and endorsements, seated beside the CLP holder. Source: Ohio BMV CLP rules and 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Since February 7, 2022, a person obtaining a Class A CDL for the first time in Ohio must complete Entry-Level Driver Training (ELDT) provided by an entity that is what?","options":["Listed on the FMCSA Training Provider Registry","Accredited by the Ohio Department of Education","Approved only by the local deputy registrar","Certified by the Ohio State Highway Patrol"],"answer":0,"explanation":"ELDT must be delivered by a provider listed on the FMCSA Training Provider Registry (TPR), and the certification must be in the registry before the skills/knowledge test. Source: FMCSA ELDT rule (49 CFR 380 subpart F) and tpr.fmcsa.dot.gov.","handbook":"","hbref":""},{"q":"Which of the following first-time actions does NOT trigger the federal Entry-Level Driver Training (ELDT) requirement?","options":["Obtaining a Class A CDL for the first time","Obtaining the Passenger (P) endorsement for the first time","Obtaining the Tanker (N) endorsement for the first time","Obtaining the HazMat (H) endorsement for the first time"],"answer":2,"explanation":"ELDT applies to first-time Class A/B CDLs, upgrades from B to A, and first-time P, S, and H endorsements. The N (Tanker) and T (Doubles/Triples) endorsements are not covered by ELDT. Source: FMCSA ELDT applicability (tpr.fmcsa.dot.gov/Drivers/Applicability).","handbook":"","hbref":""},{"q":"The ELDT requirement applies to individuals who obtain their Commercial Learner's Permit on or after which date?","options":["February 7, 2020","February 7, 2022","January 30, 2021","December 31, 2023"],"answer":1,"explanation":"Entry-Level Driver Training requirements apply to drivers who obtain a CLP on or after February 7, 2022. Source: FMCSA ELDT rule and tpr.fmcsa.dot.gov.","handbook":"","hbref":""},{"q":"On the Ohio CDL self-certification form, which category describes a driver who operates across state lines and must meet the federal DOT physical (medical card) requirements?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"answer":1,"explanation":"Non-Excepted Interstate drivers operate in interstate commerce and must meet the federal medical (Part 391) standards, providing a Medical Examiner's Certificate. Source: Ohio BMV form BMV 2159 (CDL Self-Certification) and 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which documents must a first-time Ohio CDL applicant present to the BMV to prove eligibility?","options":["Proof of identity/lawful presence, full Social Security number, and Ohio residency","Only a current Ohio driver license and a credit card","A passport and two utility bills, but no Social Security number","A vehicle title and proof of insurance only"],"answer":0,"explanation":"Ohio requires documentation of identity and lawful presence (e.g., birth certificate, passport, or permanent resident card), the Social Security number, and proof of Ohio residency. Source: Ohio BMV CDL document requirements (bmv.ohio.gov).","handbook":"","hbref":""},{"q":"An 19-year-old Ohio driver wants a CDL to haul placardable hazardous materials. Why can this driver NOT obtain the HazMat (H) endorsement?","options":["HazMat transport requires being at least 21 years old","HazMat endorsements are only issued to Class C drivers","Ohio does not offer the HazMat endorsement","A tanker (N) endorsement must be obtained first"],"answer":0,"explanation":"Hauling placarded hazardous materials is interstate-capable and requires the driver to be at least 21; Ohio's 18-20 intrastate CDL holders cannot hold the H endorsement. Source: Ohio BMV CDL eligibility and 49 CFR 383.93/391.11.","handbook":"","hbref":""},{"q":"In Ohio, what is the maximum blood alcohol concentration (BAC) a driver may have while operating a commercial motor vehicle (CMV) before being considered legally impaired for CDL purposes?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"answer":0,"explanation":"Ohio follows the federal CMV standard: operating a commercial motor vehicle with a BAC of 0.04 percent or more is a major offense. The threshold is half the 0.08 limit for non-commercial drivers. Source: Ohio CDL Manual / Ohio BMV CDL Disqualifications; ORC 4506.15; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"By obtaining and using an Ohio CDL, a driver is deemed to have given consent to chemical testing of breath, blood, or urine to determine alcohol or drug content. What is this legal principle called?","options":["Implied consent","Probable cause","Due process consent","Conditional licensing"],"answer":0,"explanation":"Ohio's implied-consent law means that operating a vehicle on Ohio roads constitutes consent to chemical testing when lawfully arrested for an alcohol/drug offense. Refusal carries its own administrative penalties. Source: ORC 4511.191; Ohio CDL Manual.","handbook":"","hbref":""},{"q":"In Ohio, what is the minimum CDL disqualification period for a driver's FIRST major offense, such as a 0.04+ BAC in a CMV or refusing a chemical test, while NOT carrying placarded hazardous materials?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense (0.04+ BAC, OVI, test refusal, leaving the scene, using a CMV in a felony, etc.) results in a 1-year CDL disqualification in Ohio. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If an Ohio driver commits a first major offense (such as a 0.04+ BAC) while operating a CMV placarded for hazardous materials, the disqualification period is increased to:","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"When a first major offense occurs in a vehicle placarded for hazardous materials, the standard 1-year disqualification is increased to 3 years. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Ohio for a SECOND major offense (for example, a second OVI or second 0.04+ BAC in a CMV)?","options":["Lifetime","10 years","3 years","5 years"],"answer":0,"explanation":"A second conviction of any major offense results in a lifetime CDL disqualification in Ohio. Some lifetime disqualifications may be reduced to 10 years after meeting reinstatement conditions. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Ohio driver lawfully arrested for OVI refuses to submit to a chemical breath test. For CDL purposes, refusing the test results in a disqualification of at least:","options":["1 year","90 days","60 days","30 days"],"answer":0,"explanation":"A test refusal is treated as a major offense for CDL purposes, carrying a 1-year disqualification (3 years if hauling placarded hazardous materials), in addition to any administrative license suspension. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Ohio's implied-consent law, a CDL holder who refuses chemical testing also faces an administrative license suspension. For a FIRST refusal, this administrative suspension is generally:","options":["1 year","90 days","6 months","2 years"],"answer":0,"explanation":"Ohio's implied-consent statute imposes a 1-year administrative license suspension for a first chemical-test refusal, with longer periods for repeat refusals within 10 years. This is separate from the CDL disqualification. Source: ORC 4511.191.","handbook":"","hbref":""},{"q":"In Ohio, how many SERIOUS traffic violations in separate incidents within a 3-year period trigger a 60-day CDL disqualification?","options":["2","3","4","5"],"answer":0,"explanation":"Conviction of 2 serious traffic violations within 3 years (in a CMV) results in a 60-day disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Ohio CDL holder is convicted of THREE serious traffic violations in separate incidents within a 3-year period. What is the CDL disqualification period?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"Conviction of 3 or more serious traffic violations within 3 years results in a 120-day disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How much over the posted speed limit must a CDL driver be cited for the offense to count as a SERIOUS traffic violation in Ohio?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","5 mph or more over the limit"],"answer":0,"explanation":"Speeding 15 mph or more above the posted limit is classified as a serious traffic violation for CDL holders. Source: Ohio CDL Manual; ORC 4506.01/4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for an Ohio CDL holder?","options":["Following too closely (tailgating)","Parking in a no-parking zone","An unlit license plate lamp","A first overweight load citation"],"answer":0,"explanation":"Serious traffic violations include following too closely, reckless/erratic lane changes, speeding 15+ mph over, texting while driving, and operating a CMV without the proper class/endorsement. Equipment and parking offenses are not serious violations. Source: Ohio CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Ohio, using a hand-held mobile phone or texting while operating a CMV is prohibited. For CDL purposes, such a conviction is counted as a:","options":["Serious traffic violation","Major offense","Out-of-service violation","Non-recordable infraction"],"answer":0,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation; two within 3 years bring a 60-day disqualification, three bring 120 days. Source: Ohio CDL Manual; 49 CFR 383.51 and 392.80/392.82.","handbook":"","hbref":""},{"q":"What is the maximum federal driver civil penalty (applied in Ohio) for a CMV driver who texts while driving a commercial vehicle?","options":["Up to $2,750","Up to $500","Up to $1,000","Up to $11,000"],"answer":0,"explanation":"A CMV driver who texts while driving faces a federal civil penalty of up to $2,750; motor carriers that allow it can be fined up to $11,000. These rules apply in Ohio. Source: 49 CFR 392.80; FMCSA No-Texting Rule.","handbook":"","hbref":""},{"q":"An Ohio CDL holder commits a FIRST railroad-highway grade crossing violation (such as failing to stop where required). What is the disqualification period?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in a 60-day CDL disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Ohio for a SECOND railroad-highway grade crossing violation within a 3-year period?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"A second railroad-grade-crossing violation within 3 years results in a 120-day disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Ohio CDL holder commits a THIRD railroad-highway grade crossing violation within a 3-year period. The disqualification period is:","options":["1 year","120 days","180 days","2 years"],"answer":0,"explanation":"A third or subsequent railroad-grade-crossing violation within 3 years results in a 1-year (365-day) disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Ohio for a driver's FIRST conviction of violating an out-of-service (OOS) order?","options":["180 days","60 days","1 year","90 days"],"answer":0,"explanation":"A first conviction of violating an out-of-service order results in a disqualification of at least 180 days. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Ohio, what is the CDL disqualification period for a SECOND out-of-service (OOS) order violation in separate incidents within a 10-year period?","options":["2 years","1 year","180 days","3 years"],"answer":0,"explanation":"A second out-of-service order violation within a 10-year period results in a 2-year disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Ohio CDL holder is convicted of a THIRD out-of-service order violation within a 10-year period. The disqualification period is:","options":["3 years","2 years","180 days","5 years"],"answer":0,"explanation":"A third or subsequent out-of-service order violation within 10 years results in a 3-year disqualification. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Ohio driver violates an out-of-service order while transporting placarded hazardous materials or operating a vehicle designed to carry 16 or more passengers. What is the disqualification for this FIRST offense?","options":["180 days","60 days","1 year","2 years"],"answer":0,"explanation":"A first out-of-service order violation while hauling placarded hazmat or carrying 16+ passengers carries a 180-day disqualification; a subsequent such violation within 10 years carries 3 years. Source: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Ohio's Move Over law, when you approach a stationary tow truck, highway maintenance vehicle, or police cruiser displaying flashing lights on a highway with two or more lanes in your direction, what must you do?","options":["Move into a lane not next to the stopped vehicle when it is safe to do so","Come to a complete stop until the vehicle moves","Sound your horn continuously while passing","Maintain your speed but turn on your four-way flashers"],"answer":0,"explanation":"Ohio's Move Over law (ORC 4511.213) requires a driver approaching a stationary public safety, emergency, road service, or maintenance vehicle displaying flashing lights to move into a lane not adjacent to that vehicle when there are at least two lanes in the same direction and it is safe. Source: Ohio Revised Code 4511.213.","handbook":"","hbref":""},{"q":"Under Ohio's Move Over law, if you cannot safely change lanes (for example on a two-lane road) when passing a stopped emergency vehicle with lights flashing, what does the law require?","options":["Proceed with due caution, reduce speed, and maintain a safe speed for conditions","Stop completely and wait for an officer to wave you through","Continue at the posted speed limit without slowing","Pull onto the shoulder and stop"],"answer":0,"explanation":"When changing lanes is impossible or unsafe, ORC 4511.213 requires the driver to proceed with due caution, reduce speed, and maintain a safe speed for road, weather, and traffic conditions. Source: Ohio Revised Code 4511.213.","handbook":"","hbref":""},{"q":"In Ohio, a driver carrying placarded hazardous materials or operating a bus must stop before a railroad grade crossing within what distance of the nearest rail?","options":["Not less than 15 feet and not more than 50 feet","Not less than 5 feet and not more than 25 feet","Not less than 25 feet and not more than 75 feet","Not less than 10 feet and not more than 100 feet"],"answer":0,"explanation":"A driver of a bus or a vehicle displaying hazardous-materials placards must stop within 50 feet but not less than 15 feet from the nearest rail at a railroad crossing, then look and listen before proceeding. Source: Ohio CDL Manual / 49 CFR 392.10; the mandatory stop is required by ORC 4511.63.","handbook":"","hbref":""},{"q":"Which of the following vehicles is REQUIRED to stop at every non-exempt railroad grade crossing in Ohio?","options":["A vehicle transporting materials that must be placarded under federal hazmat rules","Any pickup truck towing a utility trailer","Any straight truck with a gross weight over 10,000 pounds","Any vehicle with dual rear wheels"],"answer":0,"explanation":"ORC 4511.63 requires the operator of any bus, any school vehicle, or any vehicle transporting material required to be placarded under 49 CFR Parts 100-185 to stop before crossing a railroad track. Ordinary trucks and trailers are not subject to the mandatory stop. Source: Ohio Revised Code 4511.63.","handbook":"","hbref":""},{"q":"On a two-lane Ohio roadway, when you meet a stopped school bus that is loading or unloading children with its red lights flashing, you must stop at least how far from the bus?","options":["At least 10 feet from the front or rear of the bus","At least 20 feet from the front or rear of the bus","At least 30 feet from the front or rear of the bus","At least 50 feet from the front or rear of the bus"],"answer":0,"explanation":"ORC 4511.75 requires a driver meeting or overtaking a stopped school bus to stop at least 10 feet from the front or rear of the bus and not proceed until the bus moves or the driver signals to proceed. Source: Ohio Revised Code 4511.75.","handbook":"","hbref":""},{"q":"In Ohio, on a highway divided into how many traffic lanes may oncoming traffic continue without stopping for a school bus stopped on the opposite side?","options":["Four or more lanes","Two or more lanes","Three or more lanes","Six or more lanes"],"answer":0,"explanation":"Ohio's school bus law provides that on a highway of four or more lanes, a driver need not stop for a school bus that has stopped on the opposite side; only traffic traveling in the same direction as the bus must stop. Source: Ohio Revised Code 4511.75.","handbook":"","hbref":""},{"q":"After stopping for an Ohio school bus on a two-lane road, when may you proceed?","options":["When the bus resumes motion or the bus driver signals you to proceed","As soon as the children have stepped off the roadway","After waiting a mandatory 30 seconds","Whenever the bus's amber lights begin flashing"],"answer":0,"explanation":"ORC 4511.75 states a stopped driver shall not proceed until the school bus resumes motion or until signaled by the school bus driver to proceed. Source: Ohio Revised Code 4511.75.","handbook":"","hbref":""},{"q":"What is the maximum speed limit for a tractor-trailer on a rural interstate highway in Ohio (unless a lower limit is posted)?","options":["70 mph, the same as passenger cars","55 mph, lower than passenger cars","60 mph, lower than passenger cars","65 mph, lower than passenger cars"],"answer":0,"explanation":"Ohio does not set a separate, lower speed limit for trucks. Under ORC 4511.21, the maximum on rural interstates is 70 mph and commercial trucks may travel at the same limit as cars unless otherwise posted. Source: Ohio Revised Code 4511.21; ODOT speed zone rules.","handbook":"","hbref":""},{"q":"What is the speed limit for commercial trucks on the Ohio Turnpike mainline?","options":["70 mph, the same as for passenger vehicles","65 mph for trucks while cars may go 70","55 mph for all trucks","60 mph for trucks while cars may go 70"],"answer":0,"explanation":"The Ohio Turnpike posts a 70 mph mainline limit that applies to all vehicles, including commercial trucks; Ohio does not impose a separate lower truck speed. Source: Ohio Turnpike and Infrastructure Commission; ORC 4511.21.","handbook":"","hbref":""},{"q":"On a multi-lane Ohio roadway, a truck driver proceeding slower than the prevailing speed of traffic is generally required to do what?","options":["Drive in the right-hand lane available for traffic, except when passing or turning left","Stay in the center lane to avoid merging vehicles","Use the left lane so faster traffic can merge on the right","Use any lane as long as four-way flashers are on"],"answer":0,"explanation":"ORC 4511.25 requires a vehicle proceeding slower than the prevailing lawful speed to be driven in the right-hand lane available for traffic, far enough right to allow safe passing, except when overtaking, turning left, or when the route requires another lane. Source: Ohio Revised Code 4511.25.","handbook":"","hbref":""},{"q":"When a truck is disabled and stopped on an Ohio roadway, how should the three warning devices (flares, reflectors, or lanterns) be placed?","options":["One about 100 feet ahead, one about 100 feet behind, and one on the traffic side","All three placed directly behind the vehicle in a row","One on each side and one on the roof of the cab","One 10 feet ahead, one 10 feet behind, and one on the shoulder"],"answer":0,"explanation":"ORC 4513.28 requires placing warning devices approximately 100 feet in advance of the vehicle, approximately 100 feet to the rear, and one on the traffic side of the disabled vehicle. Source: Ohio Revised Code 4513.28.","handbook":"","hbref":""},{"q":"A first-offense violation of Ohio's Move Over law (ORC 4511.213) is classified as what?","options":["A minor misdemeanor with the fine doubled (up to about $300)","A felony of the fifth degree","A non-moving civil infraction with no points","A first-degree misdemeanor with mandatory jail"],"answer":0,"explanation":"A first offense under ORC 4511.213 is a minor misdemeanor, but the court must impose a fine of two times the usual amount, making it up to roughly $300. Repeat offenses within a year escalate to fourth- and third-degree misdemeanors. Source: Ohio Revised Code 4511.213.","handbook":"","hbref":""},{"q":"In Ohio, what is the maximum legal width of a commercial vehicle or load before an oversize permit is required?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"answer":0,"explanation":"Ohio's legal maximum vehicle width is 8 feet 6 inches (102 inches); anything wider requires a special hauling permit from ODOT. Source: ORC 5577.05; Ohio DOT Special Hauling Permit rules.","handbook":"","hbref":""},{"q":"In Ohio, what is the maximum legal height of a vehicle and load before a permit is required?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"answer":0,"explanation":"Ohio's legal maximum height is 13 feet 6 inches; loads taller than this require an oversize permit from ODOT. Source: ORC 5577.05; Ohio DOT Special Hauling Permit Operational Guide.","handbook":"","hbref":""},{"q":"Who issues the special permit that allows an oversize or overweight vehicle to operate on Ohio state routes?","options":["The Ohio Director of Transportation (ODOT)","The Ohio Bureau of Motor Vehicles (BMV)","The county sheriff of each county on the route","The Ohio State Highway Patrol post commander"],"answer":0,"explanation":"Vehicles exceeding the legal size or weight limits may operate on a state route only under a special written permit issued by the Ohio Director of Transportation. Source: ORC 4513.34 and 5577.04; ODOT Special Hauling Permits.","handbook":"","hbref":""},{"q":"In Ohio, what is the maximum gross vehicle weight allowed without an overweight permit, consistent with the federal limit?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"answer":0,"explanation":"Ohio follows the federal maximum gross weight of 80,000 pounds (subject to the Federal Bridge Formula); exceeding it requires an ODOT overweight permit. Source: ORC 5577.04; Federal Bridge Formula.","handbook":"","hbref":""},{"q":"When a placarded hazmat vehicle approaches a railroad crossing in Ohio, which action is correct while crossing the tracks?","options":["Do not change gears while any part of the vehicle is on the tracks","Shift into a lower gear while crossing for better control","Stop midway across to check for a second train","Switch off the engine until fully across the tracks"],"answer":0,"explanation":"After stopping, looking, and listening, the driver must cross in a gear that will not need changing and must not shift gears while any part of the vehicle is on the tracks. Source: Ohio CDL Manual / 49 CFR 392.10; ORC 4511.63.","handbook":"","hbref":""},{"q":"On a four-lane divided highway in Ohio, a school bus stopping to discharge children must, where practicable, do what to reduce road-crossing risk?","options":["Receive and discharge passengers on the residence side of the highway","Stop in the median so children can use the crossover","Discharge all passengers on the left shoulder","Require all children to be escorted across by the driver"],"answer":0,"explanation":"On divided highways or roads of four or more lanes, school buses are to receive and discharge children on the residence side so children do not have to cross the roadway; this is why oncoming traffic need not stop. Source: Ohio Revised Code 4511.75; Ohio school bus regulations.","handbook":"","hbref":""},{"q":"Under Ohio law, when a posted STOP sign is placed at a designated dangerous railroad grade crossing, a driver must stop within what distance of the nearest rail?","options":["Not less than 15 feet but within 50 feet","Not less than 5 feet but within 20 feet","Not less than 30 feet but within 60 feet","Exactly 25 feet from the nearest rail"],"answer":0,"explanation":"ORC 4511.61 requires a driver to stop within fifty feet but not less than fifteen feet from the nearest rail at a railroad crossing where a stop sign has been erected and not proceed until it is safe. Source: Ohio Revised Code 4511.61.","handbook":"","hbref":""},{"q":"Which statement best describes whether Ohio imposes truck-specific speed limits separate from cars?","options":["Ohio sets the same maximum speed limits for trucks and cars; trucks are not assigned a separate lower statewide limit","Trucks are always limited to 55 mph statewide regardless of the posted limit","Trucks must travel 10 mph below the posted car limit on all freeways","Trucks may only use the Ohio Turnpike and are banned from interstates"],"answer":0,"explanation":"Ohio applies the same posted maximum speed limits to commercial trucks and passenger cars under ORC 4511.21; there is no separate statewide lower truck speed limit, though drivers must still drive at a safe speed for conditions. Source: Ohio Revised Code 4511.21; ODOT.","handbook":"","hbref":""},{"q":"Which state agency issues Commercial Driver Licenses (CDLs) in Ohio?","options":["The Ohio Bureau of Motor Vehicles (BMV)","The Ohio Department of Transportation (ODOT)","The Ohio State Highway Patrol","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In Ohio, the Bureau of Motor Vehicles (BMV), a division of the Ohio Department of Public Safety, issues all driver licenses including CDLs. ODOT handles roads and oversize/overweight permits, not licensing, and FMCSA is the federal agency that sets standards. Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""},{"q":"Before an Ohio CDL applicant can take any commercial knowledge test, where must that test be completed?","options":["In person at an Ohio BMV driver exam station","Online from any home computer","By mail using a take-home answer sheet","At an FMCSA-registered ELDT training provider"],"answer":0,"explanation":"Ohio requires CDL knowledge tests (general knowledge, endorsements, and air-brake restriction removal) to be taken in person at a BMV driver exam station; they cannot be taken online. ELDT providers deliver training, not the state knowledge test. Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""},{"q":"How long is an Ohio Commercial Learner's Permit (CLP) valid once issued?","options":["12 months","6 months","30 days","24 months"],"answer":0,"explanation":"Ohio states that a CLP is valid for 12 months. (Under federal rule it may be renewed once without retaking the general knowledge test.) Distractors reflect common but incorrect permit periods. Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""},{"q":"After receiving an Ohio CLP, how long must an applicant hold it before becoming eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"Federal regulation, applied in Ohio, requires a CLP to be held for a minimum of 14 days before the holder may take the CDL skills (road) test. Source: Ohio BMV CDL process / 49 CFR 383.25 (FMCSA).","handbook":"","hbref":""},{"q":"The Ohio CDL skills test is administered in three parts. Which set correctly lists those three parts?","options":["Pre-trip inspection, basic control (maneuverability), and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, air-brake check, and hazardous-materials handling","Basic control, night driving, and a written endorsement exam"],"answer":0,"explanation":"Ohio's CDL skills test consists of three parts: the pre-trip inspection, the basic control (maneuverability) test, and the on-road driving test. Vision screening and written exams are separate from the skills test. Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""},{"q":"What must an Ohio applicant submit electronically BEFORE they can schedule or attempt the CDL skills test?","options":["Proof of completing Entry-Level Driver Training (ELDT), or proof of an exemption","Proof of two years of prior driving experience","A signed employer sponsorship letter","A passing score on a defensive-driving course"],"answer":0,"explanation":"Ohio requires electronic proof of completing FMCSA Entry-Level Driver Training (ELDT) matching the class/endorsement sought, or proof of an exemption, before the skills test may be scheduled or attempted. Source: Ohio BMV CDL page / FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"Ohio's self-certification process requires a CDL/CLP applicant to choose among how many type-of-driving categories?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Ohio drivers must self-certify into one of four categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: Ohio BMV CDL Self-Certification (form BMV 2159).","handbook":"","hbref":""},{"q":"An Ohio driver crosses state lines for business and must meet federal physical-qualification (medical) standards under 49 CFR Part 391. Which self-certification category applies?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"answer":0,"explanation":"Non-Excepted Interstate covers drivers who operate across state lines and must meet the federal medical requirements of 49 CFR Part 391; these drivers must keep a valid medical examiner's certificate on file. Source: Ohio BMV self-certification categories (form BMV 2159).","handbook":"","hbref":""},{"q":"Effective June 23, 2025, how is a CDL holder's DOT medical examiner's certificate information provided to the Ohio BMV?","options":["FMCSA electronically transmits exam results to the BMV, so a paper certificate is no longer required","The driver must mail a notarized paper copy to the BMV within 10 days","The medical examiner faxes a wallet card that the driver laminates","The certificate is uploaded only by the driver's employer"],"answer":0,"explanation":"As of June 23, 2025, FMCSA electronically transmits medical examination results (and variance information) for CLP applicants and CDL holders to the Ohio BMV, so drivers no longer submit a paper Medical Examiner's Certificate. Source: Ohio BMV CDL medical certification notice / FMCSA Medical Examiner's Certification Integration rule.","handbook":"","hbref":""},{"q":"Which Ohio BMV form is used for CDL self-certification of the driver's type of commercial driving?","options":["BMV 2159 (CDL Self-Certification Authorization)","BMV 2290 (Heavy Vehicle Use Tax form)","BMV 5759 (Hazardous Materials Endorsement form)","BMV 1173 (Vehicle Registration form)"],"answer":0,"explanation":"Ohio uses form BMV 2159, the CDL Self-Certification Authorization, for a driver to declare one of the four type-of-driving categories. Source: Ohio BMV form BMV 2159.","handbook":"","hbref":""},{"q":"What is the minimum number of correct answers needed to pass Ohio's 50-question CDL general knowledge test?","options":["40 correct (80%)","35 correct (70%)","45 correct (90%)","30 correct (60%)"],"answer":0,"explanation":"Ohio CDL knowledge tests require a score of at least 80% to pass; on the 50-question general knowledge test that means 40 correct answers. The 80% standard applies to endorsement tests as well. Source: Ohio CDL manual / Ohio BMV testing standards.","handbook":"","hbref":""},{"q":"Per Ohio Revised Code 4506.14, what is the maximum period for which a standard (non-hazmat) Ohio CDL may be issued?","options":["Eight years","Four years","Five years","Ten years"],"answer":0,"explanation":"ORC 4506.14 provides that no CDL may be issued for a period longer than eight years; CDLs are tied to the licensee's birthday. A hazardous-materials endorsement, however, limits issuance to four years and 180 days. Source: Ohio Revised Code 4506.14.","handbook":"","hbref":""},{"q":"Because of federal background-check (TSA) limits, an Ohio CDL carrying a hazardous-materials endorsement cannot be issued for longer than what period?","options":["Four years and 180 days","Exactly four years","Five years","Eight years"],"answer":0,"explanation":"ORC 4506.14 caps a CDL with a hazardous-materials endorsement at four years and 180 days, aligning with the federal hazmat security threat assessment cycle. Standard CDLs may run up to eight years. Source: Ohio Revised Code 4506.14.","handbook":"","hbref":""},{"q":"Under Ohio law, how far in advance of its expiration date may a CDL be renewed?","options":["Up to 180 days before expiration","Up to 30 days before expiration","Up to 90 days before expiration","Only on or after the expiration date"],"answer":0,"explanation":"ORC 4506.14 states a CDL is renewable beginning 180 days before its expiration upon payment of the required fees. Source: Ohio Revised Code 4506.14.","handbook":"","hbref":""},{"q":"Ohio's registrar may waive the renewal examination for a CDL holder only if the applicant presents a CDL that is unexpired or expired no more than how long before the application date?","options":["Six months","One month","Three months","One year"],"answer":0,"explanation":"ORC 4506.14 allows the registrar to waive the renewal examination if the applicant presents an unexpired CDL, or one expired not more than six months before the application date. Beyond that grace period, retesting is generally required. Source: Ohio Revised Code 4506.14.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Ohio CDL restricted to INTRASTATE (within Ohio only) driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"Ohio sets the minimum CDL age at 18 for intrastate-only operation; drivers under 21 are restricted to driving within Ohio. Interstate operation and hazardous-materials hauling require age 21. Source: Ohio BMV CDL requirements.","handbook":"","hbref":""},{"q":"An Ohio applicant must be at least what age to drive a commercial motor vehicle in INTERSTATE commerce or to haul hazardous materials?","options":["21 years old","18 years old","23 years old","25 years old"],"answer":0,"explanation":"Federal rule applied in Ohio requires a driver to be at least 21 to operate in interstate commerce or to transport placarded hazardous materials. Drivers aged 18-20 are limited to intrastate driving. Source: Ohio BMV CDL requirements / 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Besides a valid Ohio driver license and proof of Social Security number, what else must a first-time Ohio CDL applicant present?","options":["Proof of U.S. citizenship or lawful permanent residency","A notarized letter from a current employer","A high school diploma or GED certificate","Two personal references who hold CDLs"],"answer":0,"explanation":"Ohio requires first-time CDL applicants to provide a valid Ohio driver license, a valid Social Security number, and proof of U.S. citizenship or lawful permanent residency (e.g., passport, birth certificate, or permanent resident card). Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""},{"q":"An Ohio driver self-certifies as 'Excepted Interstate.' What does this category indicate about their federal medical requirements?","options":["They drive across state lines but are NOT required to meet the federal (Part 391) medical standards","They drive only within Ohio and must meet state medical standards","They must always carry a federal medical examiner's certificate","They never use the CDL for any business purpose"],"answer":0,"explanation":"Excepted Interstate means the driver operates across state lines but qualifies for an exception from the federal physical-qualification requirements of 49 CFR Part 391, so a DOT medical card is not required for that operation. Source: Ohio BMV self-certification categories (form BMV 2159).","handbook":"","hbref":""},{"q":"When taking the Ohio CDL skills test, who is generally responsible for providing the commercial vehicle used for the test?","options":["The applicant, who must supply (or rent) a vehicle representative of the class sought","The Ohio BMV, which keeps a fleet of test vehicles","ODOT, which loans vehicles for road tests","The FMCSA regional office"],"answer":0,"explanation":"Ohio requires the applicant to provide an appropriate commercial vehicle representative of the class being tested, or to rent one (often through a third-party testing site). The BMV does not furnish test vehicles. Source: Ohio BMV, Commercial Driver (CDL) page.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина транспортного средства, включая груз, на автомагистралях штата Огайо без специального разрешения на перевозку?","options":["8 футов (96 inches)","8 футов 6 дюймов (102 inches)","9 футов (108 inches)","8 футов 2 дюйма (98 inches)"],"explanation":"Ohio Revised Code 5577.05 устанавливает максимальную ширину транспортного средства в 102 inches (8 футов 6 дюймов), включая груз. Для большей ширины требуется специальное разрешение на перевозку от ODOT."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства с грузом на автомагистралях штата Огайо без разрешения?","options":["13 футов 0 дюймов","14 футов 0 дюймов","13 футов 6 дюймов","14 футов 6 дюймов"],"explanation":"Согласно Ohio Revised Code 5577.05, максимальная высота составляет 13 футов 6 дюймов (13.5 футов), с грузом или без него. Водитель несёт ответственность за безопасный проезд под путепроводами и сооружениями."},"2":{"q":"Какова в Огайо максимальная длина полуприцепа, эксплуатируемого в составе автопоезда «тягач-полуприцеп» без разрешения?","options":["48 футов","53 фута","57 футов","45 футов"],"explanation":"Ohio Revised Code 5577.05 допускает полуприцеп длиной до 53 футов при эксплуатации в составе коммерческого автопоезда «тягач-полуприцеп», что соответствует федеральному стандарту национальной сети дорог."},"3":{"q":"Какова максимальная полная масса транспортного средства с грузом, которая может перевозиться по автомагистралям штата Огайо без специального разрешения на перевозку?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"Ohio Revised Code 5577.04 ограничивает максимальную общую полную массу, приходящуюся на дорожное покрытие, величиной 80,000 pounds — так же, как и федеральный лимит для межштатных автомагистралей."},"4":{"q":"Согласно законодательству Огайо, нагрузка на любую одиночную ось транспортного средства не должна превышать какой величины?","options":["18,000 pounds","22,400 pounds","20,000 pounds","24,000 pounds"],"explanation":"Ohio Revised Code 5577.04 ограничивает максимальную нагрузку на одиночную ось величиной 20,000 pounds, что соответствует федеральному стандарту для одиночной оси."},"5":{"q":"Какова максимальная нагрузка, допустимая на сдвоенную группу осей в межштатной дорожной системе Огайо?","options":["32,000 pounds","36,000 pounds","38,000 pounds","34,000 pounds"],"explanation":"Ohio Revised Code 5577.04 устанавливает максимальную нагрузку на сдвоенную ось в 34,000 pounds, что соответствует федеральному лимиту для сдвоенных осей."},"6":{"q":"Какова максимальная длина любого одиночного (без прицепа) транспортного средства, кроме автобуса или дома на колёсах, на автомагистралях штата Огайо без разрешения?","options":["40 футов","50 футов","45 футов","53 фута"],"explanation":"Ohio Revised Code 5577.05 ограничивает длину одиночного транспортного средства (кроме специально перечисленных, таких как автобусы) величиной в 50 футов."},"7":{"q":"Какое государственное ведомство Огайо выдаёт специальные разрешения на перевозку негабаритных/сверхтяжёлых грузов для движения по дорогам штата, федеральным и межштатным автомагистралям?","options":["Бюро регистрации транспортных средств Огайо (BMV)","Дорожный патруль штата Огайо","Комиссия по коммунальным услугам штата Огайо (PUCO)","Департамент транспорта штата Огайо (ODOT)"],"explanation":"Департамент транспорта штата Огайо (ODOT) выдаёт специальные разрешения на перевозку, которые обрабатываются в электронном виде через систему Ohio Hauling Permit System (ODOT Special Hauling Permits)."},"8":{"q":"В составе автопоезда «тягач-полуприцеп-прицеп» (сдвоенная сцепка) на автомагистралях штата Огайо, какова максимальная длина каждого полуприцепа или прицепа без разрешения?","options":["28 футов 6 дюймов","33 фута","27 футов","30 футов"],"explanation":"Ohio Revised Code 5577.05 ограничивает длину каждого полуприцепа или прицепа величиной 28 футов 6 дюймов при эксплуатации в составе коммерческого автопоезда «тягач-полуприцеп-прицеп» или «тягач-полуприцеп-полуприцеп»."},"9":{"q":"Состав грузового автопоезда на автомагистрали Огайо слишком тяжёл для законных пределов. Какой тип разрешения должен получить водитель перед поездкой?","options":["Отметку о негабаритном грузе в CDL","Специальное разрешение на перевозку от ODOT","Федеральное освобождение по перегрузу от FMCSA","Сертификат дорожного залога, выданный округом"],"explanation":"Согласно ODOT, любое транспортное средство или груз, превышающие законные ограничения Огайо по габаритам или массе, должны получить специальное разрешение на перевозку от ODOT до начала движения по дорогам штата, федеральным или межштатным автомагистралям."},"10":{"q":"Какова максимальная длина для составов транспортных средств, прямо не предусмотренных иными нормами (например, общий состав «тягач-полуприцеп-прицеп»), на автомагистралях штата Огайо?","options":["60 футов","75 футов","65 футов","70 футов"],"explanation":"Ohio Revised Code 5577.05 устанавливает максимум в 65 футов для любого иного состава транспортных средств, прямо не предусмотренного нормами."},"11":{"q":"Федеральная мостовая формула, принятая в законодательстве Огайо для групп с несколькими осями, имеет вид W = 500((LN/(N-1)) + 12N + 36). Что в этой формуле обозначает «L»?","options":["Расчётную несущую способность моста","Расстояние в футах между крайними (первой и последней) осями группы","Длину самого длинного прицепа в составе","Общую зарегистрированную полную массу транспортного средства"],"explanation":"В мостовой формуле, изложенной в Ohio Revised Code 5577.04(C), L — это расстояние в футах между передней и самой задней осями группы, N — количество осей, а W — максимально допустимая полная масса."},"12":{"q":"Согласно специальным весовым положениям Огайо, на сколько процентов соответствующий критериям грузовик, перевозящий сельхозпродукцию, лес, уголь или твёрдые отходы, может превышать обычные весовые ограничения при перевозке от места производства до первого пункта доставки?","options":["5 percent","10 percent","7.5 percent","12.5 percent"],"explanation":"Ohio Revised Code 5577.042 разрешает соответствующим критериям грузовикам для перевозки сельхозпродукции, леса, угля и твёрдых отходов превышать весовые положения не более чем на 7.5 percent при описанных условиях."},"13":{"q":"В какие месяцы НЕ применяется весовой допуск Огайо в 7.5 percent для сельхозгрузовиков, лесовозов и сельхозтехники?","options":["Февраль и март","Январь и февраль","Март и апрель","Ноябрь и декабрь"],"explanation":"Ohio Revised Code 5577.042 указывает, что допуск в 7.5 percent не применяется в феврале и марте для сельхозгрузовиков, лесовозов или сельхозтехники (сезонный период промерзания/оттаивания)."},"14":{"q":"Весовой допуск Огайо в 7.5 percent для сельскохозяйственной/лесной продукции согласно ORC 5577.042 НЕ применяется на каких дорогах?","options":["Окружных дорогах","Межштатных автомагистралях","Дорогах тауншипов","Городских улицах"],"explanation":"Ohio Revised Code 5577.042 устанавливает, что допуск в 7.5 percent не применяется на межштатных автомагистралях (а также на дорогах, для которых установлены специально пониженные максимальные весовые пределы)."},"15":{"q":"Согласно правилам ODOT, груз классифицируется как «суперлот» (superload), когда его полная масса превышает какую величину?","options":["80,000 pounds","100,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"Согласно эксплуатационному руководству ODOT, суперлот (superload) — это любое транспортное средство/груз с полной массой более 120,000 pounds (либо шириной более 14 футов или высотой более 14 футов 6 дюймов), что требует дополнительной проверки, например анализа мостов/конструкций."},"16":{"q":"В системе дорог Огайо вне межштатных автомагистралей (общая дорожная сеть) две последовательные оси, расположенные на расстоянии более 4 футов друг от друга, могут нести до 34,000 pounds плюс 1,000 pounds на каждый дополнительный фут, но не более какого максимума?","options":["38,000 pounds","42,000 pounds","44,000 pounds","40,000 pounds"],"explanation":"Ohio Revised Code 5577.04 предусматривает, что в системе дорог вне межштатных автомагистралей две последовательные оси на расстоянии более 4 футов друг от друга могут нести 34,000 pounds плюс 1,000 pounds на каждый фут сверх 4 футов, но не более 40,000 pounds."},"17":{"q":"Согласно правилам ODOT по сопровождению, транспортное средство/груз шириной более какого размера требует одного ведущего (переднего) автомобиля сопровождения на двухполосной автомагистрали Огайо?","options":["12 футов","13 футов","11 футов","10 футов"],"explanation":"Согласно требованиям ODOT к сопровождению по разрешению, один ведущий автомобиль сопровождения требуется для любого транспортного средства/груза общей шириной более 13 футов; грузы шириной более 14 футов 6 дюймов требуют как ведущего, так и заднего автомобиля сопровождения."},"18":{"q":"Согласно правилам выдачи разрешений ODOT, негабаритному грузу шириной менее 12 футов обычно разрешено движение в какой суточный промежуток?","options":["Только с 9:00 a.m. до 3:00 p.m.","С 30 минут до восхода солнца до 30 минут после заката","С одного часа после восхода солнца до одного часа до заката","Только в полностью светлое время суток, от восхода до заката"],"explanation":"Согласно ODOT, негабаритные грузы шириной менее 12 футов могут двигаться семь дней в неделю (за исключением праздников) с 30 минут до восхода солнца до 30 минут после заката; грузы шириной 12 футов и более должны соблюдать конкретное время, указанное в разрешении."},"19":{"q":"В межштатной дорожной системе Огайо два последовательных набора сдвоенных осей могут нести по 34,000 pounds каждый при условии, что расстояние между первой и последней осями этих двух наборов составляет не менее скольких футов?","options":["30 футов","40 футов","36 футов","34 фута"],"explanation":"Ohio Revised Code 5577.04 допускает, чтобы два последовательных набора сдвоенных осей несли по 34,000 pounds каждый, только когда общее расстояние между первой и последней осями последовательных наборов составляет 36 футов или более."},"20":{"q":"В Огайо какой класс CDL требуется для управления составом транспортных средств с полной массой автопоезда (GCWR) 26,001 pounds или более при условии, что буксируемая единица имеет GVWR более 10,000 pounds?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"CDL класса A в Огайо охватывает составы транспортных средств с GCWR 26,001 lbs или более, где GVWR буксируемой единицы превышает 10,000 lbs. Источник: страница классов CDL Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx) и 49 CFR 383.91 в редакции, принятой в Огайо."},"21":{"q":"Водитель в Огайо управляет одиночным грузовиком без сцепки с GVWR 30,000 pounds, который не буксирует прицеп массой более 10,000 pounds. Какой класс CDL является подходящим?","options":["Класс A","Класс B","Класс C","Класс E"],"explanation":"CDL класса B в Огайо охватывает любое одиночное транспортное средство с GVWR 26,001 lbs или более и может буксировать прицеп с GVWR не более 10,000 lbs. Источник: страница классов CDL Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"22":{"q":"Согласно правилам Огайо, транспортное средство, которое не соответствует весовым порогам для класса A или B, но предназначено для перевозки 16 или более пассажиров (включая водителя) или опасных материалов, требующих знаков опасности, относится к какому классу CDL?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса C в Огайо применяется к транспортным средствам ниже весовых порогов класса A/B, которые перевозят 16 и более человек (включая водителя) или опасные материалы, требующие знаков опасности. Источник: страница классов CDL Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"23":{"q":"Каков минимальный возраст для выдачи CDL Огайо с ограничением только для ВНУТРИШТАТНОГО (в пределах Огайо) коммерческого вождения?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Огайо выдаёт CDL только для внутриштатной деятельности начиная с 18 лет; водители моложе 21 года ограничены коммерческой деятельностью в пределах Огайо. Источник: требования к CDL Ohio BMV (bmv.ohio.gov) и ORC 4506.10."},"24":{"q":"Каков минимальный возраст, требуемый для управления коммерческим транспортным средством в МЕЖШТАТНОЙ коммерческой деятельности с CDL Огайо?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Межштатное коммерческое вождение требует, чтобы водителю было не менее 21 года. Водители Огайо в возрасте 18-20 лет имеют CDL только для внутриштатной деятельности. Источник: требования к CDL Ohio BMV и 49 CFR 391.11."},"25":{"q":"Какая буква отметки требуется в CDL Огайо для перевозки опасных материалов в количествах, требующих установки на транспортном средстве знаков опасности?","options":["Отметка H","Отметка N","Отметка T","Отметка X"],"explanation":"Отметка H (HazMat) разрешает перевозку опасных материалов, требующих знаков опасности. Источник: страница классов/отметок CDL Ohio BMV и 49 CFR 383.93."},"26":{"q":"Водитель в Огайо, который перевозит жидкости или газы наливом/насыпью в стационарно установленной цистерне, должен иметь какую отметку?","options":["Отметка H","Отметка N","Отметка P","Отметка S"],"explanation":"Отметка N (цистерна) требуется для управления цистерной, перевозящей жидкие или газообразные материалы наливом. Источник: информация об отметках Ohio BMV и 49 CFR 383.93."},"27":{"q":"Какая отметка CDL Огайо требуется для буксировки сдвоенных или строенных прицепов?","options":["Отметка P","Отметка S","Отметка T","Отметка D"],"explanation":"Отметка T разрешает эксплуатацию составов со сдвоенными/строенными прицепами и получается путём сдачи теоретического экзамена по сдвоенным/строенным прицепам. Источник: информация об отметках Ohio BMV и 49 CFR 383.93."},"28":{"q":"Какая отметка нужна владельцу CDL Огайо для управления коммерческим транспортным средством, предназначенным для перевозки 16 или более пассажиров, включая водителя (кроме школьного автобуса)?","options":["Отметка N","Отметка P","Отметка T","Отметка H"],"explanation":"Отметка P (пассажирская) требуется для управления транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя. Источник: информация об отметках Ohio BMV и 49 CFR 383.93."},"29":{"q":"В Огайо, прежде чем водителю может быть выдана отметка «школьный автобус» (S), какую другую отметку он также должен получить?","options":["Отметку H (HazMat)","Отметку N (цистерна)","Отметку P (пассажирская)","Отметку T (сдвоенные/строенные)"],"explanation":"Федеральные правила и правила Огайо требуют, чтобы отметка S (школьный автобус) сочеталась с отметкой P (пассажирская), поскольку школьный автобус перевозит пассажиров. Источник: информация об отметках Ohio BMV и 49 CFR 383.93."},"30":{"q":"Прежде чем получить отметку HazMat (H), кандидат на CDL в Огайо должен пройти какую дополнительную проверку помимо письменного теоретического экзамена по HazMat?","options":["Оценку угрозы безопасности TSA, включая снятие отпечатков пальцев","Повторный экзамен по навыкам вождения на цистерне","Проверку зрения, проводимую BMV","Аудиторный курс безопасного вождения"],"explanation":"Отметка HazMat требует оценки угрозы безопасности от Управления транспортной безопасности (TSA) с проверкой биографических данных на основе отпечатков пальцев, в дополнение к теоретическому экзамену. Источник: информация по HazMat Ohio BMV и 49 CFR 1572."},"31":{"q":"Водитель должен получить ученическое коммерческое разрешение Огайо (CLP) и владеть им в течение минимального срока, прежде чем ему будет разрешено сдавать экзамен по навыкам (вождению по дороге) для CDL. Каков этот минимальный срок владения?","options":["7 days","14 days","30 days","60 days"],"explanation":"Федеральное правило, принятое в Огайо, требует владеть CLP не менее 14 days, прежде чем кандидат сможет сдавать экзамен по навыкам для CDL. Источник: процедура CDL Ohio BMV и 49 CFR 383.25."},"32":{"q":"При управлении коммерческим транспортным средством с ученическим коммерческим разрешением Огайо (CLP) владелец разрешения должен сопровождаться кем?","options":["Любым лицензированным водителем в возрасте 25 лет или старше","Владельцем CDL надлежащего класса/с надлежащими отметками, сидящим рядом с ним","Только экзаменатором BMV","Никем, если вождение осуществляется в светлое время суток"],"explanation":"Владелец CLP может управлять CMV только в сопровождении лица, имеющего действующий CDL соответствующего класса и с соответствующими отметками, сидящего рядом с владельцем CLP. Источник: правила CLP Ohio BMV и 49 CFR 383.25."},"33":{"q":"С 7 февраля 2022 года лицо, впервые получающее CDL класса A в Огайо, должно пройти подготовку водителей начального уровня (ELDT), предоставляемую организацией, которая является какой?","options":["Внесённой в Реестр поставщиков обучения FMCSA","Аккредитованной Департаментом образования Огайо","Одобренной только местным заместителем регистратора","Сертифицированной Дорожным патрулём штата Огайо"],"explanation":"ELDT должна предоставляться поставщиком, внесённым в Реестр поставщиков обучения (TPR) FMCSA, и сертификация должна быть в реестре до экзамена по навыкам/теоретического экзамена. Источник: правило ELDT FMCSA (49 CFR 380 subpart F) и tpr.fmcsa.dot.gov."},"34":{"q":"Какое из следующих действий, совершаемых впервые, НЕ влечёт за собой требование о федеральной подготовке водителей начального уровня (ELDT)?","options":["Получение CDL класса A впервые","Получение пассажирской отметки (P) впервые","Получение отметки «цистерна» (N) впервые","Получение отметки HazMat (H) впервые"],"explanation":"ELDT применяется к получаемым впервые CDL класса A/B, повышению с B до A и получаемым впервые отметкам P, S и H. Отметки N (цистерна) и T (сдвоенные/строенные) не охватываются ELDT. Источник: применимость ELDT FMCSA (tpr.fmcsa.dot.gov/Drivers/Applicability)."},"35":{"q":"Требование ELDT применяется к лицам, которые получают своё ученическое коммерческое разрешение в какую дату или после неё?","options":["7 февраля 2020 года","7 февраля 2022 года","30 января 2021 года","31 декабря 2023 года"],"explanation":"Требования к подготовке водителей начального уровня применяются к водителям, которые получают CLP 7 февраля 2022 года или позднее. Источник: правило ELDT FMCSA и tpr.fmcsa.dot.gov."},"36":{"q":"В форме самосертификации CDL Огайо какая категория описывает водителя, который работает на маршрутах между штатами и должен соответствовать требованиям федерального медицинского осмотра DOT (медицинской справки)?","options":["Excepted Interstate (освобождённая межштатная)","Non-Excepted Interstate (неосвобождённая межштатная)","Excepted Intrastate (освобождённая внутриштатная)","Non-Excepted Intrastate (неосвобождённая внутриштатная)"],"explanation":"Водители категории Non-Excepted Interstate работают в межштатной коммерческой деятельности и должны соответствовать федеральным медицинским стандартам (Part 391), предоставляя сертификат медицинского эксперта. Источник: форма BMV 2159 Ohio BMV (самосертификация CDL) и 49 CFR 383.71."},"37":{"q":"Какие документы кандидат, впервые получающий CDL в Огайо, должен предъявить в BMV для подтверждения права на получение?","options":["Подтверждение личности/законного присутствия, полный номер социального страхования и подтверждение проживания в Огайо","Только действующее водительское удостоверение Огайо и кредитную карту","Паспорт и два счёта за коммунальные услуги, но без номера социального страхования","Только техпаспорт транспортного средства и подтверждение страхования"],"explanation":"Огайо требует документального подтверждения личности и законного присутствия (например, свидетельство о рождении, паспорт или карту постоянного жителя), номера социального страхования и подтверждения проживания в Огайо. Источник: требования к документам для CDL Ohio BMV (bmv.ohio.gov)."},"38":{"q":"19-летний водитель в Огайо хочет получить CDL для перевозки опасных материалов, требующих знаков опасности. Почему этот водитель НЕ может получить отметку HazMat (H)?","options":["Для перевозки HazMat необходимо быть не моложе 21 года","Отметки HazMat выдаются только водителям класса C","Огайо не предлагает отметку HazMat","Сначала необходимо получить отметку «цистерна» (N)"],"explanation":"Перевозка опасных материалов со знаками опасности допускает межштатную деятельность и требует, чтобы водителю было не менее 21 года; владельцы внутриштатного CDL Огайо в возрасте 18-20 лет не могут иметь отметку H. Источник: требования к CDL Ohio BMV и 49 CFR 383.93/391.11."},"39":{"q":"В Огайо какова максимальная концентрация алкоголя в крови (BAC), которую может иметь водитель при управлении коммерческим транспортным средством (CMV), прежде чем он будет считаться юридически находящимся в состоянии опьянения для целей CDL?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"Огайо следует федеральному стандарту для CMV: управление коммерческим транспортным средством с BAC 0.04 percent или более является серьёзным нарушением. Этот порог составляет половину от лимита 0.08 для некоммерческих водителей. Источник: Ohio CDL Manual / дисквалификации CDL Ohio BMV; ORC 4506.15; 49 CFR 383.51."},"40":{"q":"Получая и используя CDL Огайо, водитель считается давшим согласие на химическое исследование дыхания, крови или мочи для определения содержания алкоголя или наркотиков. Как называется этот правовой принцип?","options":["Подразумеваемое согласие","Вероятная причина","Согласие в рамках надлежащей правовой процедуры","Условное лицензирование"],"explanation":"Закон Огайо о подразумеваемом согласии означает, что управление транспортным средством на дорогах Огайо представляет собой согласие на химическое исследование при законном задержании за нарушение, связанное с алкоголем/наркотиками. Отказ влечёт собственные административные взыскания. Источник: ORC 4511.191; Ohio CDL Manual."},"41":{"q":"В Огайо каков минимальный срок дисквалификации CDL за ПЕРВОЕ серьёзное нарушение водителя, такое как BAC 0.04+ в CMV или отказ от химического исследования, при условии, что НЕ перевозятся опасные материалы со знаками опасности?","options":["1 год","60 days","6 месяцев","3 года"],"explanation":"Первое серьёзное нарушение (BAC 0.04+, OVI, отказ от исследования, оставление места происшествия, использование CMV при совершении тяжкого преступления и т. д.) влечёт за собой дисквалификацию CDL на 1 год в Огайо. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"42":{"q":"Если водитель в Огайо совершает первое серьёзное нарушение (например, BAC 0.04+) при управлении CMV со знаками опасности для опасных материалов, срок дисквалификации увеличивается до:","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Когда первое серьёзное нарушение происходит на транспортном средстве со знаками опасности для опасных материалов, стандартная дисквалификация на 1 год увеличивается до 3 лет. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"43":{"q":"Каков срок дисквалификации CDL в Огайо за ВТОРОЕ серьёзное нарушение (например, второе OVI или второй BAC 0.04+ в CMV)?","options":["Пожизненно","10 лет","3 года","5 лет"],"explanation":"Второе осуждение за любое серьёзное нарушение влечёт за собой пожизненную дисквалификацию CDL в Огайо. Некоторые пожизненные дисквалификации могут быть сокращены до 10 лет после выполнения условий восстановления. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"44":{"q":"Водитель в Огайо, законно задержанный за OVI, отказывается пройти химическое исследование дыхания. Для целей CDL отказ от исследования влечёт за собой дисквалификацию на срок не менее:","options":["1 год","90 days","60 days","30 days"],"explanation":"Отказ от исследования рассматривается как серьёзное нарушение для целей CDL и влечёт за собой дисквалификацию на 1 год (3 года при перевозке опасных материалов со знаками опасности), в дополнение к любому административному приостановлению водительского удостоверения. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"45":{"q":"Согласно закону Огайо о подразумеваемом согласии, владелец CDL, отказавшийся от химического исследования, также подвергается административному приостановлению водительского удостоверения. За ПЕРВЫЙ отказ это административное приостановление, как правило, составляет:","options":["1 год","90 days","6 месяцев","2 года"],"explanation":"Закон Огайо о подразумеваемом согласии устанавливает административное приостановление водительского удостоверения на 1 год за первый отказ от химического исследования, с более длительными сроками за повторные отказы в течение 10 лет. Это отдельно от дисквалификации CDL. Источник: ORC 4511.191."},"46":{"q":"В Огайо сколько СЕРЬЁЗНЫХ нарушений ПДД в отдельных случаях в течение 3-летнего периода влекут за собой дисквалификацию CDL на 60 days?","options":["2","3","4","5"],"explanation":"Осуждение за 2 серьёзных нарушения ПДД в течение 3 лет (в CMV) влечёт за собой дисквалификацию на 60 days. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"47":{"q":"Владелец CDL Огайо осуждён за ТРИ серьёзных нарушения ПДД в отдельных случаях в течение 3-летнего периода. Каков срок дисквалификации CDL?","options":["120 days","60 days","90 days","1 год"],"explanation":"Осуждение за 3 или более серьёзных нарушений ПДД в течение 3 лет влечёт за собой дисквалификацию на 120 days. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"48":{"q":"На сколько превышение установленного ограничения скорости должно быть зафиксировано у водителя CDL, чтобы нарушение засчитывалось как СЕРЬЁЗНОЕ нарушение ПДД в Огайо?","options":["15 mph или более сверх ограничения","10 mph или более сверх ограничения","20 mph или более сверх ограничения","5 mph или более сверх ограничения"],"explanation":"Превышение скорости на 15 mph или более сверх установленного ограничения классифицируется как серьёзное нарушение ПДД для владельцев CDL. Источник: Ohio CDL Manual; ORC 4506.01/4506.16; 49 CFR 383.51."},"49":{"q":"Что из следующего классифицируется как СЕРЬЁЗНОЕ нарушение ПДД для владельца CDL Огайо?","options":["Несоблюдение дистанции (движение вплотную)","Парковка в зоне, где парковка запрещена","Неосвещённый фонарь номерного знака","Первое предписание за перегруз"],"explanation":"Серьёзные нарушения ПДД включают несоблюдение дистанции, неосторожную/беспорядочную смену полосы, превышение скорости на 15+ mph, набор текстовых сообщений за рулём и управление CMV без надлежащего класса/отметки. Нарушения, связанные с оборудованием и парковкой, не являются серьёзными нарушениями. Источник: Ohio CDL Manual; 49 CFR 383.51."},"50":{"q":"В Огайо использование портативного мобильного телефона или набор текстовых сообщений при управлении CMV запрещены. Для целей CDL такое осуждение засчитывается как:","options":["Серьёзное нарушение ПДД","Серьёзное правонарушение (major offense)","Нарушение предписания о выводе из эксплуатации","Нерегистрируемое нарушение"],"explanation":"Набор текстовых сообщений или использование портативного телефона при управлении CMV является серьёзным нарушением ПДД; два таких в течение 3 лет влекут за собой дисквалификацию на 60 days, три — на 120 days. Источник: Ohio CDL Manual; 49 CFR 383.51 и 392.80/392.82."},"51":{"q":"Каков максимальный федеральный гражданский штраф для водителя (применяемый в Огайо) для водителя CMV, который набирает текстовые сообщения при управлении коммерческим транспортным средством?","options":["До $2,750","До $500","До $1,000","До $11,000"],"explanation":"Водитель CMV, который набирает текстовые сообщения за рулём, подвергается федеральному гражданскому штрафу до $2,750; автоперевозчики, допускающие это, могут быть оштрафованы до $11,000. Эти правила применяются в Огайо. Источник: 49 CFR 392.80; правило FMCSA о запрете набора текстовых сообщений."},"52":{"q":"Владелец CDL Огайо совершает ПЕРВОЕ нарушение на железнодорожном переезде (например, непрекращение движения там, где это требуется). Каков срок дисквалификации?","options":["60 days","30 days","120 days","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт за собой дисквалификацию CDL на 60 days. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"53":{"q":"Каков срок дисквалификации CDL в Огайо за ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["120 days","60 days","180 days","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт за собой дисквалификацию на 120 days. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"54":{"q":"Владелец CDL Огайо совершает ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода. Срок дисквалификации составляет:","options":["1 год","120 days","180 days","2 года"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 лет влечёт за собой дисквалификацию на 1 год (365 days). Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"55":{"q":"Каков срок дисквалификации CDL в Огайо за ПЕРВОЕ осуждение водителя за нарушение предписания о выводе из эксплуатации (OOS)?","options":["180 days","60 days","1 год","90 days"],"explanation":"Первое осуждение за нарушение предписания о выводе из эксплуатации влечёт за собой дисквалификацию на срок не менее 180 days. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"56":{"q":"В Огайо каков срок дисквалификации CDL за ВТОРОЕ нарушение предписания о выводе из эксплуатации (OOS) в отдельных случаях в течение 10-летнего периода?","options":["2 года","1 год","180 days","3 года"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10-летнего периода влечёт за собой дисквалификацию на 2 года. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"57":{"q":"Владелец CDL Огайо осуждён за ТРЕТЬЕ нарушение предписания о выводе из эксплуатации в течение 10-летнего периода. Срок дисквалификации составляет:","options":["3 года","2 года","180 days","5 лет"],"explanation":"Третье или последующее нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт за собой дисквалификацию на 3 года. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"58":{"q":"Водитель в Огайо нарушает предписание о выводе из эксплуатации при перевозке опасных материалов со знаками опасности или при управлении транспортным средством, предназначенным для перевозки 16 или более пассажиров. Какова дисквалификация за это ПЕРВОЕ нарушение?","options":["180 days","60 days","1 год","2 года"],"explanation":"Первое нарушение предписания о выводе из эксплуатации при перевозке опасных материалов со знаками опасности или 16+ пассажиров влечёт за собой дисквалификацию на 180 days; последующее такое нарушение в течение 10 лет влечёт за собой 3 года. Источник: дисквалификации CDL Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"59":{"q":"Согласно закону Огайо «Move Over» («Уступи полосу»), когда вы приближаетесь к стоящему эвакуатору, машине дорожной службы или полицейскому автомобилю с включёнными проблесковыми маячками на дороге с двумя или более полосами в вашем направлении, что вы обязаны сделать?","options":["Перестроиться в полосу, не прилегающую к остановившемуся транспортному средству, когда это безопасно сделать","Полностью остановиться, пока это транспортное средство не тронется","Непрерывно сигналить во время проезда","Сохранять свою скорость, но включить аварийную сигнализацию"],"explanation":"Закон Огайо «Move Over» (ORC 4511.213) требует, чтобы водитель, приближающийся к стоящему транспортному средству общественной безопасности, экстренной, дорожной или ремонтной службы с включёнными проблесковыми маячками, перестроился в полосу, не прилегающую к этому транспортному средству, если в том же направлении есть как минимум две полосы и это безопасно. Источник: Ohio Revised Code 4511.213."},"60":{"q":"Согласно закону Огайо «Move Over», если вы не можете безопасно перестроиться (например, на двухполосной дороге) при проезде стоящего экстренного транспортного средства с включёнными маячками, что требует закон?","options":["Двигаться с должной осторожностью, снизить скорость и поддерживать безопасную для условий скорость","Полностью остановиться и ждать, пока сотрудник не пропустит вас взмахом руки","Продолжать движение с установленным ограничением скорости, не замедляясь","Съехать на обочину и остановиться"],"explanation":"Когда перестроение невозможно или небезопасно, ORC 4511.213 требует, чтобы водитель двигался с должной осторожностью, снизил скорость и поддерживал безопасную скорость с учётом дорожных, погодных и транспортных условий. Источник: Ohio Revised Code 4511.213."},"61":{"q":"В Огайо водитель, перевозящий опасные грузы с табличками-плакатами, или управляющий автобусом, обязан остановиться перед железнодорожным переездом в пределах какого расстояния от ближайшего рельса?","options":["Не менее 15 футов и не более 50 футов","Не менее 5 футов и не более 25 футов","Не менее 25 футов и не более 75 футов","Не менее 10 футов и не более 100 футов"],"explanation":"Водитель автобуса или транспортного средства с табличками-плакатами опасных грузов обязан остановиться в пределах 50 футов, но не ближе 15 футов от ближайшего рельса на железнодорожном переезде, затем посмотреть и прислушаться, прежде чем продолжить движение. Источник: Ohio CDL Manual / 49 CFR 392.10; обязательная остановка требуется по ORC 4511.63."},"62":{"q":"Какое из следующих транспортных средств ОБЯЗАНО останавливаться на каждом неисключённом железнодорожном переезде в Огайо?","options":["Транспортное средство, перевозящее материалы, которые должны иметь таблички-плакаты согласно федеральным правилам по опасным грузам","Любой пикап, буксирующий хозяйственный прицеп","Любой грузовик без прицепа полной массой свыше 10 000 фунтов","Любое транспортное средство со сдвоенными задними колёсами"],"explanation":"ORC 4511.63 требует, чтобы водитель любого автобуса, любого школьного транспортного средства или любого транспортного средства, перевозящего материал, который должен иметь таблички-плакаты согласно 49 CFR Parts 100-185, останавливался перед пересечением железнодорожных путей. На обычные грузовики и прицепы обязательная остановка не распространяется. Источник: Ohio Revised Code 4511.63."},"63":{"q":"На двухполосной дороге Огайо, когда вы встречаете остановившийся школьный автобус, который высаживает или забирает детей с включёнными красными мигающими огнями, вы обязаны остановиться на расстоянии не менее скольких футов от автобуса?","options":["Не менее 10 футов от передней или задней части автобуса","Не менее 20 футов от передней или задней части автобуса","Не менее 30 футов от передней или задней части автобуса","Не менее 50 футов от передней или задней части автобуса"],"explanation":"ORC 4511.75 требует, чтобы водитель, встречающий или обгоняющий остановившийся школьный автобус, остановился не менее чем в 10 футах от передней или задней части автобуса и не продолжал движение, пока автобус не тронется или водитель автобуса не подаст сигнал продолжать движение. Источник: Ohio Revised Code 4511.75."},"64":{"q":"В Огайо, на дороге, разделённой на сколько полос движения, встречный транспорт может продолжать движение без остановки перед школьным автобусом, остановившимся на противоположной стороне?","options":["Четыре или более полос","Две или более полос","Три или более полос","Шесть или более полос"],"explanation":"Закон Огайо о школьных автобусах предусматривает, что на дороге с четырьмя или более полосами водитель не обязан останавливаться перед школьным автобусом, остановившимся на противоположной стороне; останавливаться обязан только транспорт, движущийся в том же направлении, что и автобус. Источник: Ohio Revised Code 4511.75."},"65":{"q":"После остановки перед школьным автобусом в Огайо на двухполосной дороге, когда вы можете продолжить движение?","options":["Когда автобус возобновляет движение или водитель автобуса подаёт вам сигнал продолжать движение","Как только дети сошли с проезжей части","После обязательного ожидания в течение 30 секунд","Как только жёлтые огни автобуса начинают мигать"],"explanation":"ORC 4511.75 устанавливает, что остановившийся водитель не должен продолжать движение, пока школьный автобус не возобновит движение или пока водитель школьного автобуса не подаст сигнал продолжать движение. Источник: Ohio Revised Code 4511.75."},"66":{"q":"Каково максимальное ограничение скорости для тягача с полуприцепом на сельской межштатной автомагистрали в Огайо (если не установлено более низкое ограничение)?","options":["70 mph, как и для легковых автомобилей","55 mph, ниже, чем для легковых автомобилей","60 mph, ниже, чем для легковых автомобилей","65 mph, ниже, чем для легковых автомобилей"],"explanation":"Огайо не устанавливает отдельное, более низкое ограничение скорости для грузовиков. Согласно ORC 4511.21, максимум на сельских межштатных автомагистралях составляет 70 mph, и коммерческие грузовики могут двигаться с тем же ограничением, что и легковые автомобили, если не указано иное. Источник: Ohio Revised Code 4511.21; правила скоростных зон ODOT."},"67":{"q":"Каково ограничение скорости для коммерческих грузовиков на основной магистрали платной дороги Ohio Turnpike?","options":["70 mph, как и для легковых транспортных средств","65 mph для грузовиков, в то время как легковым автомобилям разрешено 70","55 mph для всех грузовиков","60 mph для грузовиков, в то время как легковым автомобилям разрешено 70"],"explanation":"На платной дороге Ohio Turnpike установлено ограничение 70 mph на основной магистрали, которое применяется ко всем транспортным средствам, включая коммерческие грузовики; Огайо не устанавливает отдельное более низкое ограничение скорости для грузовиков. Источник: Ohio Turnpike and Infrastructure Commission; ORC 4511.21."},"68":{"q":"На многополосной дороге Огайо водитель грузовика, движущийся медленнее преобладающей скорости потока, как правило, обязан делать что?","options":["Двигаться в правой полосе, доступной для движения, кроме случаев обгона или поворота налево","Держаться центральной полосы, чтобы избежать перестраивающихся транспортных средств","Использовать левую полосу, чтобы более быстрый транспорт мог перестраиваться справа","Использовать любую полосу при включённой аварийной сигнализации"],"explanation":"ORC 4511.25 требует, чтобы транспортное средство, движущееся медленнее преобладающей разрешённой скорости, двигалось в правой полосе, доступной для движения, достаточно близко к правому краю, чтобы обеспечить безопасный обгон, кроме случаев обгона, поворота налево или когда маршрут требует другой полосы. Источник: Ohio Revised Code 4511.25."},"69":{"q":"Когда грузовик неисправен и остановлен на дороге Огайо, как следует разместить три предупреждающих устройства (фальшфейеры, светоотражатели или фонари)?","options":["Одно примерно в 100 футах впереди, одно примерно в 100 футах позади и одно со стороны движения","Все три размещены прямо позади транспортного средства в ряд","По одному с каждой стороны и одно на крыше кабины","Одно в 10 футах впереди, одно в 10 футах позади и одно на обочине"],"explanation":"ORC 4513.28 требует размещения предупреждающих устройств примерно в 100 футах впереди транспортного средства, примерно в 100 футах позади и одного со стороны движения неисправного транспортного средства. Источник: Ohio Revised Code 4513.28."},"70":{"q":"Как классифицируется первое нарушение закона Огайо «Move Over» (ORC 4511.213)?","options":["Малозначительный проступок (minor misdemeanor) с удвоенным штрафом (примерно до $300)","Уголовное преступление пятой степени (felony of the fifth degree)","Гражданское правонарушение без движения и без штрафных баллов","Проступок первой степени (first-degree misdemeanor) с обязательным тюремным заключением"],"explanation":"Первое нарушение по ORC 4511.213 является малозначительным проступком (minor misdemeanor), но суд обязан назначить штраф в два раза больше обычной суммы, что составляет примерно до $300. Повторные нарушения в течение года повышаются до проступков четвёртой и третьей степени. Источник: Ohio Revised Code 4511.213."},"71":{"q":"Какова в Огайо максимальная разрешённая законом ширина коммерческого транспортного средства или груза, прежде чем потребуется разрешение на негабарит?","options":["8 футов 6 дюймов (102 inches)","8 футов 0 дюймов (96 inches)","9 футов 0 дюймов (108 inches)","10 футов 0 дюймов (120 inches)"],"explanation":"Максимальная разрешённая законом ширина транспортного средства в Огайо составляет 8 футов 6 дюймов (102 inches); всё, что шире, требует специального разрешения на перевозку от ODOT. Источник: ORC 5577.05; правила ODOT по специальным разрешениям на перевозку."},"72":{"q":"Какова в Огайо максимальная разрешённая законом высота транспортного средства с грузом, прежде чем потребуется разрешение?","options":["13 футов 6 дюймов","12 футов 6 дюймов","14 футов 0 дюймов","13 футов 0 дюймов"],"explanation":"Максимальная разрешённая законом высота в Огайо составляет 13 футов 6 дюймов; грузы выше этого требуют разрешения на негабарит от ODOT. Источник: ORC 5577.05; Ohio DOT Special Hauling Permit Operational Guide."},"73":{"q":"Кто выдаёт специальное разрешение, позволяющее негабаритному или сверхтяжёлому транспортному средству двигаться по дорогам штата Огайо?","options":["Директор транспорта Огайо (ODOT)","Бюро автотранспортных средств Огайо (BMV)","Шериф каждого округа на маршруте","Командир поста Дорожного патруля штата Огайо"],"explanation":"Транспортные средства, превышающие законные пределы по размеру или весу, могут двигаться по дороге штата только при наличии специального письменного разрешения, выданного директором транспорта Огайо. Источник: ORC 4513.34 и 5577.04; ODOT Special Hauling Permits."},"74":{"q":"Какова в Огайо максимальная полная масса транспортного средства, разрешённая без разрешения на перегруз, в соответствии с федеральным пределом?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"Огайо следует федеральному максимуму полной массы в 80,000 pounds (с учётом Федеральной мостовой формулы); превышение требует разрешения на перегруз от ODOT. Источник: ORC 5577.04; Federal Bridge Formula."},"75":{"q":"Когда транспортное средство с табличками-плакатами опасных грузов приближается к железнодорожному переезду в Огайо, какое действие является правильным при пересечении путей?","options":["Не переключать передачи, пока какая-либо часть транспортного средства находится на путях","Переключиться на пониженную передачу при пересечении для лучшего контроля","Остановиться на полпути для проверки наличия второго поезда","Заглушить двигатель, пока полностью не пересечёте пути"],"explanation":"После остановки, осмотра и прислушивания водитель должен пересекать пути на передаче, которую не потребуется менять, и не должен переключать передачи, пока какая-либо часть транспортного средства находится на путях. Источник: Ohio CDL Manual / 49 CFR 392.10; ORC 4511.63."},"76":{"q":"На разделённой автомагистрали с четырьмя полосами в Огайо школьный автобус, останавливающийся для высадки детей, должен, где это практически осуществимо, делать что, чтобы снизить риск перехода дороги?","options":["Забирать и высаживать пассажиров со стороны жилых домов от автомагистрали","Останавливаться на разделительной полосе, чтобы дети могли использовать переход","Высаживать всех пассажиров на левой обочине","Требовать, чтобы всех детей через дорогу сопровождал водитель"],"explanation":"На разделённых автомагистралях или дорогах с четырьмя или более полосами школьные автобусы должны забирать и высаживать детей со стороны жилых домов, чтобы детям не приходилось переходить проезжую часть; именно поэтому встречный транспорт не обязан останавливаться. Источник: Ohio Revised Code 4511.75; правила Огайо о школьных автобусах."},"77":{"q":"Согласно закону Огайо, когда установленный знак «STOP» размещён на обозначенном опасном железнодорожном переезде, водитель должен остановиться в пределах какого расстояния от ближайшего рельса?","options":["Не менее 15 футов, но в пределах 50 футов","Не менее 5 футов, но в пределах 20 футов","Не менее 30 футов, но в пределах 60 футов","Точно в 25 футах от ближайшего рельса"],"explanation":"ORC 4511.61 требует, чтобы водитель остановился в пределах пятидесяти футов, но не ближе пятнадцати футов от ближайшего рельса на железнодорожном переезде, где установлен знак «STOP», и не продолжал движение, пока это не станет безопасным. Источник: Ohio Revised Code 4511.61."},"78":{"q":"Какое утверждение лучше всего описывает, устанавливает ли Огайо отдельные ограничения скорости для грузовиков, отличные от легковых автомобилей?","options":["Огайо устанавливает одинаковые максимальные ограничения скорости для грузовиков и легковых автомобилей; грузовикам не назначается отдельный более низкий общештатный лимит","Грузовики всегда ограничены 55 mph по всему штату независимо от установленного ограничения","Грузовики должны двигаться на 10 mph ниже установленного для легковых автомобилей лимита на всех скоростных трассах","Грузовики могут использовать только платную дорогу Ohio Turnpike, и им запрещён выезд на межштатные автомагистрали"],"explanation":"Огайо применяет одинаковые установленные максимальные ограничения скорости к коммерческим грузовикам и легковым автомобилям согласно ORC 4511.21; отдельного более низкого общештатного ограничения скорости для грузовиков нет, хотя водители всё равно должны двигаться с безопасной для условий скоростью. Источник: Ohio Revised Code 4511.21; ODOT."},"79":{"q":"Какое государственное ведомство выдаёт коммерческие водительские удостоверения (CDL) в Огайо?","options":["Бюро автотранспортных средств Огайо (BMV)","Департамент транспорта Огайо (ODOT)","Дорожный патруль штата Огайо","Федеральное управление безопасности коммерческого автотранспорта (FMCSA)"],"explanation":"В Огайо Бюро автотранспортных средств (BMV), подразделение Департамента общественной безопасности Огайо, выдаёт все водительские удостоверения, включая CDL. ODOT занимается дорогами и разрешениями на негабарит/перегруз, а не выдачей удостоверений, а FMCSA — это федеральное ведомство, устанавливающее стандарты. Источник: Ohio BMV, страница Commercial Driver (CDL)."},"80":{"q":"Прежде чем кандидат на CDL в Огайо сможет сдать любой коммерческий теоретический тест, где этот тест должен быть сдан?","options":["Лично в экзаменационном пункте водителей Ohio BMV","Онлайн с любого домашнего компьютера","По почте с использованием бланка ответов для выполнения дома","У зарегистрированного FMCSA поставщика обучения ELDT"],"explanation":"Огайо требует, чтобы теоретические тесты CDL (общие знания, дополнения и снятие ограничения по пневматическим тормозам) сдавались лично в экзаменационном пункте водителей BMV; их нельзя сдать онлайн. Поставщики ELDT предоставляют обучение, а не государственный теоретический тест. Источник: Ohio BMV, страница Commercial Driver (CDL)."},"81":{"q":"Сколько действует коммерческое ученическое разрешение Огайо (CLP) после выдачи?","options":["12 месяцев","6 месяцев","30 дней","24 месяца"],"explanation":"Огайо устанавливает, что CLP действителен в течение 12 месяцев. (Согласно федеральному правилу его можно один раз продлить без повторной сдачи теста на общие знания.) Отвлекающие варианты отражают распространённые, но неверные сроки действия разрешений. Источник: Ohio BMV, страница Commercial Driver (CDL)."},"82":{"q":"После получения CLP в Огайо как долго кандидат должен владеть им, прежде чем получит право сдавать практический тест CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"Федеральное правило, применяемое в Огайо, требует владеть CLP не менее 14 дней, прежде чем его обладатель сможет сдать практический (дорожный) тест CDL. Источник: процесс получения CDL в Ohio BMV / 49 CFR 383.25 (FMCSA)."},"83":{"q":"Практический тест CDL в Огайо проводится в три части. В каком наборе правильно перечислены эти три части?","options":["Предрейсовый осмотр, базовое управление (маневрирование) и вождение по дороге","Письменный тест на знания, проверка зрения и вождение по дороге","Предрейсовый осмотр, проверка пневматических тормозов и обращение с опасными грузами","Базовое управление, ночное вождение и письменный экзамен на дополнение"],"explanation":"Практический тест CDL в Огайо состоит из трёх частей: предрейсовый осмотр, тест базового управления (маневрирования) и тест вождения по дороге. Проверка зрения и письменные экзамены отделены от практического теста. Источник: Ohio BMV, страница Commercial Driver (CDL)."},"84":{"q":"Что кандидат в Огайо должен представить в электронном виде ПЕРЕД тем, как он сможет записаться на практический тест CDL или попытаться его сдать?","options":["Подтверждение прохождения обучения для водителей начального уровня (ELDT) или подтверждение освобождения","Подтверждение двухлетнего предыдущего опыта вождения","Подписанное спонсорское письмо от работодателя","Проходной балл за курс безопасного вождения"],"explanation":"Огайо требует электронного подтверждения прохождения обучения для водителей начального уровня FMCSA (ELDT), соответствующего запрашиваемому классу/дополнению, или подтверждения освобождения, прежде чем можно будет записаться на практический тест или попытаться его сдать. Источник: страница CDL Ohio BMV / правило FMCSA ELDT (49 CFR Part 380)."},"85":{"q":"Процесс самосертификации в Огайо требует, чтобы кандидат на CDL/CLP выбрал из скольких категорий типа вождения?","options":["Четыре","Две","Три","Пять"],"explanation":"Водители Огайо должны самосертифицироваться в одну из четырёх категорий: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Источник: Ohio BMV CDL Self-Certification (форма BMV 2159)."},"86":{"q":"Водитель в Огайо пересекает границы штатов по работе и должен соответствовать федеральным стандартам физической пригодности (медицинским) согласно 49 CFR Part 391. Какая категория самосертификации применяется?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Категория Non-Excepted Interstate охватывает водителей, которые работают через границы штатов и должны соответствовать федеральным медицинским требованиям 49 CFR Part 391; эти водители должны хранить действующую справку медицинского эксперта. Источник: категории самосертификации Ohio BMV (форма BMV 2159)."},"87":{"q":"Начиная с 23 июня 2025 года (June 23, 2025), как информация из справки медицинского эксперта DOT обладателя CDL передаётся в Ohio BMV?","options":["FMCSA электронно передаёт результаты осмотра в BMV, поэтому бумажная справка больше не требуется","Водитель должен отправить заверенную нотариусом бумажную копию в BMV в течение 10 дней","Медицинский эксперт отправляет по факсу карточку размером с бумажник, которую водитель ламинирует","Справка загружается только работодателем водителя"],"explanation":"По состоянию на 23 июня 2025 года (June 23, 2025) FMCSA электронно передаёт результаты медицинского осмотра (и информацию об отклонениях) для кандидатов на CLP и обладателей CDL в Ohio BMV, поэтому водители больше не представляют бумажную справку медицинского эксперта. Источник: уведомление о медицинской сертификации CDL Ohio BMV / правило FMCSA Medical Examiner's Certification Integration."},"88":{"q":"Какая форма Ohio BMV используется для самосертификации CDL по типу коммерческого вождения водителя?","options":["BMV 2159 (CDL Self-Certification Authorization)","BMV 2290 (форма налога на использование тяжёлых транспортных средств)","BMV 5759 (форма дополнения по опасным грузам)","BMV 1173 (форма регистрации транспортного средства)"],"explanation":"Огайо использует форму BMV 2159, CDL Self-Certification Authorization, чтобы водитель заявил одну из четырёх категорий типа вождения. Источник: форма Ohio BMV BMV 2159."},"89":{"q":"Каково минимальное количество правильных ответов, необходимое для прохождения теста CDL на общие знания в Огайо, состоящего из 50 вопросов?","options":["40 правильных (80%)","35 правильных (70%)","45 правильных (90%)","30 правильных (60%)"],"explanation":"Тесты CDL на знания в Огайо требуют для прохождения как минимум 80%; на тесте на общие знания из 50 вопросов это означает 40 правильных ответов. Стандарт в 80% применяется и к тестам на дополнения. Источник: руководство CDL Огайо / стандарты тестирования Ohio BMV."},"90":{"q":"Согласно Ohio Revised Code 4506.14, каков максимальный срок, на который может быть выдано стандартное (без HazMat) CDL в Огайо?","options":["Восемь лет","Четыре года","Пять лет","Десять лет"],"explanation":"ORC 4506.14 предусматривает, что ни одно CDL не может быть выдано на срок более восьми лет; CDL привязаны ко дню рождения обладателя. Однако дополнение по опасным грузам ограничивает срок выдачи четырьмя годами и 180 днями. Источник: Ohio Revised Code 4506.14."},"91":{"q":"Из-за федеральных ограничений на проверку биографических данных (TSA) CDL в Огайо с дополнением по опасным грузам не может быть выдано на срок более какого периода?","options":["Четыре года и 180 дней","Ровно четыре года","Пять лет","Восемь лет"],"explanation":"ORC 4506.14 ограничивает CDL с дополнением по опасным грузам сроком в четыре года и 180 дней, что соответствует федеральному циклу оценки угрозы безопасности по HazMat. Стандартные CDL могут действовать до восьми лет. Источник: Ohio Revised Code 4506.14."},"92":{"q":"Согласно закону Огайо, за сколько времени до даты истечения срока действия CDL может быть продлено?","options":["До 180 дней до истечения срока","До 30 дней до истечения срока","До 90 дней до истечения срока","Только в день истечения срока или после него"],"explanation":"ORC 4506.14 устанавливает, что CDL подлежит продлению начиная за 180 дней до истечения его срока действия при условии уплаты требуемых сборов. Источник: Ohio Revised Code 4506.14."},"93":{"q":"Регистратор Огайо может освободить обладателя CDL от экзамена при продлении только если кандидат предъявит CDL, срок действия которого не истёк или истёк не более какого времени до даты подачи заявления?","options":["Шесть месяцев","Один месяц","Три месяца","Один год"],"explanation":"ORC 4506.14 позволяет регистратору освободить от экзамена при продлении, если кандидат предъявляет CDL с непросроченным сроком действия или с истёкшим не более чем за шесть месяцев до даты подачи заявления. По истечении этого льготного периода, как правило, требуется повторная сдача экзамена. Источник: Ohio Revised Code 4506.14."},"94":{"q":"Каков минимальный возраст для получения CDL в Огайо с ограничением вождения только в пределах штата (INTRASTATE, только в Огайо)?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Огайо устанавливает минимальный возраст CDL в 18 лет для работы только в пределах штата; водители моложе 21 года ограничены вождением в пределах Огайо. Работа между штатами и перевозка опасных грузов требуют возраста 21 год. Источник: требования к CDL Ohio BMV."},"95":{"q":"Какого возраста должен достичь кандидат в Огайо, чтобы управлять коммерческим транспортным средством в торговле между штатами (INTERSTATE) или перевозить опасные грузы?","options":["21 год","18 лет","23 года","25 лет"],"explanation":"Федеральное правило, применяемое в Огайо, требует, чтобы водителю было не менее 21 года для работы в торговле между штатами или для перевозки опасных грузов с табличками-плакатами. Водители в возрасте 18-20 лет ограничены вождением в пределах штата. Источник: требования к CDL Ohio BMV / 49 CFR 391.11."},"96":{"q":"Помимо действующего водительского удостоверения Огайо и подтверждения номера социального страхования, что ещё должен предъявить кандидат, впервые подающий заявление на CDL в Огайо?","options":["Подтверждение гражданства США или законного постоянного проживания","Заверенное нотариусом письмо от текущего работодателя","Аттестат о среднем образовании или сертификат GED","Двух личных поручителей, имеющих CDL"],"explanation":"Огайо требует, чтобы впервые подающие заявление на CDL предоставили действующее водительское удостоверение Огайо, действительный номер социального страхования и подтверждение гражданства США или законного постоянного проживания (например, паспорт, свидетельство о рождении или карту постоянного жителя). Источник: Ohio BMV, страница Commercial Driver (CDL)."},"97":{"q":"Водитель в Огайо самосертифицируется как «Excepted Interstate». Что эта категория указывает о его федеральных медицинских требованиях?","options":["Он ездит через границы штатов, но НЕ обязан соответствовать федеральным медицинским стандартам (Part 391)","Он ездит только в пределах Огайо и должен соответствовать медицинским стандартам штата","Он всегда должен иметь при себе федеральную справку медицинского эксперта","Он никогда не использует CDL в коммерческих целях"],"explanation":"Excepted Interstate означает, что водитель работает через границы штатов, но имеет право на освобождение от федеральных требований физической пригодности 49 CFR Part 391, поэтому медицинская карта DOT для такой работы не требуется. Источник: категории самосертификации Ohio BMV (форма BMV 2159)."},"98":{"q":"При сдаче практического теста CDL в Огайо кто, как правило, отвечает за предоставление коммерческого транспортного средства, используемого для теста?","options":["Кандидат, который должен предоставить (или арендовать) транспортное средство, представляющее запрашиваемый класс","Ohio BMV, которое содержит парк тестовых транспортных средств","ODOT, которое предоставляет транспортные средства в аренду для дорожных тестов","Региональный офис FMCSA"],"explanation":"Огайо требует, чтобы кандидат предоставил подходящее коммерческое транспортное средство, представляющее тестируемый класс, или арендовал его (часто через сторонний испытательный пункт). BMV не предоставляет тестовые транспортные средства. Источник: Ohio BMV, страница Commercial Driver (CDL)."}},"tr":{"0":{"q":"Ohio karayollarında, özel taşıma izni olmadan bir aracın yükü dahil yasal maksimum genişliği nedir?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","8 feet 2 inches (98 inches)"],"explanation":"Ohio Revised Code 5577.05, yük dahil maksimum araç genişliğini 102 inches (8 feet 6 inches) olarak belirler. Bundan daha geniş olan her şey bir ODOT özel taşıma izni gerektirir."},"1":{"q":"Ohio karayollarında izin olmadan bir aracın ve yükünün yasal maksimum yüksekliği nedir?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","14 feet 6 inches"],"explanation":"Ohio Revised Code 5577.05'e göre, yüklü ya da yüksüz maksimum yükseklik 13 feet 6 inches (13.5 feet) olarak belirlenmiştir. Üst geçitleri ve yapıları güvenli şekilde geçmek sürücünün sorumluluğundadır."},"2":{"q":"Ohio'da, çekici-yarı römork kombinasyonunda izin olmadan kullanılan bir yarı römorkun maksimum uzunluğu nedir?","options":["48 feet","53 feet","57 feet","45 feet"],"explanation":"Ohio Revised Code 5577.05, ticari bir çekici-yarı römork kombinasyonunda kullanıldığında federal ulusal şebeke standardıyla uyumlu olarak 53 feet uzunluğa kadar yarı römorka izin verir."},"3":{"q":"Özel taşıma izni olmadan Ohio karayollarında taşınabilecek bir aracın ve yükünün maksimum brüt ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"Ohio Revised Code 5577.04, yol yüzeyine uygulanan maksimum toplam brüt ağırlığı, federal Interstate sınırıyla aynı olan 80,000 pounds ile sınırlar."},"4":{"q":"Ohio yasalarına göre, bir aracın herhangi bir tek dingilindeki ağırlık hangi miktarı aşamaz?","options":["18,000 pounds","22,400 pounds","20,000 pounds","24,000 pounds"],"explanation":"Ohio Revised Code 5577.04, maksimum tek dingil ağırlığını federal tek dingil standardıyla eşleşen 20,000 pounds ile sınırlar."},"5":{"q":"Ohio'nun interstate sisteminde bir tandem dingil grubuna izin verilen maksimum ağırlık nedir?","options":["32,000 pounds","36,000 pounds","38,000 pounds","34,000 pounds"],"explanation":"Ohio Revised Code 5577.04, maksimum tandem dingil ağırlığını federal tandem dingil sınırıyla uyumlu olarak 34,000 pounds olarak belirler."},"6":{"q":"Ohio karayollarında izin olmadan, otobüs veya karavan dışındaki herhangi bir tek (römorksuz) aracın maksimum uzunluğu nedir?","options":["40 feet","50 feet","45 feet","53 feet"],"explanation":"Ohio Revised Code 5577.05, tek bir aracı (otobüsler gibi özel olarak listelenen araçlar dışında) 50 feet uzunlukla sınırlar."},"7":{"q":"Ohio'da hangi eyalet kurumu eyalet, federal ve interstate karayollarında seyahat için aşırı boyut/aşırı ağırlık özel taşıma izinleri verir?","options":["Ohio Bureau of Motor Vehicles (BMV)","Ohio State Highway Patrol","Public Utilities Commission of Ohio (PUCO)","Ohio Department of Transportation (ODOT)"],"explanation":"Ohio Department of Transportation (ODOT), Ohio Hauling Permit System (ODOT Special Hauling Permits) aracılığıyla elektronik olarak işlenen özel taşıma izinlerini verir."},"8":{"q":"Ohio karayollarında çekici-yarı römork-römork (ikili) kombinasyonunda, izin olmadan her bir yarı römork veya römorkun maksimum uzunluğu nedir?","options":["28 feet 6 inches","33 feet","27 feet","30 feet"],"explanation":"Ohio Revised Code 5577.05, ticari bir çekici-yarı römork-römork veya çekici-yarı römork-yarı römork kombinasyonunda kullanıldığında her bir yarı römork veya römorku 28 feet 6 inches ile sınırlar."},"9":{"q":"Ohio karayolundaki bir kamyon kombinasyonu yasal sınırlar için fazla ağırdır. Operatör seyahat etmeden önce hangi tür izni almalıdır?","options":["CDL üzerinde bir geniş yük onayı","Bir ODOT özel taşıma izni","Bir federal FMCSA aşırı ağırlık muafiyeti","İlçe tarafından verilen bir yol teminat sertifikası"],"explanation":"ODOT'a göre, Ohio'nun yasal boyut veya ağırlık sınırlarını aşan herhangi bir araç veya yük, eyalet, federal veya interstate karayollarında çalışmadan önce ODOT'tan bir özel taşıma izni almalıdır."},"10":{"q":"Ohio karayollarında, başka türlü özel olarak belirtilmemiş araç kombinasyonları için (örneğin genel bir çekici-yarı römork-römork kombinasyonu) maksimum uzunluk nedir?","options":["60 feet","75 feet","65 feet","70 feet"],"explanation":"Ohio Revised Code 5577.05, başka türlü belirtilmemiş herhangi bir araç kombinasyonu için maksimum 65 feet belirler."},"11":{"q":"Çoklu dingil grupları için Ohio yasasında benimsenen federal köprü formülü W = 500((LN/(N-1)) + 12N + 36) şeklindedir. Bu formülde 'L' neyi temsil eder?","options":["Köprünün yasal yük derecesi","Grubun en uç (ilk ve son) dingilleri arasındaki feet cinsinden mesafe","Kombinasyondaki en uzun römorkun uzunluğu","Aracın toplam ruhsatlı brüt ağırlığı"],"explanation":"Ohio Revised Code 5577.04(C)'de belirtilen köprü formülünde, L grubun ön ve en arka dingilleri arasındaki feet cinsinden mesafe, N dingil sayısı ve W izin verilen maksimum brüt ağırlıktır."},"12":{"q":"Ohio'nun özel ağırlık hükümlerine göre, uygun bir çiftlik, tomruk, kömür veya katı atık kamyonu, üretimden ilk teslimat noktasına taşıma yaparken normal ağırlık sınırlarını yüzde kaç oranında aşabilir?","options":["5 percent","10 percent","7.5 percent","12.5 percent"],"explanation":"Ohio Revised Code 5577.042, uygun çiftlik, tomruk, kömür ve katı atık taşıma araçlarının açıklanan koşullar altında ağırlık hükümlerini en fazla 7.5 percent aşmasına izin verir."},"13":{"q":"Ohio'nun çiftlik kamyonları, tomruk kamyonları ve çiftlik makineleri için yüzde 7.5'lik ağırlık toleransı hangi aylarda UYGULANMAZ?","options":["Şubat ve Mart","Ocak ve Şubat","Mart ve Nisan","Kasım ve Aralık"],"explanation":"Ohio Revised Code 5577.042, yüzde 7.5'lik toleransın çiftlik kamyonları, tomruk kamyonları veya çiftlik makineleri için Şubat ve Mart aylarında (mevsimsel donma/çözülme dönemi) uygulanmadığını belirtir."},"14":{"q":"ORC 5577.042 kapsamındaki Ohio'nun yüzde 7.5'lik tarım/orman ürünleri ağırlık toleransı hangi yollarda UYGULANMAZ?","options":["İlçe yolları","Interstate karayolları","Belde (township) yolları","Belediye sokakları"],"explanation":"Ohio Revised Code 5577.042, yüzde 7.5'lik toleransın interstate karayollarında (veya özel olarak düşürülmüş maksimum ağırlıklara tabi yollarda) uygulanmadığını belirtir."},"15":{"q":"ODOT kurallarına göre, bir yük brüt ağırlığı hangi miktarı aştığında 'superload' olarak sınıflandırılır?","options":["80,000 pounds","100,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"ODOT'un Operational Guide'ına göre, superload, brüt ağırlığı 120,000 pounds'u aşan (veya genişliği 14 feet'i veya yüksekliği 14 feet 6 inches'i aşan) ve köprü/yapısal analiz gibi ek inceleme gerektiren herhangi bir araç/yüktür."},"16":{"q":"Ohio'nun interstate dışı (genel karayolu) sisteminde, 4 feet'ten fazla aralıklı iki ardışık dingil, 34,000 pounds artı her ek feet için 1,000 pounds taşıyabilir, ancak hangi maksimumdan fazla olamaz?","options":["38,000 pounds","42,000 pounds","44,000 pounds","40,000 pounds"],"explanation":"Ohio Revised Code 5577.04, interstate dışı sistemde 4 feet'ten fazla aralıklı iki ardışık dingilin, 34,000 pounds artı 4 feet üzerindeki her feet için 1,000 pounds taşıyabileceğini, maksimum 40,000 pounds'a kadar olabileceğini öngörür."},"17":{"q":"ODOT eskort kurallarına göre, hangi ölçüden daha geniş bir araç/yük, iki şeritli bir Ohio karayolunda bir öncü (ön) eskort aracı gerektirir?","options":["12 feet","13 feet","11 feet","10 feet"],"explanation":"ODOT'un izin eskort gerekliliklerine göre, toplam genişliği 13 feet'ten fazla olan herhangi bir araç/yük için bir öncü eskort gereklidir; 14 feet 6 inches'ten daha geniş yükler hem bir öncü hem de bir arka eskort gerektirir."},"18":{"q":"ODOT izin kurallarına göre, 12 feet'ten daha dar bir aşırı boyutlu yükün genellikle hangi günlük zaman aralığında seyahat etmesine izin verilir?","options":["Yalnızca 9:00 a.m. ile 3:00 p.m. arasında","Gün doğumundan 30 dakika önce ile gün batımından 30 dakika sonrasına kadar","Gün doğumundan bir saat sonra ile gün batımından bir saat öncesine kadar","Yalnızca tam gün ışığı saatlerinde, gün doğumundan gün batımına kadar"],"explanation":"ODOT'a göre, 12 feet'ten dar aşırı boyutlu yükler, haftanın yedi günü (tatiller hariç) gün doğumundan 30 dakika önce ile gün batımından 30 dakika sonrasına kadar seyahat edebilir; 12 feet veya daha geniş yükler izinde belirtilen özel saatlere uymalıdır."},"19":{"q":"Ohio'nun interstate sisteminde, iki ardışık tandem dingil seti, iki setin ilk ve son dingilleri arasındaki mesafe en az kaç feet olması koşuluyla her biri 34,000 pounds taşıyabilir?","options":["30 feet","40 feet","36 feet","34 feet"],"explanation":"Ohio Revised Code 5577.04, iki ardışık tandem dingil setinin yalnızca ardışık setlerin ilk ve son dingilleri arasındaki toplam mesafe 36 feet veya daha fazla olduğunda her biri 34,000 pounds taşımasına izin verir."},"20":{"q":"Ohio'da, çekilen ünitenin GVWR'si 10,000 pounds'tan fazla olması koşuluyla, 26,001 pounds veya daha fazla Gross Combination Weight Rating (GCWR) değerine sahip araç kombinasyonlarını kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Ohio'nun Class A CDL'si, çekilen ünitenin GVWR'sinin 10,000 lbs'ı aştığı durumda, 26,001 lbs veya daha fazla GCWR'ye sahip kombinasyon araçlarını kapsar. Kaynak: Ohio BMV CDL Classes sayfası (bmv.ohio.gov/dl-cdl-classes.aspx) ve Ohio'da benimsenen 49 CFR 383.91."},"21":{"q":"Bir Ohio sürücüsü, 10,000 pounds'ı aşan herhangi bir römork çekmeyen, GVWR'si 30,000 pounds olan tek bir düz kamyon kullanıyor. Hangi CDL sınıfı uygundur?","options":["Class A","Class B","Class C","Class E"],"explanation":"Ohio'nun Class B CDL'si, GVWR'si 26,001 lbs veya daha fazla olan herhangi bir tek aracı kapsar ve GVWR'si 10,000 lbs'ı aşmayan bir römork çekebilir. Kaynak: Ohio BMV CDL Classes sayfası (bmv.ohio.gov/dl-cdl-classes.aspx)."},"22":{"q":"Ohio kurallarına göre, Class A veya B için ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) veya plaka (placard) gerektiren tehlikeli maddeler taşımak için tasarlanmış bir araç hangi CDL sınıfına girer?","options":["Class A","Class B","Class C","Class M"],"explanation":"Ohio'nun Class C CDL'si, Class A/B ağırlık eşiklerinin altında olan ve 16+ kişi (sürücü dahil) veya plaka gerektiren tehlikeli maddeler taşıyan araçlar için geçerlidir. Kaynak: Ohio BMV CDL Classes sayfası (bmv.ohio.gov/dl-cdl-classes.aspx)."},"23":{"q":"Yalnızca INTRASTATE (Ohio içi) ticari sürüş ile sınırlı bir Ohio CDL'sinin verilebilmesi için minimum yaş nedir?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"Ohio, yalnızca eyalet içi geçerli bir CDL'yi 18 yaşından itibaren verir; 21 yaşından küçük sürücüler Ohio içindeki ticaretle sınırlıdır. Kaynak: Ohio BMV CDL uygunluğu (bmv.ohio.gov) ve ORC 4506.10."},"24":{"q":"Bir Ohio CDL'si ile INTERSTATE ticarette ticari motorlu araç kullanmak için gereken minimum yaş nedir?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Interstate ticari sürüş, sürücünün en az 21 yaşında olmasını gerektirir. 18-20 yaş arası Ohio sürücüleri yalnızca eyalet içi geçerli bir CDL'ye sahiptir. Kaynak: Ohio BMV CDL uygunluğu ve 49 CFR 391.11."},"25":{"q":"Bir Ohio CDL'sinde, aracın plaka (placard) gerektiren miktarlarda tehlikeli madde taşıması için hangi onay harfi gereklidir?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement X"],"explanation":"H (HazMat) onayı, plaka gerektiren tehlikeli maddelerin taşınmasına yetki verir. Kaynak: Ohio BMV CDL Classes/onaylar sayfası ve 49 CFR 383.93."},"26":{"q":"Kalıcı olarak monte edilmiş bir tankta dökme halinde sıvı veya gaz taşıyan bir Ohio sürücüsü hangi onaya sahip olmalıdır?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement S"],"explanation":"N (Tank Vehicle) onayı, dökme halinde sıvı veya gaz halindeki maddeleri taşıyan bir tank aracını kullanmak için gereklidir. Kaynak: Ohio BMV onay bilgileri ve 49 CFR 383.93."},"27":{"q":"İkili veya üçlü römork çekmek için hangi Ohio CDL onayı gereklidir?","options":["Endorsement P","Endorsement S","Endorsement T","Endorsement D"],"explanation":"T onayı, ikili/üçlü römork kombinasyonlarının kullanımına yetki verir ve ikili/üçlü bilgi testini geçerek alınır. Kaynak: Ohio BMV onay bilgileri ve 49 CFR 383.93."},"28":{"q":"Bir Ohio CDL sahibinin, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir ticari aracı (okul otobüsü dışında) kullanması için hangi onaya ihtiyacı vardır?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı kullanmak için gereklidir. Kaynak: Ohio BMV onay bilgileri ve 49 CFR 383.93."},"29":{"q":"Ohio'da, bir sürücüye School Bus (S) onayı verilmeden önce hangi başka onayı da alması gerekir?","options":["H (HazMat) onayı","N (Tanker) onayı","P (Passenger) onayı","T (Doubles/Triples) onayı"],"explanation":"Federal ve Ohio kuralları, bir okul otobüsünün yolcu taşıması nedeniyle S (School Bus) onayının P (Passenger) onayı ile birlikte alınmasını gerektirir. Kaynak: Ohio BMV onay bilgileri ve 49 CFR 383.93."},"30":{"q":"HazMat (H) onayı verilmeden önce, bir Ohio CDL başvuru sahibinin yazılı HazMat bilgi testinin ötesinde hangi ek taramayı geçmesi gerekir?","options":["Parmak izi alımı dahil bir TSA güvenlik tehdidi değerlendirmesi","Tank aracında ikinci bir yol becerileri testi","BMV tarafından yapılan bir göz muayenesi","Bir savunmacı sürüş sınıf kursu"],"explanation":"HazMat onayı, bilgi testine ek olarak parmak izi tabanlı bir geçmiş kontrolü içeren bir Transportation Security Administration (TSA) güvenlik tehdidi değerlendirmesi gerektirir. Kaynak: Ohio BMV HazMat bilgileri ve 49 CFR 1572."},"31":{"q":"Bir sürücü, CDL becerileri (yol) testine girmesine izin verilmeden önce bir Ohio Commercial Learner's Permit (CLP) almalı ve minimum bir süre boyunca elinde tutmalıdır. Bu minimum tutma süresi nedir?","options":["7 days","14 days","30 days","60 days"],"explanation":"Ohio tarafından benimsenen federal kural, başvuru sahibinin CDL becerileri testine girebilmesi için CLP'nin en az 14 days tutulmasını gerektirir. Kaynak: Ohio BMV CDL süreci ve 49 CFR 383.25."},"32":{"q":"Bir Ohio Commercial Learner's Permit (CLP) ile ticari araç kullanırken, izin sahibine ne eşlik etmelidir?","options":["25 yaş veya üzeri herhangi bir lisanslı sürücü","Doğru sınıf/onaylara sahip ve yanında oturan bir CDL sahibi","Yalnızca bir BMV görevlisi","Gün ışığı saatlerinde sürüş yapılıyorsa hiç kimse"],"explanation":"Bir CLP sahibi, yalnızca uygun sınıf ve onaylara sahip geçerli bir CDL'ye sahip bir kişinin CLP sahibinin yanında oturması durumunda bir CMV kullanabilir. Kaynak: Ohio BMV CLP kuralları ve 49 CFR 383.25."},"33":{"q":"7 Şubat 2022'den bu yana, Ohio'da ilk kez Class A CDL alan bir kişi, ne olan bir kuruluş tarafından sağlanan Entry-Level Driver Training (ELDT) eğitimini tamamlamalıdır?","options":["FMCSA Training Provider Registry'de listelenen","Ohio Department of Education tarafından akredite edilen","Yalnızca yerel deputy registrar tarafından onaylanan","Ohio State Highway Patrol tarafından sertifikalandırılan"],"explanation":"ELDT, FMCSA Training Provider Registry'de (TPR) listelenen bir sağlayıcı tarafından verilmelidir ve sertifikasyon, becerileri/bilgi testinden önce kayıtta yer almalıdır. Kaynak: FMCSA ELDT kuralı (49 CFR 380 subpart F) ve tpr.fmcsa.dot.gov."},"34":{"q":"Aşağıdaki ilk kez yapılan işlemlerden hangisi federal Entry-Level Driver Training (ELDT) gerekliliğini TETİKLEMEZ?","options":["İlk kez bir Class A CDL almak","İlk kez Passenger (P) onayını almak","İlk kez Tanker (N) onayını almak","İlk kez HazMat (H) onayını almak"],"explanation":"ELDT, ilk kez alınan Class A/B CDL'ler, B'den A'ya yükseltmeler ve ilk kez alınan P, S ve H onayları için geçerlidir. N (Tanker) ve T (Doubles/Triples) onayları ELDT kapsamında değildir. Kaynak: FMCSA ELDT uygulanabilirliği (tpr.fmcsa.dot.gov/Drivers/Applicability)."},"35":{"q":"ELDT gerekliliği, Commercial Learner's Permit'lerini hangi tarihten itibaren alan kişiler için geçerlidir?","options":["February 7, 2020","February 7, 2022","January 30, 2021","December 31, 2023"],"explanation":"Entry-Level Driver Training gereklilikleri, February 7, 2022 tarihinde veya sonrasında CLP alan sürücüler için geçerlidir. Kaynak: FMCSA ELDT kuralı ve tpr.fmcsa.dot.gov."},"36":{"q":"Ohio CDL öz-sertifikasyon formunda, hangi kategori eyalet sınırları boyunca araç kullanan ve federal DOT fiziksel muayenesi (medical card) gerekliliklerini karşılaması gereken bir sürücüyü tanımlar?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Non-Excepted Interstate sürücüler interstate ticarette çalışır ve bir Medical Examiner's Certificate sunarak federal tıbbi (Part 391) standartlarını karşılamalıdır. Kaynak: Ohio BMV formu BMV 2159 (CDL Self-Certification) ve 49 CFR 383.71."},"37":{"q":"İlk kez Ohio CDL başvurusunda bulunan birinin uygunluğunu kanıtlamak için BMV'ye hangi belgeleri sunması gerekir?","options":["Kimlik/yasal mevcudiyet kanıtı, tam Social Security numarası ve Ohio ikamet kanıtı","Yalnızca güncel bir Ohio sürücü belgesi ve bir kredi kartı","Bir pasaport ve iki fatura, ancak Social Security numarası olmadan","Yalnızca bir araç ruhsatı ve sigorta kanıtı"],"explanation":"Ohio, kimlik ve yasal mevcudiyet belgesi (örneğin doğum belgesi, pasaport veya kalıcı oturma kartı), Social Security numarası ve Ohio ikamet kanıtı gerektirir. Kaynak: Ohio BMV CDL belge gereklilikleri (bmv.ohio.gov)."},"38":{"q":"19 yaşındaki bir Ohio sürücüsü, plaka (placard) gerektiren tehlikeli maddeler taşımak için bir CDL istiyor. Bu sürücü neden HazMat (H) onayını ALAMAZ?","options":["HazMat taşımacılığı en az 21 yaşında olmayı gerektirir","HazMat onayları yalnızca Class C sürücülerine verilir","Ohio HazMat onayı sunmaz","Önce bir tanker (N) onayı alınmalıdır"],"explanation":"Plaka gerektiren tehlikeli maddelerin taşınması interstate kapasitelidir ve sürücünün en az 21 yaşında olmasını gerektirir; Ohio'nun 18-20 yaş arası eyalet içi CDL sahipleri H onayına sahip olamaz. Kaynak: Ohio BMV CDL uygunluğu ve 49 CFR 383.93/391.11."},"39":{"q":"Ohio'da, bir sürücünün ticari motorlu araç (CMV) kullanırken, CDL amaçları açısından yasal olarak engelli kabul edilmeden önce sahip olabileceği maksimum kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"Ohio federal CMV standardını izler: 0.04 percent veya daha fazla BAC ile ticari motorlu araç kullanmak büyük bir suçtur. Bu eşik, ticari olmayan sürücüler için olan 0.08 sınırının yarısıdır. Kaynak: Ohio CDL Manual / Ohio BMV CDL Disqualifications; ORC 4506.15; 49 CFR 383.51."},"40":{"q":"Bir Ohio CDL'si alarak ve kullanarak, bir sürücünün alkol veya uyuşturucu içeriğini belirlemek için nefes, kan veya idrarın kimyasal testine onay verdiği kabul edilir. Bu yasal ilkeye ne ad verilir?","options":["Implied consent (zımni rıza)","Probable cause (muhtemel sebep)","Due process consent (adil yargılanma rızası)","Conditional licensing (koşullu lisanslama)"],"explanation":"Ohio'nun implied-consent (zımni rıza) yasası, Ohio yollarında araç kullanmanın, bir alkol/uyuşturucu suçundan yasal olarak tutuklandığında kimyasal teste rıza gösterdiği anlamına geldiğini ifade eder. Reddetmenin kendi idari cezaları vardır. Kaynak: ORC 4511.191; Ohio CDL Manual."},"41":{"q":"Ohio'da, plaka (placard) gerektiren tehlikeli madde taşımayan bir sürücünün İLK büyük suçu (örneğin bir CMV'de 0.04+ BAC veya kimyasal testi reddetme) için minimum CDL diskalifiye süresi nedir?","options":["1 year","60 days","6 months","3 years"],"explanation":"İlk büyük suç (0.04+ BAC, OVI, test reddi, olay yerini terk etme, bir suçta CMV kullanma vb.), Ohio'da 1 year CDL diskalifiyesi ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"42":{"q":"Bir Ohio sürücüsü, tehlikeli maddeler için plaka (placard) takılı bir CMV kullanırken ilk büyük suçu (örneğin bir 0.04+ BAC) işlerse, diskalifiye süresi şuna çıkarılır:","options":["3 years","1 year","5 years","Lifetime (ömür boyu)"],"explanation":"İlk büyük suç, tehlikeli maddeler için plaka takılı bir araçta meydana geldiğinde, standart 1 year diskalifiye 3 years'a çıkarılır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"43":{"q":"Ohio'da İKİNCİ bir büyük suç (örneğin ikinci bir OVI veya bir CMV'de ikinci bir 0.04+ BAC) için CDL diskalifiye süresi nedir?","options":["Lifetime (ömür boyu)","10 years","3 years","5 years"],"explanation":"Herhangi bir büyük suçtan ikinci bir mahkumiyet, Ohio'da ömür boyu CDL diskalifiyesi ile sonuçlanır. Bazı ömür boyu diskalifiyeler, geri verme koşulları karşılandıktan sonra 10 years'a indirilebilir. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"44":{"q":"OVI nedeniyle yasal olarak tutuklanan bir Ohio sürücüsü kimyasal nefes testine girmeyi reddeder. CDL amaçları açısından, testi reddetmek en az şu kadar diskalifiye ile sonuçlanır:","options":["1 year","90 days","60 days","30 days"],"explanation":"Bir test reddi, CDL amaçları açısından büyük bir suç olarak değerlendirilir ve herhangi bir idari lisans askıya alınmasına ek olarak 1 year diskalifiye (plaka gerektiren tehlikeli madde taşınıyorsa 3 years) getirir. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"45":{"q":"Ohio'nun implied-consent (zımni rıza) yasasına göre, kimyasal testi reddeden bir CDL sahibi ayrıca idari bir lisans askıya alınmasıyla da karşı karşıya kalır. İLK reddetme için bu idari askıya alma genellikle şu kadardır:","options":["1 year","90 days","6 months","2 years"],"explanation":"Ohio'nun implied-consent (zımni rıza) yasası, ilk kimyasal test reddi için 1 year idari lisans askıya alma getirir; 10 yıl içindeki tekrarlanan reddetmeler için daha uzun süreler uygulanır. Bu, CDL diskalifiyesinden ayrıdır. Kaynak: ORC 4511.191."},"46":{"q":"Ohio'da, 3 yıllık bir süre içinde ayrı olaylarda kaç CIDDI trafik ihlali 60 günlük bir CDL diskalifiyesini tetikler?","options":["2","3","4","5"],"explanation":"3 yıl içinde (bir CMV'de) 2 ciddi trafik ihlalinden mahkumiyet, 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"47":{"q":"Bir Ohio CDL sahibi, 3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlalinden mahkum edilir. CDL diskalifiye süresi nedir?","options":["120 days","60 days","90 days","1 year"],"explanation":"3 yıl içinde 3 veya daha fazla ciddi trafik ihlalinden mahkumiyet, 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"48":{"q":"Bir CDL sürücüsünün, ihlalin Ohio'da CIDDI bir trafik ihlali sayılması için belirtilen hız sınırının ne kadar üzerinde olduğu için ceza alması gerekir?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 5 mph veya daha fazla üzerinde"],"explanation":"Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak, CDL sahipleri için ciddi bir trafik ihlali olarak sınıflandırılır. Kaynak: Ohio CDL Manual; ORC 4506.01/4506.16; 49 CFR 383.51."},"49":{"q":"Aşağıdakilerden hangisi bir Ohio CDL sahibi için CIDDI bir trafik ihlali olarak sınıflandırılır?","options":["Çok yakından takip etme (arabaya yapışma)","Park yasağı bölgesinde park etme","Yanmayan bir plaka lambası","İlk aşırı yük cezası"],"explanation":"Ciddi trafik ihlalleri arasında çok yakından takip etme, dikkatsiz/düzensiz şerit değiştirme, 15+ mph hız aşımı, sürüş sırasında mesajlaşma ve uygun sınıf/onay olmadan bir CMV kullanma yer alır. Ekipman ve park suçları ciddi ihlaller değildir. Kaynak: Ohio CDL Manual; 49 CFR 383.51."},"50":{"q":"Ohio'da, bir CMV kullanırken elde tutulan bir cep telefonu kullanmak veya mesajlaşmak yasaktır. CDL amaçları açısından, böyle bir mahkumiyet şu şekilde sayılır:","options":["Ciddi trafik ihlali","Büyük suç","Hizmet dışı (out-of-service) ihlali","Kaydedilemeyen ihlal"],"explanation":"Bir CMV kullanırken mesajlaşmak veya elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük diskalifiye, üç tanesi 120 gün getirir. Kaynak: Ohio CDL Manual; 49 CFR 383.51 ve 392.80/392.82."},"51":{"q":"Bir ticari araç kullanırken mesajlaşan bir CMV sürücüsü için (Ohio'da uygulanan) maksimum federal sürücü hukuki cezası nedir?","options":["Up to $2,750","Up to $500","Up to $1,000","Up to $11,000"],"explanation":"Araç kullanırken mesajlaşan bir CMV sürücüsü, en fazla $2,750'lik bir federal hukuki cezayla karşı karşıya kalır; buna izin veren motorlu taşıyıcılar en fazla $11,000 ile cezalandırılabilir. Bu kurallar Ohio'da geçerlidir. Kaynak: 49 CFR 392.80; FMCSA No-Texting Rule."},"52":{"q":"Bir Ohio CDL sahibi İLK demiryolu-karayolu hemzemin geçit ihlalini (örneğin gerekli yerde durmama) işler. Diskalifiye süresi nedir?","options":["60 days","30 days","120 days","1 year"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, 60 günlük bir CDL diskalifiyesi ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"53":{"q":"Ohio'da, 3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali için CDL diskalifiye süresi nedir?","options":["120 days","60 days","180 days","1 year"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"54":{"q":"Bir Ohio CDL sahibi, 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Diskalifiye süresi şudur:","options":["1 year","120 days","180 days","2 years"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu hemzemin geçit ihlali, 1 year (365 günlük) bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"55":{"q":"Ohio'da, bir sürücünün hizmet dışı (out-of-service, OOS) bir emri ihlal etmekten İLK mahkumiyeti için CDL diskalifiye süresi nedir?","options":["180 days","60 days","1 year","90 days"],"explanation":"Hizmet dışı bir emri ihlal etmekten ilk mahkumiyet, en az 180 günlük bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"56":{"q":"Ohio'da, 10 yıllık bir süre içinde ayrı olaylarda İKİNCİ bir hizmet dışı (out-of-service, OOS) emir ihlali için CDL diskalifiye süresi nedir?","options":["2 years","1 year","180 days","3 years"],"explanation":"10 yıllık bir süre içinde ikinci bir hizmet dışı emir ihlali, 2 years'lık bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"57":{"q":"Bir Ohio CDL sahibi, 10 yıllık bir süre içinde ÜÇÜNCÜ bir hizmet dışı emir ihlalinden mahkum edilir. Diskalifiye süresi şudur:","options":["3 years","2 years","180 days","5 years"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı emir ihlali, 3 years'lık bir diskalifiye ile sonuçlanır. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"58":{"q":"Bir Ohio sürücüsü, plaka (placard) gerektiren tehlikeli maddeler taşırken veya 16 ya da daha fazla yolcu taşımak için tasarlanmış bir araç kullanırken bir hizmet dışı emri ihlal eder. Bu İLK suç için diskalifiye nedir?","options":["180 days","60 days","1 year","2 years"],"explanation":"Plaka gerektiren tehlikeli madde taşırken veya 16+ yolcu taşırken ilk hizmet dışı emir ihlali, 180 günlük bir diskalifiye getirir; 10 yıl içinde benzer bir sonraki ihlal 3 years getirir. Kaynak: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51."},"59":{"q":"Ohio'nun \"Yol Ver\" (Move Over) yasası uyarınca, kendi yönünüzde iki veya daha fazla şeridi olan bir karayolunda, yanıp sönen ışıklar yakan duran bir çekici aracına, karayolu bakım aracına veya polis aracına yaklaştığınızda ne yapmanız gerekir?","options":["Güvenli olduğunda, duran aracın bitişiğindeki şeritten başka bir şeride geçin","Araç hareket edene kadar tamamen durun","Geçiş sırasında kornanızı sürekli olarak çalın","Hızınızı koruyun ancak dörtlü flaşörlerinizi açın"],"explanation":"Ohio'nun \"Yol Ver\" yasası (ORC 4511.213), yanıp sönen ışıklar yakan duran bir kamu güvenliği, acil durum, yol servisi veya bakım aracına yaklaşan bir sürücünün, aynı yönde en az iki şerit bulunduğunda ve güvenli olduğunda, o aracın bitişiğinde olmayan bir şeride geçmesini gerektirir. Kaynak: Ohio Revised Code 4511.213."},"60":{"q":"Ohio'nun \"Yol Ver\" yasası uyarınca, ışıkları yanıp sönen duran bir acil durum aracının yanından geçerken (örneğin iki şeritli bir yolda) güvenli bir şekilde şerit değiştiremiyorsanız, yasa neyi gerektirir?","options":["Gereken dikkati göstererek ilerleyin, hızınızı azaltın ve koşullara uygun güvenli bir hızı koruyun","Tamamen durun ve bir görevlinin sizi geçirmesi için işaret etmesini bekleyin","Yavaşlamadan, belirtilen hız sınırında devam edin","Banketin üzerine çekip durun"],"explanation":"Şerit değiştirmek imkansız veya güvenli olmadığında, ORC 4511.213 sürücünün gereken dikkati göstererek ilerlemesini, hızını azaltmasını ve yol, hava ve trafik koşullarına uygun güvenli bir hızı korumasını gerektirir. Kaynak: Ohio Revised Code 4511.213."},"61":{"q":"Ohio'da, plakart taşıyan tehlikeli madde taşıyan bir sürücü veya bir otobüs kullanan bir sürücü, bir demiryolu hemzemin geçidinden önce, en yakın raya hangi mesafe içinde durmalıdır?","options":["15 feet'ten az ve 50 feet'ten fazla olmayan mesafede","5 feet'ten az ve 25 feet'ten fazla olmayan mesafede","25 feet'ten az ve 75 feet'ten fazla olmayan mesafede","10 feet'ten az ve 100 feet'ten fazla olmayan mesafede"],"explanation":"Bir otobüs sürücüsü veya tehlikeli madde plakartları gösteren bir aracın sürücüsü, bir demiryolu geçidinde en yakın raydan 50 feet içinde ancak 15 feet'ten az olmayan mesafede durmalı, ardından ilerlemeden önce bakıp dinlemelidir. Kaynak: Ohio CDL Manual / 49 CFR 392.10; zorunlu durma ORC 4511.63 tarafından gerektirilir."},"62":{"q":"Aşağıdaki araçlardan hangisi Ohio'da muafiyet kapsamında olmayan her demiryolu hemzemin geçidinde DURMAK ZORUNDADIR?","options":["Federal tehlikeli madde kurallarına göre plakart gerektiren malzeme taşıyan bir araç","Bir hizmet römorku çeken herhangi bir kamyonet","Brüt ağırlığı 10,000 pound'un üzerinde olan herhangi bir düz kamyon","Çift arka tekerlekli herhangi bir araç"],"explanation":"ORC 4511.63, herhangi bir otobüsün, herhangi bir okul aracının veya 49 CFR Parts 100-185 uyarınca plakart gerektiren malzeme taşıyan herhangi bir aracın sürücüsünün, bir demiryolu rayını geçmeden önce durmasını gerektirir. Sıradan kamyonlar ve römorklar zorunlu durmaya tabi değildir. Kaynak: Ohio Revised Code 4511.63."},"63":{"q":"İki şeritli bir Ohio yolunda, kırmızı ışıkları yanıp sönerek çocukları indiren veya bindiren duran bir okul otobüsüyle karşılaştığınızda, otobüsten en az ne kadar uzakta durmalısınız?","options":["Otobüsün önünden veya arkasından en az 10 feet uzakta","Otobüsün önünden veya arkasından en az 20 feet uzakta","Otobüsün önünden veya arkasından en az 30 feet uzakta","Otobüsün önünden veya arkasından en az 50 feet uzakta"],"explanation":"ORC 4511.75, duran bir okul otobüsüyle karşılaşan veya onu geçen bir sürücünün, otobüsün önünden veya arkasından en az 10 feet uzakta durmasını ve otobüs hareket edene veya sürücü ilerleme işareti verene kadar ilerlememesini gerektirir. Kaynak: Ohio Revised Code 4511.75."},"64":{"q":"Ohio'da, karşı yönden gelen trafiğin, karşı tarafta duran bir okul otobüsü için durmadan devam edebilmesi için bir karayolunun kaç trafik şeridine bölünmüş olması gerekir?","options":["Dört veya daha fazla şerit","İki veya daha fazla şerit","Üç veya daha fazla şerit","Altı veya daha fazla şerit"],"explanation":"Ohio'nun okul otobüsü yasası, dört veya daha fazla şeritli bir karayolunda, bir sürücünün karşı tarafta durmuş bir okul otobüsü için durmasının gerekmediğini öngörür; yalnızca otobüsle aynı yönde seyahat eden trafik durmalıdır. Kaynak: Ohio Revised Code 4511.75."},"65":{"q":"İki şeritli bir yolda bir Ohio okul otobüsü için durduktan sonra, ne zaman ilerleyebilirsiniz?","options":["Otobüs hareket etmeye devam ettiğinde veya otobüs sürücüsü size ilerleme işareti verdiğinde","Çocuklar yoldan indikten hemen sonra","Zorunlu olarak 30 saniye bekledikten sonra","Otobüsün sarı ışıkları yanıp sönmeye başladığında"],"explanation":"ORC 4511.75, durmuş bir sürücünün, okul otobüsü hareket etmeye devam edene veya okul otobüsü sürücüsü tarafından ilerleme işareti verilene kadar ilerlememesi gerektiğini belirtir. Kaynak: Ohio Revised Code 4511.75."},"66":{"q":"Ohio'da kırsal bir eyaletler arası karayolunda bir çekici-römork için maksimum hız sınırı nedir (daha düşük bir sınır belirtilmedikçe)?","options":["70 mph, binek otomobillerle aynı","55 mph, binek otomobillerden daha düşük","60 mph, binek otomobillerden daha düşük","65 mph, binek otomobillerden daha düşük"],"explanation":"Ohio, kamyonlar için ayrı, daha düşük bir hız sınırı belirlemez. ORC 4511.21 uyarınca, kırsal eyaletler arası yollarda maksimum hız 70 mph'dir ve aksi belirtilmedikçe ticari kamyonlar otomobillerle aynı sınırda seyahat edebilir. Kaynak: Ohio Revised Code 4511.21; ODOT hız bölgesi kuralları."},"67":{"q":"Ohio Turnpike ana hattında ticari kamyonlar için hız sınırı nedir?","options":["70 mph, binek araçlarla aynı","Kamyonlar için 65 mph, otomobiller ise 70 gidebilirken","Tüm kamyonlar için 55 mph","Kamyonlar için 60 mph, otomobiller ise 70 gidebilirken"],"explanation":"Ohio Turnpike, ticari kamyonlar dahil tüm araçlar için geçerli olan 70 mph'lik bir ana hat sınırı belirler; Ohio, ayrı bir daha düşük kamyon hızı uygulamaz. Kaynak: Ohio Turnpike and Infrastructure Commission; ORC 4511.21."},"68":{"q":"Çok şeritli bir Ohio yolunda, trafiğin geçerli hızından daha yavaş ilerleyen bir kamyon sürücüsünün genellikle ne yapması gerekir?","options":["Geçiş yaparken veya sola dönerken hariç, trafiğe ayrılmış sağ şeritte sürmek","Birleşen araçlardan kaçınmak için orta şeritte kalmak","Daha hızlı trafiğin sağdan birleşebilmesi için sol şeridi kullanmak","Dörtlü flaşörler açık olduğu sürece herhangi bir şeridi kullanmak"],"explanation":"ORC 4511.25, geçerli yasal hızdan daha yavaş ilerleyen bir aracın; geçiş yapma, sola dönme durumları veya rotanın başka bir şerit gerektirmesi hariç, güvenli geçişe izin verecek kadar sağda olacak şekilde trafiğe ayrılmış sağ şeritte sürülmesini gerektirir. Kaynak: Ohio Revised Code 4511.25."},"69":{"q":"Bir kamyon arızalandığında ve bir Ohio yolunda durduğunda, üç uyarı cihazı (işaret fişekleri, reflektörler veya fenerler) nasıl yerleştirilmelidir?","options":["Biri yaklaşık 100 feet önde, biri yaklaşık 100 feet arkada ve biri trafik tarafında","Üçü de aracın hemen arkasına bir sıra halinde yerleştirilir","Biri her iki yanda ve biri kabinin tavanında","Biri 10 feet önde, biri 10 feet arkada ve biri bankette"],"explanation":"ORC 4513.28, uyarı cihazlarının aracın yaklaşık 100 feet önüne, yaklaşık 100 feet arkasına ve arızalı aracın trafik tarafına bir adet olacak şekilde yerleştirilmesini gerektirir. Kaynak: Ohio Revised Code 4513.28."},"70":{"q":"Ohio'nun \"Yol Ver\" yasasının (ORC 4511.213) ilk kez ihlali nasıl sınıflandırılır?","options":["Para cezası ikiye katlanan bir hafif kabahat (yaklaşık 300 dolara kadar)","Beşinci derece bir suç (felony)","Puansız, hareketsiz bir sivil ihlal","Zorunlu hapis cezası olan birinci derece bir kabahat"],"explanation":"ORC 4511.213 kapsamındaki ilk ihlal bir hafif kabahattir, ancak mahkeme olağan miktarın iki katı bir para cezası uygulamak zorundadır, bu da onu yaklaşık 300 dolara kadar çıkarır. Bir yıl içinde tekrarlanan ihlaller dördüncü ve üçüncü derece kabahatlere yükselir. Kaynak: Ohio Revised Code 4511.213."},"71":{"q":"Ohio'da, bir aşırı boyut izni gerekmeden önce bir ticari aracın veya yükün maksimum yasal genişliği nedir?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"Ohio'nun yasal maksimum araç genişliği 8 feet 6 inches'tir (102 inches); bundan daha geniş olan herhangi bir şey ODOT'tan özel bir taşıma izni gerektirir. Kaynak: ORC 5577.05; Ohio DOT Özel Taşıma İzni kuralları."},"72":{"q":"Ohio'da, bir izin gerekmeden önce bir araç ve yükün maksimum yasal yüksekliği nedir?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"explanation":"Ohio'nun yasal maksimum yüksekliği 13 feet 6 inches'tir; bundan daha yüksek yükler ODOT'tan bir aşırı boyut izni gerektirir. Kaynak: ORC 5577.05; Ohio DOT Özel Taşıma İzni Operasyon Kılavuzu."},"73":{"q":"Aşırı boyutlu veya aşırı ağırlıklı bir aracın Ohio eyalet yollarında çalışmasına izin veren özel izni kim verir?","options":["Ohio Ulaştırma Müdürü (ODOT)","Ohio Motorlu Araçlar Bürosu (BMV)","Rota üzerindeki her ilçenin ilçe şerifi","Ohio Eyalet Karayolu Devriyesi karakol komutanı"],"explanation":"Yasal boyut veya ağırlık sınırlarını aşan araçlar, bir eyalet yolunda yalnızca Ohio Ulaştırma Müdürü tarafından verilen özel bir yazılı izinle çalışabilir. Kaynak: ORC 4513.34 ve 5577.04; ODOT Özel Taşıma İzinleri."},"74":{"q":"Ohio'da, federal sınırla tutarlı olarak, bir aşırı ağırlık izni gerekmeden izin verilen maksimum brüt araç ağırlığı nedir?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"Ohio, 80,000 pound'luk federal maksimum brüt ağırlığı izler (Federal Köprü Formülüne tabidir); bunun aşılması bir ODOT aşırı ağırlık izni gerektirir. Kaynak: ORC 5577.04; Federal Köprü Formülü."},"75":{"q":"Plakart taşıyan bir tehlikeli madde aracı Ohio'da bir demiryolu geçidine yaklaştığında, rayları geçerken hangi eylem doğrudur?","options":["Aracın herhangi bir kısmı raylardayken vites değiştirmeyin","Daha iyi kontrol için geçerken daha düşük bir vitese geçin","İkinci bir treni kontrol etmek için ortada durun","Tamamen geçene kadar motoru kapatın"],"explanation":"Durduktan, bakıp dinledikten sonra, sürücü değiştirmeye gerek duymayacağı bir viteste geçmeli ve aracın herhangi bir kısmı raylardayken vites değiştirmemelidir. Kaynak: Ohio CDL Manual / 49 CFR 392.10; ORC 4511.63."},"76":{"q":"Ohio'da dört şeritli bölünmüş bir karayolunda, çocukları indirmek için duran bir okul otobüsü, yolu geçme riskini azaltmak için mümkün olduğunda ne yapmalıdır?","options":["Yolcuları karayolunun konut tarafında almalı ve indirmeli","Çocukların geçidi kullanabilmesi için orta refüjde durmalı","Tüm yolcuları sol bankette indirmeli","Tüm çocukların sürücü tarafından karşıya geçirilmesini zorunlu kılmalı"],"explanation":"Bölünmüş karayollarında veya dört ya da daha fazla şeritli yollarda, okul otobüsleri çocukları konut tarafında alır ve indirir, böylece çocuklar yolu geçmek zorunda kalmaz; karşı yönden gelen trafiğin durması gerekmemesinin nedeni budur. Kaynak: Ohio Revised Code 4511.75; Ohio okul otobüsü düzenlemeleri."},"77":{"q":"Ohio yasalarına göre, belirlenmiş tehlikeli bir demiryolu hemzemin geçidine bir DUR işareti yerleştirildiğinde, bir sürücü en yakın raya hangi mesafe içinde durmalıdır?","options":["15 feet'ten az olmamak ancak 50 feet içinde","5 feet'ten az olmamak ancak 20 feet içinde","30 feet'ten az olmamak ancak 60 feet içinde","En yakın raydan tam olarak 25 feet"],"explanation":"ORC 4511.61, bir dur işareti dikilmiş bir demiryolu geçidinde bir sürücünün en yakın raydan elli feet içinde ancak on beş feet'ten az olmamak üzere durmasını ve güvenli olana kadar ilerlememesini gerektirir. Kaynak: Ohio Revised Code 4511.61."},"78":{"q":"Ohio'nun otomobillerden ayrı kamyona özgü hız sınırları uygulayıp uygulamadığını en iyi hangi ifade tanımlar?","options":["Ohio, kamyonlar ve otomobiller için aynı maksimum hız sınırlarını belirler; kamyonlara ayrı, daha düşük bir eyalet çapında sınır atanmaz","Belirtilen sınıra bakılmaksızın kamyonlar eyalet çapında her zaman 55 mph ile sınırlıdır","Kamyonlar tüm otoyollarda belirtilen otomobil sınırının 10 mph altında seyahat etmelidir","Kamyonlar yalnızca Ohio Turnpike'ı kullanabilir ve eyaletler arası yollardan yasaklanmıştır"],"explanation":"Ohio, ORC 4511.21 uyarınca ticari kamyonlara ve binek otomobillere aynı belirtilen maksimum hız sınırlarını uygular; eyalet çapında ayrı, daha düşük bir kamyon hız sınırı yoktur, ancak sürücüler yine de koşullara uygun güvenli bir hızda sürmelidir. Kaynak: Ohio Revised Code 4511.21; ODOT."},"79":{"q":"Ohio'da Ticari Sürücü Belgelerini (CDL'ler) hangi eyalet kurumu verir?","options":["Ohio Motorlu Araçlar Bürosu (BMV)","Ohio Ulaştırma Departmanı (ODOT)","Ohio Eyalet Karayolu Devriyesi","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)"],"explanation":"Ohio'da, Ohio Kamu Güvenliği Departmanı'nın bir bölümü olan Motorlu Araçlar Bürosu (BMV), CDL'ler dahil tüm sürücü belgelerini verir. ODOT, ruhsatlandırmayı değil yolları ve aşırı boyut/aşırı ağırlık izinlerini yönetir ve FMCSA, standartları belirleyen federal kurumdur. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."},"80":{"q":"Bir Ohio CDL başvuru sahibi herhangi bir ticari bilgi testine girmeden önce, bu test nerede tamamlanmalıdır?","options":["Bir Ohio BMV sürücü sınav istasyonunda şahsen","Herhangi bir ev bilgisayarından çevrimiçi olarak","Eve götürülen bir cevap kağıdı kullanılarak posta yoluyla","FMCSA'ya kayıtlı bir ELDT eğitim sağlayıcısında"],"explanation":"Ohio, CDL bilgi testlerinin (genel bilgi, onaylar ve hava freni kısıtlaması kaldırma) bir BMV sürücü sınav istasyonunda şahsen yapılmasını gerektirir; bunlar çevrimiçi olarak yapılamaz. ELDT sağlayıcıları eyalet bilgi testini değil, eğitimi sunar. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."},"81":{"q":"Bir Ohio Ticari Öğrenci İzni (CLP) verildikten sonra ne kadar süre geçerlidir?","options":["12 ay","6 ay","30 gün","24 ay"],"explanation":"Ohio, bir CLP'nin 12 ay geçerli olduğunu belirtir. (Federal kural uyarınca, genel bilgi testini tekrar almadan bir kez yenilenebilir.) Çeldiriciler yaygın ancak yanlış izin sürelerini yansıtır. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."},"82":{"q":"Bir Ohio CLP'si aldıktan sonra, bir başvuru sahibi CDL beceri testine girmeye hak kazanmadan önce onu ne kadar süre elinde tutmalıdır?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"Ohio'da uygulanan federal düzenleme, bir CLP sahibinin CDL beceri (yol) testine girebilmesi için CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: Ohio BMV CDL süreci / 49 CFR 383.25 (FMCSA)."},"83":{"q":"Ohio CDL beceri testi üç bölüm halinde uygulanır. Hangi grup bu üç bölümü doğru bir şekilde listeler?","options":["Yola çıkış öncesi muayene, temel kontrol (manevra kabiliyeti) ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Yola çıkış öncesi muayene, hava freni kontrolü ve tehlikeli madde elleçleme","Temel kontrol, gece sürüşü ve yazılı bir onay sınavı"],"explanation":"Ohio'nun CDL beceri testi üç bölümden oluşur: yola çıkış öncesi muayene, temel kontrol (manevra kabiliyeti) testi ve yolda sürüş testi. Görme taraması ve yazılı sınavlar beceri testinden ayrıdır. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."},"84":{"q":"Bir Ohio başvuru sahibinin CDL beceri testini planlayabilmesi veya teşebbüs edebilmesi için ÖNCESİNDE elektronik olarak neyi sunması gerekir?","options":["Başlangıç Seviyesi Sürücü Eğitimini (ELDT) tamamladığına dair kanıt veya bir muafiyet kanıtı","İki yıllık önceki sürüş deneyimi kanıtı","İmzalı bir işveren sponsorluk mektubu","Bir savunmacı sürüş kursunda geçer not"],"explanation":"Ohio, beceri testinin planlanabilmesi veya teşebbüs edilebilmesi için, başvurulan sınıf/onayla eşleşen FMCSA Başlangıç Seviyesi Sürücü Eğitimini (ELDT) tamamladığına dair elektronik kanıt veya bir muafiyet kanıtı gerektirir. Kaynak: Ohio BMV CDL sayfası / FMCSA ELDT kuralı (49 CFR Part 380)."},"85":{"q":"Ohio'nun öz-sertifikasyon süreci, bir CDL/CLP başvuru sahibinin kaç sürüş türü kategorisi arasından seçim yapmasını gerektirir?","options":["Dört","İki","Üç","Beş"],"explanation":"Ohio sürücüleri dört kategoriden birine öz-sertifikasyon yapmalıdır: Muaf Olmayan Eyaletler Arası, Muaf Eyaletler Arası, Muaf Olmayan Eyalet İçi ve Muaf Eyalet İçi. Kaynak: Ohio BMV CDL Öz-Sertifikasyon (form BMV 2159)."},"86":{"q":"Bir Ohio sürücüsü iş için eyalet sınırlarını geçer ve 49 CFR Part 391 kapsamındaki federal fiziksel yeterlilik (tıbbi) standartlarını karşılaması gerekir. Hangi öz-sertifikasyon kategorisi geçerlidir?","options":["Muaf Olmayan Eyaletler Arası","Muaf Eyaletler Arası","Muaf Olmayan Eyalet İçi","Muaf Eyalet İçi"],"explanation":"Muaf Olmayan Eyaletler Arası, eyalet sınırlarını geçen ve 49 CFR Part 391'in federal tıbbi gerekliliklerini karşılaması gereken sürücüleri kapsar; bu sürücüler dosyalarında geçerli bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: Ohio BMV öz-sertifikasyon kategorileri (form BMV 2159)."},"87":{"q":"23 Haziran 2025 itibarıyla, bir CDL sahibinin DOT tıbbi muayene sertifikası bilgileri Ohio BMV'ye nasıl sağlanır?","options":["FMCSA muayene sonuçlarını elektronik olarak BMV'ye iletir, bu nedenle artık kağıt sertifika gerekmez","Sürücü 10 gün içinde noter onaylı bir kağıt kopyasını BMV'ye postalamalıdır","Tıbbi muayene yapan kişi, sürücünün lamine ettiği bir cüzdan kartını faksla gönderir","Sertifika yalnızca sürücünün işvereni tarafından yüklenir"],"explanation":"23 Haziran 2025 itibarıyla, FMCSA, CLP başvuru sahipleri ve CDL sahipleri için tıbbi muayene sonuçlarını (ve sapma bilgilerini) Ohio BMV'ye elektronik olarak iletir, bu nedenle sürücüler artık kağıt bir Tıbbi Muayene Sertifikası sunmaz. Kaynak: Ohio BMV CDL tıbbi sertifikasyon bildirimi / FMCSA Tıbbi Muayene Sertifikasyon Entegrasyonu kuralı."},"88":{"q":"Sürücünün ticari sürüş türünün CDL öz-sertifikasyonu için hangi Ohio BMV formu kullanılır?","options":["BMV 2159 (CDL Öz-Sertifikasyon Yetkilendirmesi)","BMV 2290 (Ağır Araç Kullanım Vergisi formu)","BMV 5759 (Tehlikeli Maddeler Onay formu)","BMV 1173 (Araç Tescil formu)"],"explanation":"Ohio, bir sürücünün dört sürüş türü kategorisinden birini beyan etmesi için CDL Öz-Sertifikasyon Yetkilendirmesi olan form BMV 2159'u kullanır. Kaynak: Ohio BMV formu BMV 2159."},"89":{"q":"Ohio'nun 50 soruluk CDL genel bilgi testini geçmek için gereken minimum doğru cevap sayısı nedir?","options":["40 doğru (%80)","35 doğru (%70)","45 doğru (%90)","30 doğru (%60)"],"explanation":"Ohio CDL bilgi testleri geçmek için en az %80'lik bir puan gerektirir; 50 soruluk genel bilgi testinde bu, 40 doğru cevap anlamına gelir. %80 standardı onay testleri için de geçerlidir. Kaynak: Ohio CDL kılavuzu / Ohio BMV test standartları."},"90":{"q":"Ohio Revised Code 4506.14 uyarınca, standart bir (tehlikeli madde içermeyen) Ohio CDL'sinin verilebileceği maksimum süre nedir?","options":["Sekiz yıl","Dört yıl","Beş yıl","On yıl"],"explanation":"ORC 4506.14, hiçbir CDL'nin sekiz yıldan uzun bir süre için verilemeyeceğini öngörür; CDL'ler ruhsat sahibinin doğum gününe bağlıdır. Ancak tehlikeli maddeler onayı, verilmeyi dört yıl ve 180 gün ile sınırlar. Kaynak: Ohio Revised Code 4506.14."},"91":{"q":"Federal arka plan kontrolü (TSA) sınırları nedeniyle, tehlikeli maddeler onayı taşıyan bir Ohio CDL'si hangi süreden daha uzun bir süre için verilemez?","options":["Dört yıl ve 180 gün","Tam olarak dört yıl","Beş yıl","Sekiz yıl"],"explanation":"ORC 4506.14, federal tehlikeli madde güvenlik tehdit değerlendirme döngüsüyle uyumlu olarak, tehlikeli maddeler onaylı bir CDL'yi dört yıl ve 180 gün ile sınırlar. Standart CDL'ler sekiz yıla kadar sürebilir. Kaynak: Ohio Revised Code 4506.14."},"92":{"q":"Ohio yasalarına göre, bir CDL son kullanma tarihinden ne kadar önce yenilenebilir?","options":["Son kullanma tarihinden 180 gün öncesine kadar","Son kullanma tarihinden 30 gün öncesine kadar","Son kullanma tarihinden 90 gün öncesine kadar","Yalnızca son kullanma tarihinde veya sonrasında"],"explanation":"ORC 4506.14, gerekli ücretlerin ödenmesi üzerine bir CDL'nin son kullanma tarihinden 180 gün önce başlayarak yenilenebileceğini belirtir. Kaynak: Ohio Revised Code 4506.14."},"93":{"q":"Ohio kayıt memuru, bir CDL sahibinin yenileme sınavından muaf tutulmasına yalnızca başvuru sahibinin başvuru tarihinden ne kadar önce süresi dolmamış veya süresi dolmuş bir CDL sunması durumunda izin verebilir?","options":["Altı ay","Bir ay","Üç ay","Bir yıl"],"explanation":"ORC 4506.14, başvuru sahibinin süresi dolmamış bir CDL veya başvuru tarihinden en fazla altı ay önce süresi dolmuş bir CDL sunması durumunda kayıt memurunun yenileme sınavından muaf tutmasına izin verir. Bu ek süreyi aşan durumlarda, genellikle yeniden test yapılması gerekir. Kaynak: Ohio Revised Code 4506.14."},"94":{"q":"EYALET İÇİ (yalnızca Ohio içinde) sürüşle sınırlı bir Ohio CDL'si almak için minimum yaş nedir?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Ohio, yalnızca eyalet içi operasyon için minimum CDL yaşını 18 olarak belirler; 21 yaşından küçük sürücüler Ohio içinde sürüşle sınırlıdır. Eyaletler arası operasyon ve tehlikeli madde taşıma 21 yaş gerektirir. Kaynak: Ohio BMV CDL gereklilikleri."},"95":{"q":"Bir Ohio başvuru sahibinin, EYALETLER ARASI ticarette bir ticari motorlu araç kullanması veya tehlikeli madde taşıması için en az kaç yaşında olması gerekir?","options":["21 yaşında","18 yaşında","23 yaşında","25 yaşında"],"explanation":"Ohio'da uygulanan federal kural, bir sürücünün eyaletler arası ticarette çalışması veya plakart taşıyan tehlikeli maddeler taşıması için en az 21 yaşında olmasını gerektirir. 18-20 yaş arası sürücüler eyalet içi sürüşle sınırlıdır. Kaynak: Ohio BMV CDL gereklilikleri / 49 CFR 391.11."},"96":{"q":"Geçerli bir Ohio sürücü belgesi ve Sosyal Güvenlik numarası kanıtının yanı sıra, ilk kez başvuran bir Ohio CDL başvuru sahibinin başka neyi sunması gerekir?","options":["ABD vatandaşlığı veya yasal daimi ikamet kanıtı","Mevcut bir işverenden noter onaylı bir mektup","Bir lise diploması veya GED sertifikası","CDL sahibi olan iki kişisel referans"],"explanation":"Ohio, ilk kez başvuran CDL başvuru sahiplerinin geçerli bir Ohio sürücü belgesi, geçerli bir Sosyal Güvenlik numarası ve ABD vatandaşlığı ya da yasal daimi ikamet kanıtı (örneğin pasaport, doğum belgesi veya daimi oturma kartı) sunmasını gerektirir. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."},"97":{"q":"Bir Ohio sürücüsü kendisini 'Muaf Eyaletler Arası' olarak öz-sertifikalandırır. Bu kategori onların federal tıbbi gereklilikleri hakkında neyi gösterir?","options":["Eyalet sınırlarını geçerek sürerler ancak federal (Part 391) tıbbi standartları karşılamaları GEREKMEZ","Yalnızca Ohio içinde sürerler ve eyalet tıbbi standartlarını karşılamalıdırlar","Her zaman bir federal tıbbi muayene sertifikası taşımalıdırlar","CDL'yi hiçbir iş amacıyla asla kullanmazlar"],"explanation":"Muaf Eyaletler Arası, sürücünün eyalet sınırlarını geçerek çalıştığı ancak 49 CFR Part 391'in federal fiziksel yeterlilik gerekliliklerinden bir muafiyete hak kazandığı anlamına gelir, dolayısıyla o operasyon için bir DOT tıbbi kartı gerekmez. Kaynak: Ohio BMV öz-sertifikasyon kategorileri (form BMV 2159)."},"98":{"q":"Ohio CDL beceri testine girerken, test için kullanılan ticari aracı sağlamaktan genellikle kim sorumludur?","options":["Başvurulan sınıfı temsil eden bir aracı sağlaması (veya kiralaması) gereken başvuru sahibi","Bir test araçları filosu bulunduran Ohio BMV","Yol testleri için araç ödünç veren ODOT","FMCSA bölge ofisi"],"explanation":"Ohio, başvuru sahibinin test edilen sınıfı temsil eden uygun bir ticari araç sağlamasını veya bir araç kiralamasını (genellikle üçüncü taraf bir test sitesi aracılığıyla) gerektirir. BMV test araçları sağlamaz. Kaynak: Ohio BMV, Commercial Driver (CDL) sayfası."}},"es":{"0":{"q":"En las carreteras de Ohio, ¿cuál es el ancho máximo legal de un vehículo, incluida su carga, sin un permiso especial de transporte?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","8 pies 2 pulgadas (98 pulgadas)"],"explanation":"El Código Revisado de Ohio 5577.05 establece el ancho máximo del vehículo en 102 pulgadas (8 pies 6 pulgadas), incluida la carga. Cualquier cosa más ancha requiere un permiso especial de transporte de ODOT."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Ohio sin un permiso?","options":["13 pies 0 pulgadas","14 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 6 pulgadas"],"explanation":"Según el Código Revisado de Ohio 5577.05, la altura máxima es de 13 pies 6 pulgadas (13.5 pies), con o sin carga. El conductor es responsable de pasar por debajo de los pasos elevados y las estructuras."},"2":{"q":"En Ohio, ¿cuál es la longitud máxima de un semirremolque operado en una combinación de tractor y semirremolque sin un permiso?","options":["48 pies","53 pies","57 pies","45 pies"],"explanation":"El Código Revisado de Ohio 5577.05 permite un semirremolque de hasta 53 pies de longitud cuando se opera en una combinación comercial de tractor y semirremolque, en consonancia con la norma federal de la red nacional."},"3":{"q":"¿Cuál es el peso bruto máximo de un vehículo y su carga que puede transportarse en las carreteras de Ohio sin un permiso especial de transporte?","options":["73,280 libras","80,000 libras","90,000 libras","84,000 libras"],"explanation":"El Código Revisado de Ohio 5577.04 limita el peso bruto total máximo impuesto sobre la superficie de la carretera a 80,000 libras, el mismo que el límite federal interestatal."},"4":{"q":"Según la ley de Ohio, el peso sobre cualquier eje simple de un vehículo no puede exceder ¿qué cantidad?","options":["18,000 libras","22,400 libras","20,000 libras","24,000 libras"],"explanation":"El Código Revisado de Ohio 5577.04 limita el peso máximo por eje simple a 20,000 libras, igual que la norma federal de eje simple."},"5":{"q":"¿Cuál es el peso máximo permitido sobre un grupo de ejes en tándem en el sistema interestatal de Ohio?","options":["32,000 libras","36,000 libras","38,000 libras","34,000 libras"],"explanation":"El Código Revisado de Ohio 5577.04 fija el peso máximo por eje en tándem en 34,000 libras, en consonancia con el límite federal de eje en tándem."},"6":{"q":"¿Cuál es la longitud máxima de cualquier vehículo individual (no remolque) que no sea un autobús o un vehículo recreativo en las carreteras de Ohio sin un permiso?","options":["40 pies","50 pies","45 pies","53 pies"],"explanation":"El Código Revisado de Ohio 5577.05 limita un vehículo individual (que no sea uno de los vehículos específicamente enumerados, como los autobuses) a 50 pies de longitud."},"7":{"q":"¿Qué agencia estatal de Ohio emite los permisos especiales de transporte para cargas de gran tamaño o sobrepeso para circular por carreteras estatales, federales e interestatales?","options":["La Oficina de Vehículos Motorizados de Ohio (BMV)","La Patrulla de Carreteras del Estado de Ohio","La Comisión de Servicios Públicos de Ohio (PUCO)","El Departamento de Transporte de Ohio (ODOT)"],"explanation":"El Departamento de Transporte de Ohio (ODOT) emite los permisos especiales de transporte, que se tramitan electrónicamente a través del Sistema de Permisos de Transporte de Ohio (ODOT Special Hauling Permits)."},"8":{"q":"En una combinación de tractor, semirremolque y remolque (doble) en las carreteras de Ohio, ¿cuál es la longitud máxima de cada semirremolque o remolque sin un permiso?","options":["28 pies 6 pulgadas","33 pies","27 pies","30 pies"],"explanation":"El Código Revisado de Ohio 5577.05 limita cada semirremolque o remolque a 28 pies 6 pulgadas cuando se opera en una combinación comercial de tractor-semirremolque-remolque o tractor-semirremolque-semirremolque."},"9":{"q":"Una combinación de camión en una carretera de Ohio es demasiado pesada para los límites legales. ¿Qué tipo de permiso debe obtener el operador antes de circular?","options":["Un endoso de carga ancha en la CDL","Un permiso especial de transporte de ODOT","Una exención federal de sobrepeso de la FMCSA","Un certificado de fianza vial emitido por el condado"],"explanation":"Según ODOT, cualquier vehículo o carga que exceda los límites legales de tamaño o peso de Ohio debe obtener un permiso especial de transporte de ODOT antes de operar en carreteras estatales, federales o interestatales."},"10":{"q":"En las carreteras de Ohio, ¿cuál es la longitud máxima para combinaciones de vehículos que no estén específicamente previstas de otra manera (por ejemplo, una combinación general de tractor-semirremolque-remolque)?","options":["60 pies","75 pies","65 pies","70 pies"],"explanation":"El Código Revisado de Ohio 5577.05 fija un máximo de 65 pies para cualquier otra combinación de vehículos no especificada de otra manera."},"11":{"q":"La fórmula federal de puentes adoptada en la ley de Ohio para grupos de ejes múltiples es W = 500((LN/(N-1)) + 12N + 36). En esta fórmula, ¿qué representa la 'L'?","options":["La clasificación de carga legal del puente","La distancia en pies entre los ejes extremos (primero y último) del grupo","La longitud del remolque más largo de la combinación","El peso bruto total con licencia del vehículo"],"explanation":"En la fórmula de puentes establecida en el Código Revisado de Ohio 5577.04(C), L es la distancia en pies entre el primer eje y el eje trasero del grupo, N es el número de ejes y W es el peso bruto máximo permitido."},"12":{"q":"Según las disposiciones especiales de peso de Ohio, ¿en qué porcentaje puede un camión agrícola, maderero, de carbón o de residuos sólidos que reúna los requisitos exceder los límites de peso normales cuando transporta desde la producción hasta el primer punto de entrega?","options":["5 por ciento","10 por ciento","7.5 por ciento","12.5 por ciento"],"explanation":"El Código Revisado de Ohio 5577.042 permite a los vehículos de transporte agrícola, maderero, de carbón y de residuos sólidos que reúnan los requisitos exceder las disposiciones de peso en no más de 7.5 por ciento bajo las condiciones descritas."},"13":{"q":"¿Durante qué meses NO se aplica la variación de peso del 7.5 por ciento de Ohio para camiones agrícolas, camiones madereros y maquinaria agrícola?","options":["Febrero y marzo","Enero y febrero","Marzo y abril","Noviembre y diciembre"],"explanation":"El Código Revisado de Ohio 5577.042 especifica que la variación del 7.5 por ciento no se aplica durante febrero y marzo para camiones agrícolas, camiones madereros o maquinaria agrícola (el período estacional de congelamiento/deshielo)."},"14":{"q":"La variación de peso del 7.5 por ciento para productos agrícolas y forestales de Ohio según el ORC 5577.042 NO se aplica en ¿cuáles vías?","options":["Caminos de condado","Carreteras interestatales","Caminos de municipio (township)","Calles municipales"],"explanation":"El Código Revisado de Ohio 5577.042 establece que la variación del 7.5 por ciento no se aplica en las carreteras interestatales (ni en los caminos sujetos a pesos máximos especialmente reducidos)."},"15":{"q":"Según las reglas de ODOT, una carga se clasifica como 'supercarga' (superload) cuando su peso bruto excede ¿qué cantidad?","options":["80,000 libras","100,000 libras","120,000 libras","150,000 libras"],"explanation":"Según la Guía Operativa de ODOT, una supercarga es cualquier vehículo/carga con un peso bruto superior a 120,000 libras (o un ancho superior a 14 pies o una altura superior a 14 pies 6 pulgadas), lo que requiere una revisión adicional, como un análisis de puentes/estructural."},"16":{"q":"En el sistema no interestatal (red de carreteras general) de Ohio, dos ejes sucesivos separados por más de 4 pies pueden transportar hasta 34,000 libras más 1,000 libras por cada pie adicional, pero no más de ¿qué máximo?","options":["38,000 libras","42,000 libras","44,000 libras","40,000 libras"],"explanation":"El Código Revisado de Ohio 5577.04 dispone que, en el sistema no interestatal, dos ejes sucesivos separados por más de 4 pies pueden transportar 34,000 libras más 1,000 libras por cada pie que exceda los 4 pies, hasta un máximo de 40,000 libras."},"17":{"q":"Según las reglas de escolta de ODOT, un vehículo/carga más ancho que ¿qué dimensión requiere un vehículo de escolta delantero (líder) en una carretera de dos carriles de Ohio?","options":["12 pies","13 pies","11 pies","10 pies"],"explanation":"Según los requisitos de escolta de los permisos de ODOT, se requiere una escolta delantera para cualquier vehículo/carga con un ancho total superior a 13 pies; las cargas de más de 14 pies 6 pulgadas de ancho requieren tanto una escolta delantera como una trasera."},"18":{"q":"Según las reglas de permisos de ODOT, generalmente se permite que una carga de gran tamaño de menos de 12 pies de ancho circule durante ¿qué franja horaria diaria?","options":["Solo entre las 9:00 a.m. y las 3:00 p.m.","Desde 30 minutos antes del amanecer hasta 30 minutos después del atardecer","Desde una hora después del amanecer hasta una hora antes del atardecer","Solo durante las horas de plena luz del día, del amanecer al atardecer"],"explanation":"Según ODOT, las cargas de gran tamaño de menos de 12 pies de ancho pueden circular los siete días de la semana (excepto los días festivos) desde 30 minutos antes del amanecer hasta 30 minutos después del atardecer; las cargas de 12 pies de ancho o más deben respetar los horarios específicos indicados en el permiso."},"19":{"q":"En el sistema interestatal de Ohio, dos conjuntos consecutivos de ejes en tándem pueden transportar cada uno 34,000 libras siempre que la distancia entre el primer y el último eje de los dos conjuntos sea de al menos ¿cuántos pies?","options":["30 pies","40 pies","36 pies","34 pies"],"explanation":"El Código Revisado de Ohio 5577.04 permite que dos conjuntos consecutivos de ejes en tándem transporten 34,000 libras cada uno solo cuando la distancia total entre el primer y el último eje de los conjuntos consecutivos sea de 36 pies o más."},"20":{"q":"En Ohio, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Clasificación de Peso Bruto Combinado (GCWR) de 26,001 libras o más, siempre que la unidad remolcada tenga un GVWR de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"La CDL Clase A de Ohio cubre vehículos en combinación con un GCWR de 26,001 lbs o más, donde el GVWR de la unidad remolcada excede las 10,000 lbs. Fuente: página de Clases de CDL de Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx) y 49 CFR 383.91 según lo adoptado en Ohio."},"21":{"q":"Un conductor de Ohio opera un camión rígido individual con un GVWR de 30,000 libras que no remolca ningún remolque de más de 10,000 libras. ¿Qué clase de CDL es la adecuada?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"La CDL Clase B de Ohio cubre cualquier vehículo individual con un GVWR de 26,001 lbs o más, y puede remolcar un remolque que no exceda las 10,000 lbs de GVWR. Fuente: página de Clases de CDL de Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"22":{"q":"Según las reglas de Ohio, un vehículo que no cumple con los umbrales de peso para la Clase A o B, pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o materiales peligrosos que requieran carteles (placas), ¿bajo qué clase de CDL se clasifica?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"La CDL Clase C de Ohio se aplica a los vehículos por debajo de los umbrales de peso de la Clase A/B que transportan 16 o más personas (incluido el conductor) o materiales peligrosos que requieran carteles (placas). Fuente: página de Clases de CDL de Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"23":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Ohio restringida únicamente a la conducción comercial INTRAESTATAL (dentro de Ohio)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Ohio emite una CDL solo intraestatal a partir de los 18 años; los conductores menores de 21 años están limitados al comercio dentro de Ohio. Fuente: requisitos de elegibilidad de CDL de Ohio BMV (bmv.ohio.gov) y ORC 4506.10."},"24":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo motorizado comercial en el comercio INTERESTATAL con una CDL de Ohio?","options":["18 años","19 años","20 años","21 años"],"explanation":"La conducción comercial interestatal requiere que el conductor tenga al menos 21 años. Los conductores de Ohio de entre 18 y 20 años tienen una CDL solo intraestatal. Fuente: requisitos de elegibilidad de CDL de Ohio BMV y 49 CFR 391.11."},"25":{"q":"¿Qué letra de endoso se requiere en una CDL de Ohio para transportar materiales peligrosos en cantidades que requieran que el vehículo lleve carteles (placas)?","options":["Endoso H","Endoso N","Endoso T","Endoso X"],"explanation":"El endoso H (HazMat) autoriza el transporte de materiales peligrosos que requieran carteles (placas). Fuente: página de Clases/endosos de CDL de Ohio BMV y 49 CFR 383.93."},"26":{"q":"Un conductor de Ohio que transporta líquidos o gases a granel en un tanque montado permanentemente debe poseer ¿qué endoso?","options":["Endoso H","Endoso N","Endoso P","Endoso S"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para operar un vehículo cisterna que transporte materiales líquidos o gaseosos a granel. Fuente: información de endosos de Ohio BMV y 49 CFR 383.93."},"27":{"q":"¿Qué endoso de CDL de Ohio se requiere para arrastrar remolques dobles o triples?","options":["Endoso P","Endoso S","Endoso T","Endoso D"],"explanation":"El endoso T autoriza la operación de combinaciones de remolques dobles/triples y se obtiene aprobando el examen de conocimientos de dobles/triples. Fuente: información de endosos de Ohio BMV y 49 CFR 383.93."},"28":{"q":"¿Qué endoso necesita un titular de CDL de Ohio para conducir un vehículo comercial diseñado para transportar 16 o más pasajeros, incluido el conductor (que no sea un autobús escolar)?","options":["Endoso N","Endoso P","Endoso T","Endoso H"],"explanation":"El endoso P (Pasajeros) se requiere para operar un vehículo diseñado para transportar 16 o más personas, incluido el conductor. Fuente: información de endosos de Ohio BMV y 49 CFR 383.93."},"29":{"q":"En Ohio, antes de que se pueda emitir a un conductor el endoso de Autobús Escolar (S), ¿qué otro endoso debe también obtener?","options":["El endoso H (HazMat)","El endoso N (Cisterna)","El endoso P (Pasajeros)","El endoso T (Dobles/Triples)"],"explanation":"Las reglas federales y de Ohio requieren que el endoso S (Autobús Escolar) se combine con el endoso P (Pasajeros), ya que un autobús escolar transporta pasajeros. Fuente: información de endosos de Ohio BMV y 49 CFR 383.93."},"30":{"q":"Antes de que se le otorgue el endoso de HazMat (H), un solicitante de CDL de Ohio debe aprobar ¿qué evaluación adicional además del examen escrito de conocimientos de HazMat?","options":["Una evaluación de amenazas a la seguridad de la TSA que incluye la toma de huellas dactilares","Una segunda prueba de habilidades de manejo en un vehículo cisterna","Un examen de la vista administrado por el BMV","Un curso de manejo defensivo en aula"],"explanation":"El endoso de HazMat requiere una evaluación de amenazas a la seguridad de la Administración de Seguridad en el Transporte (TSA) con una verificación de antecedentes basada en huellas dactilares, además del examen de conocimientos. Fuente: información de HazMat de Ohio BMV y 49 CFR 1572."},"31":{"q":"Un conductor debe obtener un Permiso de Aprendiz Comercial (CLP) de Ohio y conservarlo durante un período mínimo antes de poder presentar la prueba de habilidades (de manejo) de la CDL. ¿Cuál es ese período mínimo de tenencia?","options":["7 días","14 días","30 días","60 días"],"explanation":"La regla federal adoptada por Ohio requiere que el CLP se conserve durante al menos 14 días antes de que el solicitante pueda presentar la prueba de habilidades de la CDL. Fuente: proceso de CDL de Ohio BMV y 49 CFR 383.25."},"32":{"q":"Al operar un vehículo comercial con un Permiso de Aprendiz Comercial (CLP) de Ohio, ¿de quién debe estar acompañado el titular del permiso?","options":["De cualquier conductor con licencia de 25 años o más","De un titular de CDL con la clase/endosos apropiados sentado a su lado","Solo de un examinador del BMV","De nadie, si conduce durante las horas de luz del día"],"explanation":"Un titular de CLP puede operar un CMV solo cuando esté acompañado de una persona que posea una CDL válida de la clase y los endosos apropiados, sentada junto al titular del CLP. Fuente: reglas de CLP de Ohio BMV y 49 CFR 383.25."},"33":{"q":"Desde el 7 de febrero de 2022, una persona que obtiene una CDL Clase A por primera vez en Ohio debe completar la Capacitación para Conductores Principiantes (ELDT) impartida por una entidad que sea ¿qué?","options":["Que figure en el Registro de Proveedores de Capacitación (Training Provider Registry) de la FMCSA","Acreditada por el Departamento de Educación de Ohio","Aprobada únicamente por el registrador adjunto local","Certificada por la Patrulla de Carreteras del Estado de Ohio"],"explanation":"La ELDT debe ser impartida por un proveedor que figure en el Registro de Proveedores de Capacitación (TPR) de la FMCSA, y la certificación debe estar en el registro antes de la prueba de habilidades/conocimientos. Fuente: regla ELDT de la FMCSA (49 CFR 380 subparte F) y tpr.fmcsa.dot.gov."},"34":{"q":"¿Cuál de las siguientes acciones realizadas por primera vez NO desencadena el requisito federal de Capacitación para Conductores Principiantes (ELDT)?","options":["Obtener una CDL Clase A por primera vez","Obtener el endoso de Pasajeros (P) por primera vez","Obtener el endoso de Cisterna (N) por primera vez","Obtener el endoso de HazMat (H) por primera vez"],"explanation":"La ELDT se aplica a las CDL Clase A/B obtenidas por primera vez, a las mejoras de B a A y a los endosos P, S y H obtenidos por primera vez. Los endosos N (Cisterna) y T (Dobles/Triples) no están cubiertos por la ELDT. Fuente: aplicabilidad de la ELDT de la FMCSA (tpr.fmcsa.dot.gov/Drivers/Applicability)."},"35":{"q":"El requisito de ELDT se aplica a las personas que obtienen su Permiso de Aprendiz Comercial en o después de ¿qué fecha?","options":["7 de febrero de 2020","7 de febrero de 2022","30 de enero de 2021","31 de diciembre de 2023"],"explanation":"Los requisitos de Capacitación para Conductores Principiantes se aplican a los conductores que obtienen un CLP en o después del 7 de febrero de 2022. Fuente: regla ELDT de la FMCSA y tpr.fmcsa.dot.gov."},"36":{"q":"En el formulario de autocertificación de CDL de Ohio, ¿qué categoría describe a un conductor que opera cruzando líneas estatales y debe cumplir con los requisitos del examen físico federal del DOT (tarjeta médica)?","options":["Interestatal Exceptuado (Excepted Interstate)","Interestatal No Exceptuado (Non-Excepted Interstate)","Intraestatal Exceptuado (Excepted Intrastate)","Intraestatal No Exceptuado (Non-Excepted Intrastate)"],"explanation":"Los conductores Interestatales No Exceptuados (Non-Excepted Interstate) operan en el comercio interestatal y deben cumplir con las normas médicas federales (Parte 391), proporcionando un Certificado de Examinador Médico. Fuente: formulario BMV 2159 de Ohio (Autocertificación de CDL) y 49 CFR 383.71."},"37":{"q":"¿Qué documentos debe presentar al BMV un solicitante de CDL por primera vez en Ohio para probar su elegibilidad?","options":["Prueba de identidad/presencia legal, número completo del Seguro Social y residencia en Ohio","Solo una licencia de conducir vigente de Ohio y una tarjeta de crédito","Un pasaporte y dos facturas de servicios públicos, pero sin número de Seguro Social","Solo un título del vehículo y prueba de seguro"],"explanation":"Ohio requiere documentación de identidad y presencia legal (por ejemplo, acta de nacimiento, pasaporte o tarjeta de residente permanente), el número del Seguro Social y prueba de residencia en Ohio. Fuente: requisitos de documentación de CDL de Ohio BMV (bmv.ohio.gov)."},"38":{"q":"Un conductor de Ohio de 19 años quiere una CDL para transportar materiales peligrosos que requieran carteles (placas). ¿Por qué este conductor NO puede obtener el endoso de HazMat (H)?","options":["El transporte de HazMat requiere tener al menos 21 años","Los endosos de HazMat solo se emiten a conductores de Clase C","Ohio no ofrece el endoso de HazMat","Primero debe obtenerse un endoso de cisterna (N)"],"explanation":"El transporte de materiales peligrosos con carteles (placas) tiene capacidad interestatal y requiere que el conductor tenga al menos 21 años; los titulares de la CDL intraestatal de 18 a 20 años de Ohio no pueden tener el endoso H. Fuente: requisitos de elegibilidad de CDL de Ohio BMV y 49 CFR 383.93/391.11."},"39":{"q":"En Ohio, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) que puede tener un conductor mientras opera un vehículo motorizado comercial (CMV) antes de que se le considere legalmente con sus facultades disminuidas a efectos de la CDL?","options":["0.04 por ciento","0.08 por ciento","0.02 por ciento","0.10 por ciento"],"explanation":"Ohio sigue la norma federal para CMV: operar un vehículo motorizado comercial con un BAC de 0.04 por ciento o más es un delito grave. El umbral es la mitad del límite de 0.08 para conductores no comerciales. Fuente: Manual de CDL de Ohio / Descalificaciones de CDL de Ohio BMV; ORC 4506.15; 49 CFR 383.51."},"40":{"q":"Al obtener y usar una CDL de Ohio, se considera que un conductor ha dado su consentimiento para someterse a pruebas químicas de aliento, sangre u orina para determinar el contenido de alcohol o drogas. ¿Cómo se llama este principio legal?","options":["Consentimiento implícito","Causa probable","Consentimiento del debido proceso","Licencia condicional"],"explanation":"La ley de consentimiento implícito de Ohio significa que operar un vehículo en las carreteras de Ohio constituye consentimiento para someterse a pruebas químicas cuando se es arrestado legalmente por un delito relacionado con el alcohol/drogas. La negativa conlleva sus propias sanciones administrativas. Fuente: ORC 4511.191; Manual de CDL de Ohio."},"41":{"q":"En Ohio, ¿cuál es el período mínimo de descalificación de la CDL para el PRIMER delito grave de un conductor, como un BAC de 0.04+ en un CMV o negarse a una prueba química, mientras NO se transportan materiales peligrosos con carteles (placas)?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Un primer delito grave (BAC de 0.04+, OVI, negativa a la prueba, abandonar la escena, usar un CMV en un delito grave, etc.) resulta en una descalificación de la CDL de 1 año en Ohio. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"42":{"q":"Si un conductor de Ohio comete un primer delito grave (como un BAC de 0.04+) mientras opera un CMV con carteles (placas) de materiales peligrosos, el período de descalificación se incrementa a:","options":["3 años","1 año","5 años","De por vida"],"explanation":"Cuando un primer delito grave ocurre en un vehículo con carteles (placas) de materiales peligrosos, la descalificación estándar de 1 año se incrementa a 3 años. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"43":{"q":"¿Cuál es el período de descalificación de la CDL en Ohio para un SEGUNDO delito grave (por ejemplo, un segundo OVI o un segundo BAC de 0.04+ en un CMV)?","options":["De por vida","10 años","3 años","5 años"],"explanation":"Una segunda condena por cualquier delito grave resulta en una descalificación de la CDL de por vida en Ohio. Algunas descalificaciones de por vida pueden reducirse a 10 años después de cumplir con las condiciones de reinstalación. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"44":{"q":"Un conductor de Ohio arrestado legalmente por OVI se niega a someterse a una prueba química de aliento. A efectos de la CDL, negarse a la prueba resulta en una descalificación de al menos:","options":["1 año","90 días","60 días","30 días"],"explanation":"Una negativa a la prueba se trata como un delito grave a efectos de la CDL, y conlleva una descalificación de 1 año (3 años si se transportan materiales peligrosos con carteles/placas), además de cualquier suspensión administrativa de la licencia. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"45":{"q":"Según la ley de consentimiento implícito de Ohio, un titular de CDL que se niega a someterse a pruebas químicas también enfrenta una suspensión administrativa de la licencia. Para una PRIMERA negativa, esta suspensión administrativa es generalmente:","options":["1 año","90 días","6 meses","2 años"],"explanation":"La ley de consentimiento implícito de Ohio impone una suspensión administrativa de la licencia de 1 año para una primera negativa a la prueba química, con períodos más largos para negativas reiteradas dentro de 10 años. Esto es independiente de la descalificación de la CDL. Fuente: ORC 4511.191."},"46":{"q":"En Ohio, ¿cuántas infracciones de tránsito GRAVES en incidentes separados dentro de un período de 3 años desencadenan una descalificación de la CDL de 60 días?","options":["2","3","4","5"],"explanation":"La condena por 2 infracciones de tránsito graves dentro de 3 años (en un CMV) resulta en una descalificación de 60 días. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"47":{"q":"Un titular de CDL de Ohio es condenado por TRES infracciones de tránsito graves en incidentes separados dentro de un período de 3 años. ¿Cuál es el período de descalificación de la CDL?","options":["120 días","60 días","90 días","1 año"],"explanation":"La condena por 3 o más infracciones de tránsito graves dentro de 3 años resulta en una descalificación de 120 días. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"48":{"q":"¿Cuánto por encima del límite de velocidad indicado debe ser multado un conductor de CDL para que la infracción cuente como una infracción de tránsito GRAVE en Ohio?","options":["15 mph o más por encima del límite","10 mph o más por encima del límite","20 mph o más por encima del límite","5 mph o más por encima del límite"],"explanation":"Exceder la velocidad en 15 mph o más por encima del límite indicado se clasifica como una infracción de tránsito grave para los titulares de CDL. Fuente: Manual de CDL de Ohio; ORC 4506.01/4506.16; 49 CFR 383.51."},"49":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Ohio?","options":["Seguir demasiado de cerca (no guardar distancia)","Estacionarse en una zona de no estacionar","Una luz de placa de matrícula apagada","Una primera multa por carga con sobrepeso"],"explanation":"Las infracciones de tránsito graves incluyen seguir demasiado de cerca, cambios de carril imprudentes/erráticos, exceder la velocidad en 15+ mph, enviar mensajes de texto mientras se conduce y operar un CMV sin la clase/endoso apropiados. Las infracciones de equipo y estacionamiento no son infracciones graves. Fuente: Manual de CDL de Ohio; 49 CFR 383.51."},"50":{"q":"En Ohio, usar un teléfono móvil de mano o enviar mensajes de texto mientras se opera un CMV está prohibido. A efectos de la CDL, tal condena se cuenta como una:","options":["Infracción de tránsito grave","Delito grave","Infracción de fuera de servicio (out-of-service)","Infracción no registrable"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años conllevan una descalificación de 60 días, tres conllevan 120 días. Fuente: Manual de CDL de Ohio; 49 CFR 383.51 y 392.80/392.82."},"51":{"q":"¿Cuál es la sanción civil federal máxima para el conductor (aplicada en Ohio) a un conductor de CMV que envía mensajes de texto mientras conduce un vehículo comercial?","options":["Hasta $2,750","Hasta $500","Hasta $1,000","Hasta $11,000"],"explanation":"Un conductor de CMV que envía mensajes de texto mientras conduce enfrenta una sanción civil federal de hasta $2,750; los transportistas que lo permiten pueden ser multados con hasta $11,000. Estas reglas se aplican en Ohio. Fuente: 49 CFR 392.80; Regla de No Enviar Mensajes de Texto de la FMCSA."},"52":{"q":"Un titular de CDL de Ohio comete una PRIMERA infracción en un cruce a nivel de ferrocarril y carretera (como no detenerse donde se requiere). ¿Cuál es el período de descalificación?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera resulta en una descalificación de la CDL de 60 días. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"53":{"q":"¿Cuál es el período de descalificación de la CDL en Ohio para una SEGUNDA infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["120 días","60 días","180 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel de ferrocarril dentro de 3 años resulta en una descalificación de 120 días. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"54":{"q":"Un titular de CDL de Ohio comete una TERCERA infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de 3 años. El período de descalificación es:","options":["1 año","120 días","180 días","2 años"],"explanation":"Una tercera o posterior infracción en un cruce a nivel de ferrocarril dentro de 3 años resulta en una descalificación de 1 año (365 días). Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"55":{"q":"¿Cuál es el período de descalificación de la CDL en Ohio para la PRIMERA condena de un conductor por violar una orden de fuera de servicio (OOS)?","options":["180 días","60 días","1 año","90 días"],"explanation":"Una primera condena por violar una orden de fuera de servicio resulta en una descalificación de al menos 180 días. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"56":{"q":"En Ohio, ¿cuál es el período de descalificación de la CDL para una SEGUNDA violación de una orden de fuera de servicio (OOS) en incidentes separados dentro de un período de 10 años?","options":["2 años","1 año","180 días","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de 2 años. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"57":{"q":"Un titular de CDL de Ohio es condenado por una TERCERA violación de una orden de fuera de servicio dentro de un período de 10 años. El período de descalificación es:","options":["3 años","2 años","180 días","5 años"],"explanation":"Una tercera o posterior violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de 3 años. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"58":{"q":"Un conductor de Ohio viola una orden de fuera de servicio mientras transporta materiales peligrosos con carteles (placas) u opera un vehículo diseñado para transportar 16 o más pasajeros. ¿Cuál es la descalificación para esta PRIMERA infracción?","options":["180 días","60 días","1 año","2 años"],"explanation":"Una primera violación de una orden de fuera de servicio mientras se transportan materiales peligrosos con carteles (placas) o se llevan 16+ pasajeros conlleva una descalificación de 180 días; una violación posterior de este tipo dentro de 10 años conlleva 3 años. Fuente: Descalificaciones de CDL de Ohio BMV; ORC 4506.16; 49 CFR 383.51."},"59":{"q":"Según la ley de Ohio de \"Cámbiate de carril\" (Move Over), cuando te acercas a una grúa, un vehículo de mantenimiento de carreteras o una patrulla de policía detenidos que muestran luces intermitentes en una autopista con dos o más carriles en tu sentido de circulación, ¿qué debes hacer?","options":["Cambiarte a un carril que no esté junto al vehículo detenido cuando sea seguro hacerlo","Detenerte por completo hasta que el vehículo se mueva","Tocar la bocina de forma continua mientras pasas","Mantener tu velocidad pero encender las luces intermitentes de emergencia"],"explanation":"La ley de Ohio de \"Cámbiate de carril\" (ORC 4511.213) exige que un conductor que se acerca a un vehículo detenido de seguridad pública, emergencia, servicio en carretera o mantenimiento que muestra luces intermitentes se cambie a un carril que no esté junto a ese vehículo cuando haya al menos dos carriles en el mismo sentido y sea seguro hacerlo. Fuente: Ohio Revised Code 4511.213."},"60":{"q":"Según la ley de Ohio de \"Cámbiate de carril\" (Move Over), si no puedes cambiar de carril de forma segura (por ejemplo, en una vía de dos carriles) al pasar junto a un vehículo de emergencia detenido con las luces intermitentes encendidas, ¿qué exige la ley?","options":["Continuar con la debida precaución, reducir la velocidad y mantener una velocidad segura según las condiciones","Detenerte por completo y esperar a que un oficial te indique con la mano que avances","Continuar al límite de velocidad indicado sin reducir la marcha","Orillarte hacia el acotamiento y detenerte"],"explanation":"Cuando cambiar de carril es imposible o inseguro, el ORC 4511.213 exige que el conductor continúe con la debida precaución, reduzca la velocidad y mantenga una velocidad segura según las condiciones de la vía, del clima y del tránsito. Fuente: Ohio Revised Code 4511.213."},"61":{"q":"En Ohio, un conductor que transporta materiales peligrosos con rótulos (placards) o que opera un autobús debe detenerse antes de un cruce a nivel de ferrocarril ¿a qué distancia del riel más cercano?","options":["No menos de 15 feet y no más de 50 feet","No menos de 5 feet y no más de 25 feet","No menos de 25 feet y no más de 75 feet","No menos de 10 feet y no más de 100 feet"],"explanation":"Un conductor de un autobús o de un vehículo que muestra rótulos (placards) de materiales peligrosos debe detenerse a no más de 50 feet pero no menos de 15 feet del riel más cercano en un cruce de ferrocarril, y luego mirar y escuchar antes de continuar. Fuente: Ohio CDL Manual / 49 CFR 392.10; la parada obligatoria es exigida por el ORC 4511.63."},"62":{"q":"¿Cuál de los siguientes vehículos está OBLIGADO a detenerse en todo cruce a nivel de ferrocarril no exento en Ohio?","options":["Un vehículo que transporta materiales que deben llevar rótulos (placards) según las normas federales de materiales peligrosos","Cualquier camioneta pickup que remolca un tráiler utilitario","Cualquier camión rígido (straight truck) con un peso bruto superior a 10,000 pounds","Cualquier vehículo con ruedas traseras dobles"],"explanation":"El ORC 4511.63 exige que el operador de cualquier autobús, cualquier vehículo escolar o cualquier vehículo que transporte material que deba llevar rótulos (placards) conforme a 49 CFR Parts 100-185 se detenga antes de cruzar una vía férrea. Los camiones y tráileres comunes no están sujetos a la parada obligatoria. Fuente: Ohio Revised Code 4511.63."},"63":{"q":"En una vía de dos carriles en Ohio, cuando te encuentras con un autobús escolar detenido que está subiendo o bajando niños con sus luces rojas intermitentes encendidas, debes detenerte ¿a qué distancia mínima del autobús?","options":["Al menos 10 feet del frente o la parte trasera del autobús","Al menos 20 feet del frente o la parte trasera del autobús","Al menos 30 feet del frente o la parte trasera del autobús","Al menos 50 feet del frente o la parte trasera del autobús"],"explanation":"El ORC 4511.75 exige que un conductor que se encuentra con un autobús escolar detenido o lo rebasa se detenga al menos a 10 feet del frente o la parte trasera del autobús y no avance hasta que el autobús se mueva o el conductor le indique que avance. Fuente: Ohio Revised Code 4511.75."},"64":{"q":"En Ohio, en una autopista dividida en cuántos carriles de circulación puede el tránsito en sentido contrario continuar sin detenerse ante un autobús escolar detenido en el lado opuesto?","options":["Cuatro o más carriles","Dos o más carriles","Tres o más carriles","Seis o más carriles"],"explanation":"La ley de autobuses escolares de Ohio establece que, en una autopista de cuatro o más carriles, un conductor no necesita detenerse ante un autobús escolar que se ha detenido en el lado opuesto; solo el tránsito que circula en el mismo sentido que el autobús debe detenerse. Fuente: Ohio Revised Code 4511.75."},"65":{"q":"Después de detenerte ante un autobús escolar en Ohio en una vía de dos carriles, ¿cuándo puedes avanzar?","options":["Cuando el autobús reanuda la marcha o el conductor del autobús te indica que avances","Tan pronto como los niños hayan bajado de la calzada","Después de esperar 30 segundos obligatorios","Cuando las luces ámbar del autobús comienzan a parpadear"],"explanation":"El ORC 4511.75 establece que un conductor detenido no debe avanzar hasta que el autobús escolar reanude la marcha o hasta que el conductor del autobús le indique que avance. Fuente: Ohio Revised Code 4511.75."},"66":{"q":"¿Cuál es el límite máximo de velocidad para un tractocamión con remolque en una autopista interestatal rural en Ohio (a menos que se indique un límite menor)?","options":["70 mph, igual que los autos de pasajeros","55 mph, menor que los autos de pasajeros","60 mph, menor que los autos de pasajeros","65 mph, menor que los autos de pasajeros"],"explanation":"Ohio no establece un límite de velocidad separado y menor para los camiones. Según el ORC 4511.21, el máximo en las interestatales rurales es de 70 mph y los camiones comerciales pueden circular al mismo límite que los autos, salvo que se indique lo contrario. Fuente: Ohio Revised Code 4511.21; normas de zonas de velocidad de ODOT."},"67":{"q":"¿Cuál es el límite de velocidad para los camiones comerciales en el tramo principal de la Ohio Turnpike?","options":["70 mph, igual que para los vehículos de pasajeros","65 mph para camiones mientras que los autos pueden ir a 70","55 mph para todos los camiones","60 mph para camiones mientras que los autos pueden ir a 70"],"explanation":"La Ohio Turnpike indica un límite de 70 mph en su tramo principal que aplica a todos los vehículos, incluidos los camiones comerciales; Ohio no impone una velocidad menor separada para camiones. Fuente: Ohio Turnpike and Infrastructure Commission; ORC 4511.21."},"68":{"q":"En una vía de varios carriles en Ohio, un conductor de camión que circula más lento que la velocidad predominante del tránsito generalmente está obligado a hacer ¿qué?","options":["Circular en el carril de la derecha disponible para el tránsito, excepto al rebasar o al girar a la izquierda","Permanecer en el carril central para evitar vehículos que se incorporan","Usar el carril izquierdo para que el tránsito más rápido se incorpore por la derecha","Usar cualquier carril siempre que las luces intermitentes de emergencia estén encendidas"],"explanation":"El ORC 4511.25 exige que un vehículo que circula más lento que la velocidad legal predominante se conduzca en el carril de la derecha disponible para el tránsito, lo suficientemente a la derecha como para permitir un rebase seguro, excepto al rebasar, al girar a la izquierda o cuando la ruta requiera otro carril. Fuente: Ohio Revised Code 4511.25."},"69":{"q":"Cuando un camión queda averiado y detenido en una vía de Ohio, ¿cómo deben colocarse los tres dispositivos de advertencia (bengalas, reflectores o linternas)?","options":["Uno a unos 100 feet por delante, uno a unos 100 feet por detrás y uno del lado del tránsito","Los tres colocados directamente detrás del vehículo en fila","Uno a cada lado y uno sobre el techo de la cabina","Uno a 10 feet por delante, uno a 10 feet por detrás y uno en el acotamiento"],"explanation":"El ORC 4513.28 exige colocar los dispositivos de advertencia aproximadamente a 100 feet por delante del vehículo, aproximadamente a 100 feet por detrás y uno del lado del tránsito del vehículo averiado. Fuente: Ohio Revised Code 4513.28."},"70":{"q":"Una primera infracción de la ley de Ohio de \"Cámbiate de carril\" (ORC 4511.213) se clasifica como ¿qué?","options":["Un delito menor leve (minor misdemeanor) con la multa duplicada (hasta unos $300)","Un delito grave (felony) de quinto grado","Una infracción civil sin movimiento, sin puntos","Un delito menor (misdemeanor) de primer grado con cárcel obligatoria"],"explanation":"Una primera infracción conforme al ORC 4511.213 es un delito menor leve (minor misdemeanor), pero el tribunal debe imponer una multa del doble del monto habitual, lo que la lleva hasta aproximadamente $300. Las infracciones repetidas dentro de un año se elevan a delitos menores de cuarto y tercer grado. Fuente: Ohio Revised Code 4511.213."},"71":{"q":"En Ohio, ¿cuál es el ancho legal máximo de un vehículo comercial o una carga antes de que se requiera un permiso de sobredimensión?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"El ancho máximo legal de un vehículo en Ohio es de 8 feet 6 inches (102 inches); cualquier cosa más ancha requiere un permiso especial de transporte de ODOT. Fuente: ORC 5577.05; normas del Special Hauling Permit del Ohio DOT."},"72":{"q":"En Ohio, ¿cuál es la altura legal máxima de un vehículo y su carga antes de que se requiera un permiso?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"explanation":"La altura máxima legal en Ohio es de 13 feet 6 inches; las cargas más altas que esto requieren un permiso de sobredimensión de ODOT. Fuente: ORC 5577.05; Special Hauling Permit Operational Guide del Ohio DOT."},"73":{"q":"¿Quién emite el permiso especial que permite que un vehículo de sobredimensión o sobrepeso opere en las rutas estatales de Ohio?","options":["El Director de Transporte de Ohio (ODOT)","La Oficina de Vehículos Motorizados de Ohio (BMV)","El sheriff de cada condado de la ruta","El comandante del puesto del Ohio State Highway Patrol"],"explanation":"Los vehículos que exceden los límites legales de tamaño o peso pueden operar en una ruta estatal solo bajo un permiso especial por escrito emitido por el Director de Transporte de Ohio. Fuente: ORC 4513.34 y 5577.04; Special Hauling Permits de ODOT."},"74":{"q":"En Ohio, ¿cuál es el peso bruto vehicular máximo permitido sin un permiso de sobrepeso, conforme al límite federal?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"Ohio sigue el peso bruto máximo federal de 80,000 pounds (sujeto a la Federal Bridge Formula); excederlo requiere un permiso de sobrepeso de ODOT. Fuente: ORC 5577.04; Federal Bridge Formula."},"75":{"q":"Cuando un vehículo con rótulos (placards) de materiales peligrosos se acerca a un cruce de ferrocarril en Ohio, ¿qué acción es correcta mientras cruza las vías?","options":["No cambiar de marcha (engranaje) mientras cualquier parte del vehículo esté sobre las vías","Reducir a una marcha más baja mientras cruza para tener mejor control","Detenerse a medio cruce para verificar si viene un segundo tren","Apagar el motor hasta haber cruzado por completo las vías"],"explanation":"Después de detenerse, mirar y escuchar, el conductor debe cruzar en una marcha que no necesite cambiar y no debe cambiar de marcha mientras cualquier parte del vehículo esté sobre las vías. Fuente: Ohio CDL Manual / 49 CFR 392.10; ORC 4511.63."},"76":{"q":"En una autopista dividida de cuatro carriles en Ohio, un autobús escolar que se detiene para bajar niños debe, cuando sea posible, hacer ¿qué para reducir el riesgo de cruzar la vía?","options":["Recoger y bajar pasajeros del lado de la autopista donde están las viviendas","Detenerse en el camellón central para que los niños usen el cruce","Bajar a todos los pasajeros en el acotamiento izquierdo","Exigir que el conductor escolte a todos los niños al cruzar"],"explanation":"En autopistas divididas o vías de cuatro o más carriles, los autobuses escolares deben recoger y bajar a los niños del lado de las viviendas para que los niños no tengan que cruzar la calzada; por eso el tránsito en sentido contrario no necesita detenerse. Fuente: Ohio Revised Code 4511.75; reglamentos de autobuses escolares de Ohio."},"77":{"q":"Según la ley de Ohio, cuando se coloca una señal de ALTO (STOP) en un cruce a nivel de ferrocarril designado como peligroso, ¿a qué distancia del riel más cercano debe detenerse un conductor?","options":["No menos de 15 feet pero dentro de 50 feet","No menos de 5 feet pero dentro de 20 feet","No menos de 30 feet pero dentro de 60 feet","Exactamente a 25 feet del riel más cercano"],"explanation":"El ORC 4511.61 exige que un conductor se detenga a no más de cincuenta feet pero no menos de quince feet del riel más cercano en un cruce de ferrocarril donde se ha colocado una señal de alto, y que no avance hasta que sea seguro. Fuente: Ohio Revised Code 4511.61."},"78":{"q":"¿Qué afirmación describe mejor si Ohio impone límites de velocidad específicos para camiones, distintos de los de los autos?","options":["Ohio establece los mismos límites máximos de velocidad para camiones y autos; a los camiones no se les asigna un límite estatal menor por separado","Los camiones siempre están limitados a 55 mph en todo el estado sin importar el límite indicado","Los camiones deben circular 10 mph por debajo del límite de los autos en todas las autopistas","Los camiones solo pueden usar la Ohio Turnpike y tienen prohibido el acceso a las interestatales"],"explanation":"Ohio aplica los mismos límites máximos de velocidad indicados a los camiones comerciales y a los autos de pasajeros conforme al ORC 4511.21; no hay un límite estatal menor por separado para camiones, aunque los conductores aún deben circular a una velocidad segura según las condiciones. Fuente: Ohio Revised Code 4511.21; ODOT."},"79":{"q":"¿Qué agencia estatal emite las Licencias de Conducir Comerciales (CDL) en Ohio?","options":["La Oficina de Vehículos Motorizados de Ohio (BMV)","El Departamento de Transporte de Ohio (ODOT)","El Ohio State Highway Patrol","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Ohio, la Oficina de Vehículos Motorizados (BMV), una división del Departamento de Seguridad Pública de Ohio, emite todas las licencias de conducir, incluidas las CDL. ODOT se encarga de las carreteras y de los permisos de sobredimensión/sobrepeso, no de las licencias, y la FMCSA es la agencia federal que establece las normas. Fuente: Ohio BMV, página de Commercial Driver (CDL)."},"80":{"q":"Antes de que un solicitante de CDL en Ohio pueda presentar cualquier examen de conocimientos comercial, ¿dónde debe realizarse ese examen?","options":["En persona en una estación de exámenes de conducir del BMV de Ohio","En línea desde cualquier computadora de casa","Por correo usando una hoja de respuestas para hacer en casa","En un proveedor de capacitación ELDT registrado ante la FMCSA"],"explanation":"Ohio exige que los exámenes de conocimientos de CDL (conocimientos generales, endosos y eliminación de la restricción de frenos de aire) se presenten en persona en una estación de exámenes de conducir del BMV; no se pueden presentar en línea. Los proveedores de ELDT imparten la capacitación, no el examen estatal de conocimientos. Fuente: Ohio BMV, página de Commercial Driver (CDL)."},"81":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Ohio una vez emitido?","options":["12 meses","6 meses","30 días","24 meses"],"explanation":"Ohio indica que un CLP es válido por 12 meses. (Según la norma federal, puede renovarse una vez sin volver a presentar el examen de conocimientos generales.) Las opciones incorrectas reflejan periodos de permiso comunes pero erróneos. Fuente: Ohio BMV, página de Commercial Driver (CDL)."},"82":{"q":"Después de recibir un CLP de Ohio, ¿por cuánto tiempo debe el solicitante mantenerlo antes de ser elegible para presentar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 10 días","Al menos 60 días"],"explanation":"La regulación federal, aplicada en Ohio, exige que un CLP se mantenga durante un mínimo de 14 días antes de que el titular pueda presentar el examen de habilidades (de manejo) de la CDL. Fuente: proceso de CDL del Ohio BMV / 49 CFR 383.25 (FMCSA)."},"83":{"q":"El examen de habilidades de la CDL de Ohio se administra en tres partes. ¿Qué conjunto enumera correctamente esas tres partes?","options":["Inspección previaje (pre-trip), control básico (maniobrabilidad) y manejo en carretera","Conocimientos escritos, examen de la vista y manejo en carretera","Inspección previaje (pre-trip), revisión de frenos de aire y manejo de materiales peligrosos","Control básico, manejo nocturno y un examen escrito de endoso"],"explanation":"El examen de habilidades de la CDL de Ohio consta de tres partes: la inspección previaje (pre-trip), el examen de control básico (maniobrabilidad) y el examen de manejo en carretera. El examen de la vista y los exámenes escritos son independientes del examen de habilidades. Fuente: Ohio BMV, página de Commercial Driver (CDL)."},"84":{"q":"¿Qué debe presentar electrónicamente un solicitante de Ohio ANTES de poder agendar o intentar el examen de habilidades de la CDL?","options":["Comprobante de haber completado la Capacitación para Conductores Principiantes (ELDT), o comprobante de una exención","Comprobante de dos años de experiencia de manejo previa","Una carta firmada de patrocinio del empleador","Una calificación aprobatoria en un curso de manejo defensivo"],"explanation":"Ohio exige comprobante electrónico de haber completado la Capacitación para Conductores Principiantes (ELDT) de la FMCSA que corresponda a la clase/endoso solicitado, o comprobante de una exención, antes de poder agendar o intentar el examen de habilidades. Fuente: página de CDL del Ohio BMV / regla ELDT de la FMCSA (49 CFR Part 380)."},"85":{"q":"El proceso de autocertificación de Ohio exige que un solicitante de CDL/CLP elija entre cuántas categorías de tipo de manejo?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Los conductores de Ohio deben autocertificarse en una de cuatro categorías: Interestatal No Exento, Interestatal Exento, Intraestatal No Exento e Intraestatal Exento. Fuente: Autocertificación de CDL del Ohio BMV (formulario BMV 2159)."},"86":{"q":"Un conductor de Ohio cruza líneas estatales por negocios y debe cumplir con los estándares federales de calificación física (médica) conforme a 49 CFR Part 391. ¿Qué categoría de autocertificación aplica?","options":["Interestatal No Exento","Interestatal Exento","Intraestatal No Exento","Intraestatal Exento"],"explanation":"Interestatal No Exento cubre a los conductores que operan cruzando líneas estatales y deben cumplir con los requisitos médicos federales de 49 CFR Part 391; estos conductores deben mantener en archivo un certificado válido de examinador médico. Fuente: categorías de autocertificación del Ohio BMV (formulario BMV 2159)."},"87":{"q":"A partir del 23 de junio de 2025, ¿cómo se proporciona al BMV de Ohio la información del certificado de examinador médico DOT de un titular de CDL?","options":["La FMCSA transmite electrónicamente los resultados del examen al BMV, por lo que ya no se requiere un certificado en papel","El conductor debe enviar por correo una copia en papel notariada al BMV dentro de los 10 días","El examinador médico envía por fax una tarjeta de bolsillo que el conductor lamina","El certificado lo sube únicamente el empleador del conductor"],"explanation":"A partir del 23 de junio de 2025, la FMCSA transmite electrónicamente al BMV de Ohio los resultados del examen médico (y la información de excepciones) de los solicitantes de CLP y los titulares de CDL, por lo que los conductores ya no presentan un Certificado de Examinador Médico en papel. Fuente: aviso de certificación médica de CDL del Ohio BMV / regla de Integración de la Certificación del Examinador Médico de la FMCSA."},"88":{"q":"¿Qué formulario del BMV de Ohio se usa para la autocertificación de CDL del tipo de manejo comercial del conductor?","options":["BMV 2159 (Autorización de Autocertificación de CDL)","BMV 2290 (formulario del Impuesto sobre el Uso de Vehículos Pesados)","BMV 5759 (formulario del Endoso de Materiales Peligrosos)","BMV 1173 (formulario de Registro de Vehículo)"],"explanation":"Ohio usa el formulario BMV 2159, la Autorización de Autocertificación de CDL, para que un conductor declare una de las cuatro categorías de tipo de manejo. Fuente: formulario BMV 2159 del Ohio BMV."},"89":{"q":"¿Cuál es el número mínimo de respuestas correctas necesarias para aprobar el examen de conocimientos generales de CDL de Ohio, de 50 preguntas?","options":["40 correctas (80%)","35 correctas (70%)","45 correctas (90%)","30 correctas (60%)"],"explanation":"Los exámenes de conocimientos de CDL de Ohio requieren una calificación de al menos 80% para aprobar; en el examen de conocimientos generales de 50 preguntas eso significa 40 respuestas correctas. El estándar del 80% también aplica a los exámenes de endoso. Fuente: manual de CDL de Ohio / estándares de examen del Ohio BMV."},"90":{"q":"Conforme al Ohio Revised Code 4506.14, ¿cuál es el periodo máximo por el cual se puede emitir una CDL estándar de Ohio (sin materiales peligrosos)?","options":["Ocho años","Cuatro años","Cinco años","Diez años"],"explanation":"El ORC 4506.14 establece que ninguna CDL puede emitirse por un periodo mayor a ocho años; las CDL están vinculadas al cumpleaños del titular. Sin embargo, un endoso de materiales peligrosos limita la emisión a cuatro años y 180 días. Fuente: Ohio Revised Code 4506.14."},"91":{"q":"Debido a los límites de la verificación federal de antecedentes (TSA), una CDL de Ohio que incluye un endoso de materiales peligrosos no puede emitirse por más de qué periodo?","options":["Cuatro años y 180 días","Exactamente cuatro años","Cinco años","Ocho años"],"explanation":"El ORC 4506.14 limita una CDL con endoso de materiales peligrosos a cuatro años y 180 días, alineándose con el ciclo federal de evaluación de amenazas de seguridad para materiales peligrosos. Las CDL estándar pueden durar hasta ocho años. Fuente: Ohio Revised Code 4506.14."},"92":{"q":"Según la ley de Ohio, ¿con cuánta anticipación a su fecha de vencimiento puede renovarse una CDL?","options":["Hasta 180 días antes del vencimiento","Hasta 30 días antes del vencimiento","Hasta 90 días antes del vencimiento","Solo en la fecha de vencimiento o después de ella"],"explanation":"El ORC 4506.14 establece que una CDL es renovable a partir de los 180 días previos a su vencimiento, tras el pago de las tarifas requeridas. Fuente: Ohio Revised Code 4506.14."},"93":{"q":"El registrador de Ohio puede eximir el examen de renovación de un titular de CDL solo si el solicitante presenta una CDL que no esté vencida o que haya vencido hace no más de cuánto tiempo antes de la fecha de solicitud?","options":["Seis meses","Un mes","Tres meses","Un año"],"explanation":"El ORC 4506.14 permite que el registrador exima el examen de renovación si el solicitante presenta una CDL no vencida, o una que haya vencido hace no más de seis meses antes de la fecha de solicitud. Pasado ese periodo de gracia, por lo general se requiere volver a presentar el examen. Fuente: Ohio Revised Code 4506.14."},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL de Ohio restringida al manejo INTRAESTATAL (solo dentro de Ohio)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Ohio fija la edad mínima de CDL en 18 años para la operación solo intraestatal; los conductores menores de 21 años están restringidos a conducir dentro de Ohio. La operación interestatal y el transporte de materiales peligrosos requieren tener 21 años. Fuente: requisitos de CDL del Ohio BMV."},"95":{"q":"Un solicitante de Ohio debe tener al menos qué edad para conducir un vehículo motorizado comercial en el comercio INTERESTATAL o para transportar materiales peligrosos?","options":["21 años","18 años","23 años","25 años"],"explanation":"La regla federal aplicada en Ohio exige que un conductor tenga al menos 21 años para operar en el comercio interestatal o para transportar materiales peligrosos con rótulos (placards). Los conductores de 18 a 20 años están limitados al manejo intraestatal. Fuente: requisitos de CDL del Ohio BMV / 49 CFR 391.11."},"96":{"q":"Además de una licencia de conducir válida de Ohio y comprobante del número de Seguro Social, ¿qué más debe presentar un solicitante de CDL de Ohio por primera vez?","options":["Comprobante de ciudadanía estadounidense o residencia permanente legal","Una carta notariada de un empleador actual","Un diploma de preparatoria o certificado GED","Dos referencias personales que posean CDL"],"explanation":"Ohio exige que los solicitantes de CDL por primera vez proporcionen una licencia de conducir válida de Ohio, un número de Seguro Social válido y comprobante de ciudadanía estadounidense o residencia permanente legal (por ejemplo, pasaporte, acta de nacimiento o tarjeta de residente permanente). Fuente: Ohio BMV, página de Commercial Driver (CDL)."},"97":{"q":"Un conductor de Ohio se autocertifica como 'Interestatal Exento'. ¿Qué indica esta categoría sobre sus requisitos médicos federales?","options":["Conduce cruzando líneas estatales pero NO está obligado a cumplir con los estándares médicos federales (Part 391)","Conduce solo dentro de Ohio y debe cumplir con los estándares médicos estatales","Siempre debe portar un certificado de examinador médico federal","Nunca usa la CDL para ningún fin comercial"],"explanation":"Interestatal Exento significa que el conductor opera cruzando líneas estatales pero califica para una exención de los requisitos federales de calificación física de 49 CFR Part 391, por lo que no se requiere una tarjeta médica DOT para esa operación. Fuente: categorías de autocertificación del Ohio BMV (formulario BMV 2159)."},"98":{"q":"Al presentar el examen de habilidades de la CDL de Ohio, ¿quién es generalmente responsable de proporcionar el vehículo comercial usado para el examen?","options":["El solicitante, que debe proporcionar (o rentar) un vehículo representativo de la clase solicitada","El BMV de Ohio, que mantiene una flota de vehículos de prueba","ODOT, que presta vehículos para los exámenes de manejo","La oficina regional de la FMCSA"],"explanation":"Ohio exige que el solicitante proporcione un vehículo comercial apropiado y representativo de la clase que se examina, o que rente uno (a menudo a través de un sitio de pruebas externo). El BMV no proporciona vehículos de prueba. Fuente: Ohio BMV, página de Commercial Driver (CDL)."}},"hi":{"0":{"q":"ओहायो के राजमार्गों पर, विशेष ढुलाई परमिट के बिना किसी वाहन की, उसके लदान सहित, अधिकतम कानूनी चौड़ाई कितनी होती है?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","8 feet 2 inches (98 inches)"],"explanation":"Ohio Revised Code 5577.05 वाहन की अधिकतम चौड़ाई लदान सहित 102 inches (8 feet 6 inches) निर्धारित करता है। इससे अधिक चौड़ाई के लिए ODOT का विशेष ढुलाई परमिट आवश्यक है।"},"1":{"q":"ओहायो के राजमार्गों पर परमिट के बिना किसी वाहन और लदान की अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","14 feet 6 inches"],"explanation":"Ohio Revised Code 5577.05 के अनुसार, लदान के साथ या बिना अधिकतम ऊँचाई 13 feet 6 inches (13.5 feet) है। ओवरपास और संरचनाओं के नीचे से सुरक्षित निकलने की ज़िम्मेदारी चालक की होती है।"},"2":{"q":"ओहायो में, ट्रैक्टर-सेमीट्रेलर संयोजन में चलाए जाने वाले सेमीट्रेलर की परमिट के बिना अधिकतम लंबाई कितनी होती है?","options":["48 feet","53 feet","57 feet","45 feet"],"explanation":"Ohio Revised Code 5577.05 वाणिज्यिक ट्रैक्टर-सेमीट्रेलर संयोजन में चलाए जाने पर सेमीट्रेलर को 53 feet तक लंबा होने की अनुमति देता है, जो संघीय राष्ट्रीय नेटवर्क मानक के अनुरूप है।"},"3":{"q":"ओहायो के राजमार्गों पर विशेष ढुलाई परमिट के बिना किसी वाहन और लदान का अधिकतम सकल वजन कितना हो सकता है?","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"Ohio Revised Code 5577.04 सड़क की सतह पर पड़ने वाले अधिकतम कुल सकल वजन को 80,000 pounds तक सीमित करता है, जो संघीय Interstate सीमा के समान है।"},"4":{"q":"ओहायो कानून के तहत, किसी वाहन के किसी एकल एक्सल पर वजन कितनी मात्रा से अधिक नहीं हो सकता?","options":["18,000 pounds","22,400 pounds","20,000 pounds","24,000 pounds"],"explanation":"Ohio Revised Code 5577.04 अधिकतम एकल एक्सल वजन को 20,000 pounds तक सीमित करता है, जो संघीय एकल-एक्सल मानक से मेल खाता है।"},"5":{"q":"ओहायो के इंटरस्टेट सिस्टम पर टैंडम एक्सल समूह पर अनुमत अधिकतम वजन कितना होता है?","options":["32,000 pounds","36,000 pounds","38,000 pounds","34,000 pounds"],"explanation":"Ohio Revised Code 5577.04 अधिकतम टैंडम एक्सल वजन को 34,000 pounds निर्धारित करता है, जो संघीय टैंडम-एक्सल सीमा के अनुरूप है।"},"6":{"q":"ओहायो के राजमार्गों पर परमिट के बिना बस या मनोरंजन वाहन के अलावा किसी एकल (गैर-ट्रेलर) वाहन की अधिकतम लंबाई कितनी होती है?","options":["40 feet","50 feet","45 feet","53 feet"],"explanation":"Ohio Revised Code 5577.05 किसी एकल वाहन (बसों जैसे विशेष रूप से सूचीबद्ध वाहनों के अलावा) को लंबाई में 50 feet तक सीमित करता है।"},"7":{"q":"ओहायो की कौन-सी राज्य एजेंसी राज्य, संघीय और इंटरस्टेट राजमार्गों पर यात्रा के लिए ओवरसाइज़/ओवरवेट विशेष ढुलाई परमिट जारी करती है?","options":["The Ohio Bureau of Motor Vehicles (BMV)","The Ohio State Highway Patrol","The Public Utilities Commission of Ohio (PUCO)","The Ohio Department of Transportation (ODOT)"],"explanation":"The Ohio Department of Transportation (ODOT) विशेष ढुलाई परमिट जारी करता है, जिनकी प्रक्रिया Ohio Hauling Permit System (ODOT Special Hauling Permits) के माध्यम से इलेक्ट्रॉनिक रूप से की जाती है।"},"8":{"q":"ओहायो के राजमार्गों पर ट्रैक्टर-सेमीट्रेलर-ट्रेलर (डबल) संयोजन में, परमिट के बिना प्रत्येक सेमीट्रेलर या ट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["28 feet 6 inches","33 feet","27 feet","30 feet"],"explanation":"Ohio Revised Code 5577.05 वाणिज्यिक ट्रैक्टर-सेमीट्रेलर-ट्रेलर या ट्रैक्टर-सेमीट्रेलर-सेमीट्रेलर संयोजन में चलाए जाने पर प्रत्येक सेमीट्रेलर या ट्रेलर को 28 feet 6 inches तक सीमित करता है।"},"9":{"q":"ओहायो के किसी राजमार्ग पर एक ट्रक संयोजन कानूनी सीमा से अधिक भारी है। यात्रा करने से पहले संचालक को किस प्रकार का परमिट प्राप्त करना होगा?","options":["CDL पर एक वाइड-लोड एंडोर्समेंट","एक ODOT विशेष ढुलाई परमिट","एक संघीय FMCSA ओवरवेट छूट","एक काउंटी द्वारा जारी रोड बॉन्ड प्रमाणपत्र"],"explanation":"ODOT के अनुसार, ओहायो की कानूनी आकार या वजन सीमा से अधिक किसी भी वाहन या लदान को राज्य, संघीय, या इंटरस्टेट राजमार्गों पर चलाने से पहले ODOT से एक विशेष ढुलाई परमिट प्राप्त करना होगा।"},"10":{"q":"ओहायो के राजमार्गों पर, वाहनों के उन संयोजनों के लिए अधिकतम लंबाई कितनी होती है जिनके लिए अन्यथा विशेष रूप से कोई प्रावधान नहीं किया गया है (जैसे, एक सामान्य ट्रैक्टर-सेमीट्रेलर-ट्रेलर संयोजन)?","options":["60 feet","75 feet","65 feet","70 feet"],"explanation":"Ohio Revised Code 5577.05 वाहनों के किसी भी अन्य संयोजन के लिए, जिसका अन्यथा उल्लेख नहीं किया गया है, अधिकतम 65 feet निर्धारित करता है।"},"11":{"q":"बहु-एक्सल समूहों के लिए ओहायो कानून में अपनाया गया संघीय ब्रिज फॉर्मूला W = 500((LN/(N-1)) + 12N + 36) है। इस फॉर्मूले में, 'L' किसका प्रतिनिधित्व करता है?","options":["पुल की कानूनी लोड रेटिंग","समूह के अंतिम सिरों वाले (पहले और आखिरी) एक्सल के बीच की दूरी feet में","संयोजन में सबसे लंबे ट्रेलर की लंबाई","वाहन का कुल लाइसेंसीकृत सकल वजन"],"explanation":"Ohio Revised Code 5577.04(C) में बताए गए ब्रिज फॉर्मूले में, L समूह के अगले और सबसे पीछे वाले एक्सल के बीच की दूरी feet में है, N एक्सल की संख्या है, और W अधिकतम अनुमेय सकल वजन है।"},"12":{"q":"ओहायो के विशेष वजन प्रावधानों के तहत, उत्पादन स्थल से पहले वितरण बिंदु तक ढुलाई करते समय कोई पात्र फार्म, लॉग, कोयला, या ठोस-अपशिष्ट ट्रक सामान्य वजन सीमाओं को कितने प्रतिशत तक पार कर सकता है?","options":["5 percent","10 percent","7.5 percent","12.5 percent"],"explanation":"Ohio Revised Code 5577.042 पात्र फार्म, लॉग, कोयला, और ठोस-अपशिष्ट ढुलाई वाहनों को वर्णित शर्तों के तहत वजन प्रावधानों को 7.5 percent से अधिक नहीं पार करने की अनुमति देता है।"},"13":{"q":"किन महीनों के दौरान ओहायो का फार्म ट्रकों, लॉग ट्रकों, और फार्म मशीनरी के लिए 7.5 percent वजन छूट लागू नहीं होता?","options":["February और March","January और February","March और April","November और December"],"explanation":"Ohio Revised Code 5577.042 निर्दिष्ट करता है कि 7.5 percent छूट फार्म ट्रकों, लॉग ट्रकों, या फार्म मशीनरी के लिए February और March के दौरान लागू नहीं होती (मौसमी पाला/पिघलने की अवधि)।"},"14":{"q":"ORC 5577.042 के तहत ओहायो की 7.5 percent कृषि/वन-उत्पाद वजन छूट किन सड़कमार्गों पर लागू नहीं होती?","options":["काउंटी रोड","इंटरस्टेट राजमार्ग","टाउनशिप रोड","नगरपालिका सड़कें"],"explanation":"Ohio Revised Code 5577.042 कहता है कि 7.5 percent छूट इंटरस्टेट राजमार्गों पर (या विशेष रूप से कम किए गए अधिकतम वजन वाली सड़कों पर) लागू नहीं होती।"},"15":{"q":"ODOT नियमों के तहत, किसी लदान को 'सुपरलोड' के रूप में वर्गीकृत किया जाता है जब उसका सकल वजन किस मात्रा से अधिक हो?","options":["80,000 pounds","100,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"ODOT के Operational Guide के अनुसार, सुपरलोड कोई भी ऐसा वाहन/लदान है जिसका सकल वजन 120,000 pounds से अधिक हो (या चौड़ाई 14 feet से अधिक या ऊँचाई 14 feet 6 inches से अधिक हो), जिसके लिए पुल/संरचनात्मक विश्लेषण जैसी अतिरिक्त समीक्षा आवश्यक होती है।"},"16":{"q":"ओहायो के गैर-इंटरस्टेट (सामान्य राजमार्ग) सिस्टम पर, 4 feet से अधिक दूरी पर रखे गए दो क्रमिक एक्सल 34,000 pounds और प्रत्येक अतिरिक्त foot के लिए 1,000 pounds तक ले जा सकते हैं, लेकिन किस अधिकतम सीमा से अधिक नहीं?","options":["38,000 pounds","42,000 pounds","44,000 pounds","40,000 pounds"],"explanation":"Ohio Revised Code 5577.04 प्रावधान करता है कि गैर-इंटरस्टेट सिस्टम पर, 4 feet से अधिक दूरी पर रखे गए दो क्रमिक एक्सल 34,000 pounds और 4 feet से ऊपर प्रत्येक foot के लिए 1,000 pounds तक ले जा सकते हैं, अधिकतम 40,000 pounds तक।"},"17":{"q":"ODOT एस्कॉर्ट नियमों के अनुसार, किसी दो-लेन ओहायो राजमार्ग पर किस आयाम से अधिक चौड़े वाहन/लदान के लिए एक अग्रणी (आगे का) एस्कॉर्ट वाहन आवश्यक होता है?","options":["12 feet","13 feet","11 feet","10 feet"],"explanation":"ODOT की परमिट एस्कॉर्ट आवश्यकताओं के अनुसार, 13 feet से अधिक कुल चौड़ाई वाले किसी भी वाहन/लदान के लिए एक अग्रणी एस्कॉर्ट आवश्यक होता है; 14 feet 6 inches से अधिक चौड़े लदान के लिए एक अग्रणी और एक पिछला दोनों एस्कॉर्ट आवश्यक होते हैं।"},"18":{"q":"ODOT परमिट नियमों के तहत, 12 feet से कम चौड़े किसी ओवरसाइज़ लदान को आम तौर पर किस दैनिक समय-सीमा के दौरान यात्रा करने की अनुमति होती है?","options":["केवल 9:00 a.m. और 3:00 p.m. के बीच","सूर्योदय से 30 minutes पहले से सूर्यास्त के 30 minutes बाद तक","सूर्योदय के एक घंटे बाद से सूर्यास्त के एक घंटे पहले तक","केवल पूर्ण दिन के उजाले के घंटों के दौरान, सूर्योदय से सूर्यास्त तक"],"explanation":"ODOT के अनुसार, 12 feet से कम चौड़े ओवरसाइज़ लदान सप्ताह में सातों दिन (छुट्टियों को छोड़कर) सूर्योदय से 30 minutes पहले से सूर्यास्त के 30 minutes बाद तक यात्रा कर सकते हैं; 12 feet चौड़े या उससे अधिक चौड़े लदान को परमिट पर बताए गए विशिष्ट समय का पालन करना होगा।"},"19":{"q":"ओहायो के इंटरस्टेट सिस्टम पर, टैंडम एक्सल के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं, बशर्ते दोनों सेटों के पहले और आखिरी एक्सल के बीच की दूरी कम से कम कितने feet हो?","options":["30 feet","40 feet","36 feet","34 feet"],"explanation":"Ohio Revised Code 5577.04 टैंडम एक्सल के दो लगातार सेटों को प्रत्येक 34,000 pounds ले जाने की अनुमति केवल तभी देता है जब लगातार सेटों के पहले और आखिरी एक्सल के बीच की कुल दूरी 36 feet या उससे अधिक हो।"},"20":{"q":"ओहायो में, 26,001 pounds या उससे अधिक की Gross Combination Weight Rating (GCWR) वाले वाहनों के संयोजन को चलाने के लिए कौन-सा CDL वर्ग आवश्यक होता है, बशर्ते खींचे जा रहे यूनिट का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"ओहायो का Class A CDL उन संयोजन वाहनों को कवर करता है जिनका GCWR 26,001 lbs या उससे अधिक है, जहाँ खींचे जा रहे यूनिट का GVWR 10,000 lbs से अधिक हो। स्रोत: Ohio BMV CDL Classes पृष्ठ (bmv.ohio.gov/dl-cdl-classes.aspx) और ओहायो में अपनाया गया 49 CFR 383.91।"},"21":{"q":"एक ओहायो चालक एक एकल सीधा ट्रक चलाता है जिसका GVWR 30,000 pounds है और जो 10,000 pounds से अधिक के किसी ट्रेलर को नहीं खींचता। कौन-सा CDL वर्ग उपयुक्त है?","options":["Class A","Class B","Class C","Class E"],"explanation":"ओहायो का Class B CDL 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल वाहन को कवर करता है, और 10,000 lbs GVWR से अधिक न होने वाले ट्रेलर को खींच सकता है। स्रोत: Ohio BMV CDL Classes पृष्ठ (bmv.ohio.gov/dl-cdl-classes.aspx)।"},"22":{"q":"ओहायो नियमों के तहत, ऐसा वाहन जो Class A या B के वजन सीमा को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (चालक सहित) या प्लेकार्ड आवश्यकता वाली खतरनाक सामग्री को ले जाने के लिए डिज़ाइन किया गया है, किस CDL वर्ग में आता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"ओहायो का Class C CDL उन वाहनों पर लागू होता है जो Class A/B वजन सीमा से कम हैं लेकिन 16+ व्यक्तियों (चालक सहित) या प्लेकार्ड योग्य खतरनाक सामग्री ले जाते हैं। स्रोत: Ohio BMV CDL Classes पृष्ठ (bmv.ohio.gov/dl-cdl-classes.aspx)।"},"23":{"q":"केवल INTRASTATE (ओहायो के भीतर) वाणिज्यिक ड्राइविंग तक सीमित ओहायो CDL जारी किए जाने के लिए न्यूनतम आयु क्या है?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"ओहायो 18 वर्ष की आयु से केवल-इंट्रास्टेट CDL जारी करता है; 21 वर्ष से कम आयु के चालक ओहायो के भीतर ही वाणिज्य तक सीमित होते हैं। स्रोत: Ohio BMV CDL पात्रता (bmv.ohio.gov) और ORC 4506.10।"},"24":{"q":"ओहायो CDL पर INTERSTATE वाणिज्य में एक वाणिज्यिक मोटर वाहन चलाने के लिए न्यूनतम आयु क्या आवश्यक है?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"इंटरस्टेट वाणिज्यिक ड्राइविंग के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। 18-20 आयु के ओहायो चालक केवल-इंट्रास्टेट CDL रखते हैं। स्रोत: Ohio BMV CDL पात्रता और 49 CFR 391.11।"},"25":{"q":"ऐसी मात्रा में खतरनाक सामग्री का परिवहन करने के लिए जिसके लिए वाहन का प्लेकार्ड लगाना आवश्यक हो, ओहायो CDL पर कौन-सा एंडोर्समेंट अक्षर आवश्यक होता है?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement X"],"explanation":"H (HazMat) एंडोर्समेंट प्लेकार्ड योग्य खतरनाक सामग्री के परिवहन को अधिकृत करता है। स्रोत: Ohio BMV CDL Classes/एंडोर्समेंट पृष्ठ और 49 CFR 383.93।"},"26":{"q":"एक ओहायो चालक जो स्थायी रूप से लगे टैंक में तरल पदार्थ या गैसों को थोक में ढोता है, उसे कौन-सा एंडोर्समेंट रखना होगा?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement S"],"explanation":"थोक में तरल या गैसीय सामग्री ले जाने वाले टैंक वाहन को चलाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: Ohio BMV एंडोर्समेंट जानकारी और 49 CFR 383.93।"},"27":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन-सा ओहायो CDL एंडोर्समेंट आवश्यक होता है?","options":["Endorsement P","Endorsement S","Endorsement T","Endorsement D"],"explanation":"T एंडोर्समेंट डबल/ट्रिपल ट्रेलर संयोजनों के संचालन को अधिकृत करता है और doubles/triples ज्ञान परीक्षा पास करके प्राप्त किया जाता है। स्रोत: Ohio BMV एंडोर्समेंट जानकारी और 49 CFR 383.93।"},"28":{"q":"चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाणिज्यिक वाहन (स्कूल बस के अलावा) को चलाने के लिए किसी ओहायो CDL धारक को कौन-सा एंडोर्समेंट चाहिए?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: Ohio BMV एंडोर्समेंट जानकारी और 49 CFR 383.93।"},"29":{"q":"ओहायो में, किसी चालक को School Bus (S) एंडोर्समेंट जारी किए जाने से पहले, उसे कौन-सा अन्य एंडोर्समेंट भी प्राप्त करना होगा?","options":["H (HazMat) एंडोर्समेंट","N (Tanker) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","T (Doubles/Triples) एंडोर्समेंट"],"explanation":"संघीय और ओहायो नियमों के लिए S (School Bus) एंडोर्समेंट को P (Passenger) एंडोर्समेंट के साथ जोड़ना आवश्यक है, क्योंकि एक स्कूल बस यात्रियों को ले जाती है। स्रोत: Ohio BMV एंडोर्समेंट जानकारी और 49 CFR 383.93।"},"30":{"q":"HazMat (H) एंडोर्समेंट दिए जाने से पहले, एक ओहायो CDL आवेदक को लिखित HazMat ज्ञान परीक्षा के अतिरिक्त कौन-सी स्क्रीनिंग पास करनी होगी?","options":["फिंगरप्रिंटिंग सहित एक TSA सुरक्षा खतरा आकलन","एक टैंक वाहन में दूसरी रोड स्किल्स परीक्षा","BMV द्वारा आयोजित एक नेत्र परीक्षा","एक डिफेंसिव-ड्राइविंग कक्षा पाठ्यक्रम"],"explanation":"HazMat एंडोर्समेंट के लिए ज्ञान परीक्षा के अतिरिक्त फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच के साथ एक Transportation Security Administration (TSA) सुरक्षा खतरा आकलन आवश्यक है। स्रोत: Ohio BMV HazMat जानकारी और 49 CFR 1572।"},"31":{"q":"किसी चालक को CDL स्किल्स (रोड) परीक्षा देने की अनुमति मिलने से पहले एक ओहायो Commercial Learner's Permit (CLP) प्राप्त करना और उसे न्यूनतम अवधि तक रखना होगा। वह न्यूनतम धारण अवधि क्या है?","options":["7 days","14 days","30 days","60 days"],"explanation":"ओहायो द्वारा अपनाए गए संघीय नियम के अनुसार आवेदक के CDL स्किल्स परीक्षा देने से पहले CLP को कम से कम 14 days तक रखा जाना आवश्यक है। स्रोत: Ohio BMV CDL प्रक्रिया और 49 CFR 383.25।"},"32":{"q":"किसी ओहायो Commercial Learner's Permit (CLP) पर वाणिज्यिक वाहन चलाते समय, परमिट धारक के साथ क्या होना चाहिए?","options":["25 वर्ष या उससे अधिक आयु का कोई भी लाइसेंस प्राप्त चालक","उचित वर्ग/एंडोर्समेंट वाला एक CDL धारक जो उनके बगल में बैठा हो","केवल एक BMV परीक्षक","कोई नहीं, यदि दिन के उजाले के घंटों में चला रहा हो"],"explanation":"एक CLP धारक किसी CMV को केवल तभी चला सकता है जब उसके साथ ऐसा व्यक्ति हो जो उपयुक्त वर्ग और एंडोर्समेंट का वैध CDL रखता हो और CLP धारक के बगल में बैठा हो। स्रोत: Ohio BMV CLP नियम और 49 CFR 383.25।"},"33":{"q":"February 7, 2022 से, ओहायो में पहली बार Class A CDL प्राप्त करने वाले व्यक्ति को ऐसी संस्था द्वारा प्रदान किया गया Entry-Level Driver Training (ELDT) पूरा करना होगा जो क्या है?","options":["FMCSA Training Provider Registry पर सूचीबद्ध","Ohio Department of Education द्वारा मान्यता प्राप्त","केवल स्थानीय डिप्टी रजिस्ट्रार द्वारा अनुमोदित","Ohio State Highway Patrol द्वारा प्रमाणित"],"explanation":"ELDT FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रदाता द्वारा दिया जाना चाहिए, और स्किल्स/ज्ञान परीक्षा से पहले प्रमाणन रजिस्ट्री में होना चाहिए। स्रोत: FMCSA ELDT नियम (49 CFR 380 subpart F) और tpr.fmcsa.dot.gov।"},"34":{"q":"निम्नलिखित में से कौन-सी पहली बार की कार्रवाई संघीय Entry-Level Driver Training (ELDT) आवश्यकता को ट्रिगर नहीं करती?","options":["पहली बार Class A CDL प्राप्त करना","पहली बार Passenger (P) एंडोर्समेंट प्राप्त करना","पहली बार Tanker (N) एंडोर्समेंट प्राप्त करना","पहली बार HazMat (H) एंडोर्समेंट प्राप्त करना"],"explanation":"ELDT पहली बार के Class A/B CDL, B से A अपग्रेड, और पहली बार के P, S, और H एंडोर्समेंट पर लागू होता है। N (Tanker) और T (Doubles/Triples) एंडोर्समेंट ELDT द्वारा कवर नहीं किए जाते। स्रोत: FMCSA ELDT प्रयोज्यता (tpr.fmcsa.dot.gov/Drivers/Applicability)।"},"35":{"q":"ELDT आवश्यकता उन व्यक्तियों पर लागू होती है जो अपना Commercial Learner's Permit किस तारीख को या उसके बाद प्राप्त करते हैं?","options":["February 7, 2020","February 7, 2022","January 30, 2021","December 31, 2023"],"explanation":"Entry-Level Driver Training आवश्यकताएँ उन चालकों पर लागू होती हैं जो February 7, 2022 को या उसके बाद CLP प्राप्त करते हैं। स्रोत: FMCSA ELDT नियम और tpr.fmcsa.dot.gov।"},"36":{"q":"ओहायो CDL स्व-प्रमाणन फॉर्म पर, कौन-सी श्रेणी ऐसे चालक का वर्णन करती है जो राज्य की सीमाओं के पार संचालन करता है और जिसे संघीय DOT फिज़िकल (मेडिकल कार्ड) आवश्यकताओं को पूरा करना होगा?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Non-Excepted Interstate चालक इंटरस्टेट वाणिज्य में संचालन करते हैं और उन्हें संघीय मेडिकल (Part 391) मानकों को पूरा करना होगा, और एक Medical Examiner's Certificate प्रदान करना होगा। स्रोत: Ohio BMV फॉर्म BMV 2159 (CDL Self-Certification) और 49 CFR 383.71।"},"37":{"q":"पात्रता साबित करने के लिए पहली बार के ओहायो CDL आवेदक को BMV को कौन-से दस्तावेज़ प्रस्तुत करने होंगे?","options":["पहचान/वैध उपस्थिति का प्रमाण, पूरा Social Security number, और ओहायो निवास","केवल एक वर्तमान ओहायो ड्राइवर लाइसेंस और एक क्रेडिट कार्ड","एक पासपोर्ट और दो उपयोगिता बिल, लेकिन कोई Social Security number नहीं","केवल एक वाहन शीर्षक और बीमा का प्रमाण"],"explanation":"ओहायो को पहचान और वैध उपस्थिति का दस्तावेज़ीकरण (जैसे, जन्म प्रमाणपत्र, पासपोर्ट, या स्थायी निवासी कार्ड), Social Security number, और ओहायो निवास का प्रमाण चाहिए। स्रोत: Ohio BMV CDL दस्तावेज़ आवश्यकताएँ (bmv.ohio.gov)।"},"38":{"q":"एक 19 वर्षीय ओहायो चालक प्लेकार्ड योग्य खतरनाक सामग्री ढोने के लिए CDL चाहता है। यह चालक HazMat (H) एंडोर्समेंट क्यों प्राप्त नहीं कर सकता?","options":["HazMat परिवहन के लिए कम से कम 21 वर्ष का होना आवश्यक है","HazMat एंडोर्समेंट केवल Class C चालकों को जारी किए जाते हैं","ओहायो HazMat एंडोर्समेंट प्रदान नहीं करता","पहले एक tanker (N) एंडोर्समेंट प्राप्त करना होगा"],"explanation":"प्लेकार्ड लगी खतरनाक सामग्री ढोना इंटरस्टेट-सक्षम है और इसके लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है; ओहायो के 18-20 इंट्रास्टेट CDL धारक H एंडोर्समेंट नहीं रख सकते। स्रोत: Ohio BMV CDL पात्रता और 49 CFR 383.93/391.11।"},"39":{"q":"ओहायो में, किसी वाणिज्यिक मोटर वाहन (CMV) को चलाते समय CDL उद्देश्यों के लिए कानूनी रूप से अक्षम माने जाने से पहले किसी चालक का अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितना हो सकता है?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"ओहायो संघीय CMV मानक का पालन करता है: 0.04 percent या उससे अधिक BAC के साथ वाणिज्यिक मोटर वाहन चलाना एक प्रमुख अपराध है। यह सीमा गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा की आधी है। स्रोत: Ohio CDL Manual / Ohio BMV CDL Disqualifications; ORC 4506.15; 49 CFR 383.51।"},"40":{"q":"ओहायो CDL प्राप्त करने और उसका उपयोग करने से, एक चालक को अल्कोहल या ड्रग सामग्री निर्धारित करने के लिए साँस, रक्त, या मूत्र की रासायनिक जाँच के लिए सहमति दे चुका माना जाता है। इस कानूनी सिद्धांत को क्या कहते हैं?","options":["Implied consent (अंतर्निहित सहमति)","Probable cause (संभावित कारण)","Due process consent","Conditional licensing"],"explanation":"ओहायो के implied-consent कानून का अर्थ है कि ओहायो की सड़कों पर वाहन चलाना अल्कोहल/ड्रग अपराध के लिए कानूनी रूप से गिरफ्तार किए जाने पर रासायनिक जाँच की सहमति का गठन करता है। इनकार के अपने प्रशासनिक दंड होते हैं। स्रोत: ORC 4511.191; Ohio CDL Manual।"},"41":{"q":"ओहायो में, प्लेकार्ड लगी खतरनाक सामग्री न ले जाते समय किसी चालक के पहले प्रमुख अपराध, जैसे CMV में 0.04+ BAC या रासायनिक जाँच से इनकार, के लिए न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["1 year","60 days","6 months","3 years"],"explanation":"पहला प्रमुख अपराध (0.04+ BAC, OVI, जाँच से इनकार, घटनास्थल छोड़ना, अपराध में CMV का उपयोग, आदि) ओहायो में 1-year CDL अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"42":{"q":"यदि कोई ओहायो चालक खतरनाक सामग्री के लिए प्लेकार्ड लगे CMV को चलाते समय पहला प्रमुख अपराध (जैसे 0.04+ BAC) करता है, तो अयोग्यता अवधि बढ़ाकर कितनी कर दी जाती है:","options":["3 years","1 year","5 years","आजीवन"],"explanation":"जब पहला प्रमुख अपराध खतरनाक सामग्री के लिए प्लेकार्ड लगे वाहन में होता है, तो मानक 1-year अयोग्यता बढ़ाकर 3 years कर दी जाती है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"43":{"q":"ओहायो में किसी दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरा OVI या CMV में दूसरा 0.04+ BAC) के लिए CDL अयोग्यता अवधि क्या है?","options":["आजीवन","10 years","3 years","5 years"],"explanation":"किसी भी प्रमुख अपराध की दूसरी दोषसिद्धि ओहायो में आजीवन CDL अयोग्यता का परिणाम देती है। कुछ आजीवन अयोग्यताओं को पुनर्स्थापना शर्तों को पूरा करने के बाद 10 years तक घटाया जा सकता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"44":{"q":"OVI के लिए कानूनी रूप से गिरफ्तार किया गया एक ओहायो चालक रासायनिक साँस जाँच कराने से इनकार कर देता है। CDL उद्देश्यों के लिए, जाँच से इनकार करने पर कम से कम कितनी अयोग्यता होती है:","options":["1 year","90 days","60 days","30 days"],"explanation":"जाँच से इनकार को CDL उद्देश्यों के लिए एक प्रमुख अपराध माना जाता है, जिसमें किसी भी प्रशासनिक लाइसेंस निलंबन के अतिरिक्त 1-year अयोग्यता (यदि प्लेकार्ड लगी खतरनाक सामग्री ढो रहा हो तो 3 years) होती है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"45":{"q":"ओहायो के implied-consent कानून के तहत, एक CDL धारक जो रासायनिक जाँच से इनकार करता है उसे एक प्रशासनिक लाइसेंस निलंबन का भी सामना करना पड़ता है। पहले इनकार के लिए, यह प्रशासनिक निलंबन आम तौर पर है:","options":["1 year","90 days","6 months","2 years"],"explanation":"ओहायो का implied-consent क़ानून पहले रासायनिक-जाँच इनकार के लिए 1-year प्रशासनिक लाइसेंस निलंबन लगाता है, 10 years के भीतर बार-बार इनकार के लिए लंबी अवधि के साथ। यह CDL अयोग्यता से अलग है। स्रोत: ORC 4511.191।"},"46":{"q":"ओहायो में, 3-year अवधि के भीतर अलग-अलग घटनाओं में कितने गंभीर यातायात उल्लंघन 60-day CDL अयोग्यता को ट्रिगर करते हैं?","options":["2","3","4","5"],"explanation":"3 years के भीतर 2 गंभीर यातायात उल्लंघनों (CMV में) की दोषसिद्धि 60-day अयोग्यता का परिणाम देती है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"47":{"q":"एक ओहायो CDL धारक को 3-year अवधि के भीतर अलग-अलग घटनाओं में तीन गंभीर यातायात उल्लंघनों का दोषी ठहराया जाता है। CDL अयोग्यता अवधि क्या है?","options":["120 days","60 days","90 days","1 year"],"explanation":"3 years के भीतर 3 या अधिक गंभीर यातायात उल्लंघनों की दोषसिद्धि 120-day अयोग्यता का परिणाम देती है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"48":{"q":"ओहायो में किसी अपराध को गंभीर यातायात उल्लंघन के रूप में गिने जाने के लिए एक CDL चालक को पोस्ट की गई गति सीमा से कितना अधिक चालान किया जाना चाहिए?","options":["सीमा से 15 mph या अधिक ऊपर","सीमा से 10 mph या अधिक ऊपर","सीमा से 20 mph या अधिक ऊपर","सीमा से 5 mph या अधिक ऊपर"],"explanation":"पोस्ट की गई सीमा से 15 mph या अधिक ऊपर गति करना CDL धारकों के लिए एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत है। स्रोत: Ohio CDL Manual; ORC 4506.01/4506.16; 49 CFR 383.51।"},"49":{"q":"निम्नलिखित में से किसे एक ओहायो CDL धारक के लिए गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया जाता है?","options":["बहुत पास से चलना (टेलगेटिंग)","नो-पार्किंग ज़ोन में पार्क करना","एक बिना रोशनी वाला लाइसेंस प्लेट लैंप","पहला ओवरवेट लोड चालान"],"explanation":"गंभीर यातायात उल्लंघनों में बहुत पास से चलना, लापरवाह/अनियमित लेन परिवर्तन, 15+ mph ऊपर गति करना, ड्राइविंग के दौरान टेक्स्टिंग, और उचित वर्ग/एंडोर्समेंट के बिना CMV चलाना शामिल हैं। उपकरण और पार्किंग अपराध गंभीर उल्लंघन नहीं हैं। स्रोत: Ohio CDL Manual; 49 CFR 383.51।"},"50":{"q":"ओहायो में, किसी CMV को चलाते समय हाथ में पकड़े मोबाइल फोन का उपयोग करना या टेक्स्टिंग करना निषिद्ध है। CDL उद्देश्यों के लिए, ऐसी दोषसिद्धि को किस रूप में गिना जाता है:","options":["गंभीर यातायात उल्लंघन","प्रमुख अपराध","आउट-ऑफ-सर्विस उल्लंघन","गैर-रिकॉर्ड करने योग्य उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग या हाथ में पकड़े फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है; 3 years के भीतर दो उल्लंघन 60-day अयोग्यता लाते हैं, तीन 120 days लाते हैं। स्रोत: Ohio CDL Manual; 49 CFR 383.51 और 392.80/392.82।"},"51":{"q":"किसी वाणिज्यिक वाहन को चलाते समय टेक्स्टिंग करने वाले CMV चालक के लिए अधिकतम संघीय चालक नागरिक दंड (ओहायो में लागू) क्या है?","options":["$2,750 तक","$500 तक","$1,000 तक","$11,000 तक"],"explanation":"ड्राइविंग के दौरान टेक्स्टिंग करने वाले एक CMV चालक को $2,750 तक का संघीय नागरिक दंड का सामना करना पड़ता है; इसकी अनुमति देने वाले मोटर वाहक पर $11,000 तक का जुर्माना लगाया जा सकता है। ये नियम ओहायो में लागू होते हैं। स्रोत: 49 CFR 392.80; FMCSA No-Texting Rule।"},"52":{"q":"एक ओहायो CDL धारक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन (जैसे आवश्यक स्थान पर रुकने में विफल होना) करता है। अयोग्यता अवधि क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 60-day CDL अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"53":{"q":"3-year अवधि के भीतर दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए ओहायो में CDL अयोग्यता अवधि क्या है?","options":["120 days","60 days","180 days","1 year"],"explanation":"3 years के भीतर दूसरा रेलमार्ग-ग्रेड-क्रॉसिंग उल्लंघन 120-day अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"54":{"q":"एक ओहायो CDL धारक 3-year अवधि के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता अवधि है:","options":["1 year","120 days","180 days","2 years"],"explanation":"3 years के भीतर तीसरा या उसके बाद का रेलमार्ग-ग्रेड-क्रॉसिंग उल्लंघन 1-year (365-day) अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"55":{"q":"किसी आउट-ऑफ-सर्विस (OOS) आदेश का उल्लंघन करने की किसी चालक की पहली दोषसिद्धि के लिए ओहायो में CDL अयोग्यता अवधि क्या है?","options":["180 days","60 days","1 year","90 days"],"explanation":"किसी आउट-ऑफ-सर्विस आदेश का उल्लंघन करने की पहली दोषसिद्धि कम से कम 180 days की अयोग्यता का परिणाम देती है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"56":{"q":"ओहायो में, 10-year अवधि के भीतर अलग-अलग घटनाओं में दूसरे आउट-ऑफ-सर्विस (OOS) आदेश उल्लंघन के लिए CDL अयोग्यता अवधि क्या है?","options":["2 years","1 year","180 days","3 years"],"explanation":"10-year अवधि के भीतर दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन 2-year अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"57":{"q":"एक ओहायो CDL धारक को 10-year अवधि के भीतर तीसरे आउट-ऑफ-सर्विस आदेश उल्लंघन का दोषी ठहराया जाता है। अयोग्यता अवधि है:","options":["3 years","2 years","180 days","5 years"],"explanation":"10 years के भीतर तीसरा या उसके बाद का आउट-ऑफ-सर्विस आदेश उल्लंघन 3-year अयोग्यता का परिणाम देता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"58":{"q":"एक ओहायो चालक प्लेकार्ड लगी खतरनाक सामग्री का परिवहन करते समय या 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाते समय किसी आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है। इस पहले अपराध के लिए अयोग्यता क्या है?","options":["180 days","60 days","1 year","2 years"],"explanation":"प्लेकार्ड लगी खतरनाक सामग्री ढोते समय या 16+ यात्रियों को ले जाते समय पहला आउट-ऑफ-सर्विस आदेश उल्लंघन 180-day अयोग्यता लाता है; 10 years के भीतर ऐसा बाद का उल्लंघन 3 years लाता है। स्रोत: Ohio BMV CDL Disqualifications; ORC 4506.16; 49 CFR 383.51।"},"59":{"q":"ओहायो के Move Over कानून के तहत, जब आप किसी हाईवे पर अपनी दिशा में दो या अधिक लेन वाली सड़क पर चमकती रोशनी (flashing lights) दिखा रहे किसी खड़े टो ट्रक, हाईवे रखरखाव वाहन, या पुलिस गाड़ी के पास पहुँचते हैं, तो आपको क्या करना चाहिए?","options":["जब ऐसा करना सुरक्षित हो, तब खड़े वाहन के बगल वाली लेन से हटकर दूसरी लेन में चले जाएँ","जब तक वाहन हट न जाए, तब तक पूरी तरह रुक जाएँ","गुज़रते समय लगातार हॉर्न बजाते रहें","अपनी गति बनाए रखें लेकिन अपने चारों ओर के flashers (four-way flashers) चालू कर लें"],"explanation":"ओहायो का Move Over कानून (ORC 4511.213) यह अपेक्षा करता है कि किसी खड़े सार्वजनिक सुरक्षा, आपातकालीन, सड़क सेवा, या रखरखाव वाहन के पास पहुँच रहा चालक, जब उसी दिशा में कम से कम दो लेन हों और ऐसा करना सुरक्षित हो, तो उस वाहन के बगल वाली लेन से हटकर दूसरी लेन में चला जाए। स्रोत: Ohio Revised Code 4511.213."},"60":{"q":"ओहायो के Move Over कानून के तहत, यदि रोशनी चमका रहे किसी खड़े आपातकालीन वाहन के पास से गुज़रते समय आप सुरक्षित रूप से लेन नहीं बदल सकते (उदाहरण के लिए दो-लेन वाली सड़क पर), तो कानून क्या अपेक्षा करता है?","options":["उचित सावधानी के साथ आगे बढ़ें, गति कम करें, और परिस्थितियों के अनुसार सुरक्षित गति बनाए रखें","पूरी तरह रुक जाएँ और किसी अधिकारी के आपको हाथ से आगे जाने का इशारा करने तक प्रतीक्षा करें","बिना धीमे हुए निर्धारित गति सीमा (posted speed limit) पर चलते रहें","किनारे (shoulder) पर जाकर रुक जाएँ"],"explanation":"जब लेन बदलना असंभव या असुरक्षित हो, तो ORC 4511.213 के अनुसार चालक को उचित सावधानी के साथ आगे बढ़ना चाहिए, गति कम करनी चाहिए, और सड़क, मौसम तथा यातायात की परिस्थितियों के अनुसार सुरक्षित गति बनाए रखनी चाहिए। स्रोत: Ohio Revised Code 4511.213."},"61":{"q":"ओहायो में, प्लैकार्ड लगे खतरनाक पदार्थ (hazardous materials) ले जा रहा या बस चला रहा कोई चालक, रेलरोड ग्रेड क्रॉसिंग से पहले सबसे नज़दीकी रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 feet से कम नहीं और 50 feet से अधिक नहीं","5 feet से कम नहीं और 25 feet से अधिक नहीं","25 feet से कम नहीं और 75 feet से अधिक नहीं","10 feet से कम नहीं और 100 feet से अधिक नहीं"],"explanation":"किसी बस या hazardous-materials प्लैकार्ड दिखा रहे वाहन का चालक रेलरोड क्रॉसिंग पर सबसे नज़दीकी रेल से 50 feet के भीतर परंतु 15 feet से कम नहीं की दूरी पर रुकना चाहिए, फिर आगे बढ़ने से पहले देखना और सुनना चाहिए। स्रोत: Ohio CDL Manual / 49 CFR 392.10; अनिवार्य ठहराव ORC 4511.63 द्वारा आवश्यक है।"},"62":{"q":"ओहायो में निम्नलिखित में से किस वाहन के लिए हर गैर-छूट प्राप्त (non-exempt) रेलरोड ग्रेड क्रॉसिंग पर रुकना अनिवार्य है?","options":["ऐसे पदार्थ ले जा रहा वाहन जिन पर संघीय hazmat नियमों के तहत प्लैकार्ड लगाना आवश्यक हो","यूटिलिटी ट्रेलर खींच रहा कोई भी पिकअप ट्रक","10,000 pounds से अधिक सकल वज़न वाला कोई भी straight truck","दोहरे पिछले पहियों (dual rear wheels) वाला कोई भी वाहन"],"explanation":"ORC 4511.63 के अनुसार किसी भी बस, किसी भी स्कूल वाहन, या ऐसे किसी भी वाहन के चालक को जो 49 CFR Parts 100-185 के तहत प्लैकार्ड लगाना आवश्यक पदार्थ ले जा रहा हो, रेलरोड ट्रैक पार करने से पहले रुकना होगा। सामान्य ट्रक और ट्रेलर इस अनिवार्य ठहराव के अधीन नहीं हैं। स्रोत: Ohio Revised Code 4511.63."},"63":{"q":"ओहायो की दो-लेन वाली सड़क पर, जब आप किसी खड़ी स्कूल बस के सामने आते हैं जो अपनी लाल बत्तियाँ चमकाते हुए बच्चों को चढ़ा या उतार रही है, तो आपको बस से कम से कम कितनी दूरी पर रुकना चाहिए?","options":["बस के आगे या पीछे से कम से कम 10 feet दूर","बस के आगे या पीछे से कम से कम 20 feet दूर","बस के आगे या पीछे से कम से कम 30 feet दूर","बस के आगे या पीछे से कम से कम 50 feet दूर"],"explanation":"ORC 4511.75 के अनुसार किसी खड़ी स्कूल बस के सामने आने या उसे पीछे से पार करने वाले चालक को बस के आगे या पीछे से कम से कम 10 feet दूर रुकना चाहिए और जब तक बस आगे न बढ़े या चालक आगे जाने का इशारा न करे, तब तक आगे नहीं बढ़ना चाहिए। स्रोत: Ohio Revised Code 4511.75."},"64":{"q":"ओहायो में, कितनी यातायात लेन वाली विभाजित (divided) हाईवे पर सामने से आता यातायात विपरीत दिशा में खड़ी स्कूल बस के लिए बिना रुके चलता रह सकता है?","options":["चार या अधिक लेन","दो या अधिक लेन","तीन या अधिक लेन","छह या अधिक लेन"],"explanation":"ओहायो का स्कूल बस कानून यह प्रावधान करता है कि चार या अधिक लेन वाली हाईवे पर, विपरीत दिशा में खड़ी स्कूल बस के लिए चालक को रुकने की आवश्यकता नहीं है; केवल बस के समान दिशा में चल रहे यातायात को रुकना होगा। स्रोत: Ohio Revised Code 4511.75."},"65":{"q":"दो-लेन वाली सड़क पर किसी ओहायो स्कूल बस के लिए रुकने के बाद, आप कब आगे बढ़ सकते हैं?","options":["जब बस फिर से चलने लगे या बस चालक आपको आगे जाने का इशारा करे","जैसे ही बच्चे सड़क से हट जाएँ","अनिवार्य 30 सेकंड प्रतीक्षा करने के बाद","जब भी बस की पीली (amber) बत्तियाँ चमकने लगें"],"explanation":"ORC 4511.75 कहता है कि रुका हुआ चालक तब तक आगे नहीं बढ़ेगा जब तक स्कूल बस फिर से चलना शुरू न कर दे या जब तक स्कूल बस चालक आगे जाने का इशारा न कर दे। स्रोत: Ohio Revised Code 4511.75."},"66":{"q":"ओहायो में किसी ग्रामीण इंटरस्टेट हाईवे पर ट्रैक्टर-ट्रेलर के लिए अधिकतम गति सीमा क्या है (जब तक कि कोई कम सीमा निर्धारित (posted) न हो)?","options":["70 mph, यात्री कारों के समान ही","55 mph, यात्री कारों से कम","60 mph, यात्री कारों से कम","65 mph, यात्री कारों से कम"],"explanation":"ओहायो ट्रकों के लिए अलग, कम गति सीमा निर्धारित नहीं करता। ORC 4511.21 के तहत ग्रामीण इंटरस्टेट पर अधिकतम 70 mph है और जब तक अन्यथा निर्धारित न हो, वाणिज्यिक ट्रक कारों के समान ही गति सीमा पर चल सकते हैं। स्रोत: Ohio Revised Code 4511.21; ODOT speed zone नियम।"},"67":{"q":"Ohio Turnpike की मुख्य लाइन (mainline) पर वाणिज्यिक ट्रकों के लिए गति सीमा क्या है?","options":["70 mph, यात्री वाहनों के समान ही","ट्रकों के लिए 65 mph जबकि कारें 70 पर जा सकती हैं","सभी ट्रकों के लिए 55 mph","ट्रकों के लिए 60 mph जबकि कारें 70 पर जा सकती हैं"],"explanation":"Ohio Turnpike पर 70 mph की मुख्य लाइन सीमा निर्धारित है जो वाणिज्यिक ट्रकों सहित सभी वाहनों पर लागू होती है; ओहायो ट्रकों के लिए अलग कम गति लागू नहीं करता। स्रोत: Ohio Turnpike and Infrastructure Commission; ORC 4511.21."},"68":{"q":"ओहायो की किसी मल्टी-लेन सड़क पर, यातायात की प्रचलित गति से धीमे चल रहे ट्रक चालक से आमतौर पर क्या करने की अपेक्षा की जाती है?","options":["यातायात के लिए उपलब्ध दाएँ हाथ की लेन में चलें, सिवाय ओवरटेक करते या बाएँ मुड़ते समय","मर्ज करने वाले वाहनों से बचने के लिए बीच की लेन में रहें","बाईं लेन का उपयोग करें ताकि तेज़ यातायात दाईं ओर से मर्ज कर सके","जब तक four-way flashers चालू हों, किसी भी लेन का उपयोग करें"],"explanation":"ORC 4511.25 के अनुसार प्रचलित वैध गति से धीमे चल रहे वाहन को यातायात के लिए उपलब्ध दाएँ हाथ की लेन में, इतना दाईं ओर चलाया जाना चाहिए कि सुरक्षित रूप से पार किया जा सके, सिवाय ओवरटेक करते समय, बाएँ मुड़ते समय, या जब मार्ग के लिए किसी अन्य लेन की आवश्यकता हो। स्रोत: Ohio Revised Code 4511.25."},"69":{"q":"जब कोई ट्रक खराब होकर ओहायो की किसी सड़क पर रुका हो, तो तीन चेतावनी उपकरण (flares, reflectors, या lanterns) कैसे रखे जाने चाहिए?","options":["एक लगभग 100 feet आगे, एक लगभग 100 feet पीछे, और एक यातायात वाली ओर","तीनों सीधे वाहन के पीछे एक पंक्ति में रखे जाएँ","एक प्रत्येक ओर और एक केबिन की छत पर","एक 10 feet आगे, एक 10 feet पीछे, और एक किनारे (shoulder) पर"],"explanation":"ORC 4513.28 के अनुसार चेतावनी उपकरणों को वाहन के लगभग 100 feet आगे, लगभग 100 feet पीछे, और खराब वाहन की यातायात वाली ओर एक रखना आवश्यक है। स्रोत: Ohio Revised Code 4513.28."},"70":{"q":"ओहायो के Move Over कानून (ORC 4511.213) के पहली बार के उल्लंघन को किस रूप में वर्गीकृत किया जाता है?","options":["जुर्माना दोगुना (लगभग $300 तक) के साथ एक minor misdemeanor","पाँचवीं डिग्री का felony","बिना किसी अंक (points) के एक non-moving civil infraction","अनिवार्य जेल के साथ एक first-degree misdemeanor"],"explanation":"ORC 4511.213 के तहत पहला उल्लंघन एक minor misdemeanor है, लेकिन न्यायालय को सामान्य राशि का दोगुना जुर्माना लगाना होगा, जिससे यह लगभग $300 तक हो जाता है। एक वर्ष के भीतर बार-बार उल्लंघन चौथी- और तीसरी-डिग्री के misdemeanors तक बढ़ जाते हैं। स्रोत: Ohio Revised Code 4511.213."},"71":{"q":"ओहायो में, oversize परमिट की आवश्यकता पड़ने से पहले किसी वाणिज्यिक वाहन या लोड की अधिकतम वैध चौड़ाई क्या है?","options":["8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"ओहायो की वैध अधिकतम वाहन चौड़ाई 8 feet 6 inches (102 inches) है; इससे अधिक चौड़ी किसी भी चीज़ के लिए ODOT से एक विशेष हॉलिंग परमिट (special hauling permit) की आवश्यकता होती है। स्रोत: ORC 5577.05; Ohio DOT Special Hauling Permit नियम।"},"72":{"q":"ओहायो में, परमिट की आवश्यकता पड़ने से पहले किसी वाहन और लोड की अधिकतम वैध ऊँचाई क्या है?","options":["13 feet 6 inches","12 feet 6 inches","14 feet 0 inches","13 feet 0 inches"],"explanation":"ओहायो की वैध अधिकतम ऊँचाई 13 feet 6 inches है; इससे ऊँचे लोड के लिए ODOT से एक oversize परमिट की आवश्यकता होती है। स्रोत: ORC 5577.05; Ohio DOT Special Hauling Permit Operational Guide."},"73":{"q":"वह विशेष परमिट कौन जारी करता है जो किसी oversize या overweight वाहन को ओहायो की राज्य मार्गों (state routes) पर चलने की अनुमति देता है?","options":["Ohio Director of Transportation (ODOT)","Ohio Bureau of Motor Vehicles (BMV)","मार्ग के प्रत्येक काउंटी का county sheriff","Ohio State Highway Patrol post commander"],"explanation":"वैध आकार या वज़न सीमा से अधिक वाले वाहन किसी राज्य मार्ग पर केवल Ohio Director of Transportation द्वारा जारी एक विशेष लिखित परमिट के तहत ही चल सकते हैं। स्रोत: ORC 4513.34 और 5577.04; ODOT Special Hauling Permits."},"74":{"q":"ओहायो में, संघीय सीमा के अनुरूप, overweight परमिट के बिना अनुमत अधिकतम सकल वाहन वज़न (gross vehicle weight) क्या है?","options":["80,000 pounds","73,280 pounds","90,000 pounds","100,000 pounds"],"explanation":"ओहायो 80,000 pounds की संघीय अधिकतम सकल वज़न सीमा का पालन करता है (Federal Bridge Formula के अधीन); इससे अधिक होने पर ODOT overweight परमिट की आवश्यकता होती है। स्रोत: ORC 5577.04; Federal Bridge Formula."},"75":{"q":"जब कोई प्लैकार्ड लगा hazmat वाहन ओहायो में किसी रेलरोड क्रॉसिंग के पास पहुँचता है, तो ट्रैक पार करते समय कौन-सी क्रिया सही है?","options":["जब तक वाहन का कोई भी हिस्सा ट्रैक पर हो, तब तक गियर न बदलें","बेहतर नियंत्रण के लिए पार करते समय निचले गियर में डाल लें","दूसरी ट्रेन की जाँच के लिए बीच में रुक जाएँ","जब तक पूरी तरह पार न हो जाएँ, तब तक इंजन बंद कर दें"],"explanation":"रुकने, देखने और सुनने के बाद, चालक को ऐसे गियर में पार करना चाहिए जिसे बदलने की आवश्यकता न पड़े और जब तक वाहन का कोई भी हिस्सा ट्रैक पर हो, तब तक गियर नहीं बदलना चाहिए। स्रोत: Ohio CDL Manual / 49 CFR 392.10; ORC 4511.63."},"76":{"q":"ओहायो में किसी चार-लेन विभाजित (divided) हाईवे पर, बच्चों को उतारने के लिए रुकती स्कूल बस को, जहाँ व्यावहारिक हो, सड़क पार करने के जोखिम को कम करने के लिए क्या करना चाहिए?","options":["यात्रियों को हाईवे की निवास वाली ओर (residence side) चढ़ाएँ और उतारें","median में रुकें ताकि बच्चे crossover का उपयोग कर सकें","सभी यात्रियों को बाएँ किनारे (left shoulder) पर उतारें","सभी बच्चों को चालक द्वारा साथ ले जाकर सड़क पार कराना आवश्यक करें"],"explanation":"विभाजित हाईवे या चार या अधिक लेन वाली सड़कों पर, स्कूल बसों को बच्चों को निवास वाली ओर चढ़ाना और उतारना चाहिए ताकि बच्चों को सड़क पार न करनी पड़े; यही कारण है कि सामने से आते यातायात को रुकने की आवश्यकता नहीं होती। स्रोत: Ohio Revised Code 4511.75; Ohio स्कूल बस नियम।"},"77":{"q":"ओहायो कानून के तहत, जब किसी नामित खतरनाक रेलरोड ग्रेड क्रॉसिंग पर एक निर्धारित STOP चिह्न लगा हो, तो चालक को सबसे नज़दीकी रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 feet से कम नहीं परंतु 50 feet के भीतर","5 feet से कम नहीं परंतु 20 feet के भीतर","30 feet से कम नहीं परंतु 60 feet के भीतर","सबसे नज़दीकी रेल से ठीक 25 feet"],"explanation":"ORC 4511.61 के अनुसार जहाँ STOP चिह्न लगाया गया हो, वहाँ रेलरोड क्रॉसिंग पर चालक को सबसे नज़दीकी रेल से पचास feet के भीतर परंतु पंद्रह feet से कम नहीं की दूरी पर रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक ऐसा करना सुरक्षित न हो। स्रोत: Ohio Revised Code 4511.61."},"78":{"q":"कौन-सा कथन सबसे अच्छी तरह बताता है कि ओहायो कारों से अलग ट्रक-विशिष्ट गति सीमाएँ लागू करता है या नहीं?","options":["ओहायो ट्रकों और कारों के लिए समान अधिकतम गति सीमाएँ निर्धारित करता है; ट्रकों को राज्यव्यापी अलग कम सीमा नहीं दी जाती","ट्रक निर्धारित सीमा की परवाह किए बिना राज्यव्यापी हमेशा 55 mph तक सीमित रहते हैं","ट्रकों को सभी फ्रीवे पर निर्धारित कार सीमा से 10 mph कम चलना चाहिए","ट्रक केवल Ohio Turnpike का उपयोग कर सकते हैं और इंटरस्टेट पर प्रतिबंधित हैं"],"explanation":"ओहायो ORC 4511.21 के तहत वाणिज्यिक ट्रकों और यात्री कारों पर समान निर्धारित अधिकतम गति सीमाएँ लागू करता है; कोई अलग राज्यव्यापी कम ट्रक गति सीमा नहीं है, हालाँकि चालकों को फिर भी परिस्थितियों के अनुसार सुरक्षित गति पर चलना चाहिए। स्रोत: Ohio Revised Code 4511.21; ODOT."},"79":{"q":"ओहायो में Commercial Driver Licenses (CDLs) कौन-सी राज्य एजेंसी जारी करती है?","options":["Ohio Bureau of Motor Vehicles (BMV)","Ohio Department of Transportation (ODOT)","Ohio State Highway Patrol","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"ओहायो में, Bureau of Motor Vehicles (BMV), जो Ohio Department of Public Safety का एक प्रभाग है, CDLs सहित सभी ड्राइवर लाइसेंस जारी करता है। ODOT सड़कों और oversize/overweight परमिटों को संभालता है, लाइसेंसिंग को नहीं, और FMCSA वह संघीय एजेंसी है जो मानक निर्धारित करती है। स्रोत: Ohio BMV, Commercial Driver (CDL) page."},"80":{"q":"किसी ओहायो CDL आवेदक के कोई भी commercial knowledge test देने से पहले, वह परीक्षा कहाँ पूरी की जानी चाहिए?","options":["किसी Ohio BMV driver exam station पर व्यक्तिगत रूप से (in person)","किसी भी घरेलू कंप्यूटर से ऑनलाइन","घर ले जाने वाली उत्तर पुस्तिका का उपयोग करके डाक द्वारा","किसी FMCSA-पंजीकृत ELDT प्रशिक्षण प्रदाता पर"],"explanation":"ओहायो यह अपेक्षा करता है कि CDL knowledge tests (general knowledge, endorsements, और air-brake restriction removal) किसी BMV driver exam station पर व्यक्तिगत रूप से दिए जाएँ; इन्हें ऑनलाइन नहीं दिया जा सकता। ELDT प्रदाता प्रशिक्षण देते हैं, राज्य की knowledge test नहीं। स्रोत: Ohio BMV, Commercial Driver (CDL) page."},"81":{"q":"जारी होने के बाद ओहायो का Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है?","options":["12 महीने","6 महीने","30 दिन","24 महीने"],"explanation":"ओहायो बताता है कि CLP 12 महीने के लिए वैध रहता है। (संघीय नियम के तहत इसे general knowledge test दोबारा दिए बिना एक बार नवीनीकृत किया जा सकता है।) अन्य विकल्प सामान्य परंतु गलत परमिट अवधियों को दर्शाते हैं। स्रोत: Ohio BMV, Commercial Driver (CDL) page."},"82":{"q":"ओहायो CLP प्राप्त करने के बाद, CDL skills test देने के योग्य होने से पहले किसी आवेदक को इसे कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 60 दिन"],"explanation":"ओहायो में लागू संघीय विनियमन के अनुसार धारक के CDL skills (road) test देने से पहले CLP को कम से कम 14 दिन तक रखना आवश्यक है। स्रोत: Ohio BMV CDL process / 49 CFR 383.25 (FMCSA)."},"83":{"q":"ओहायो CDL skills test तीन भागों में संचालित की जाती है। कौन-सा समूह उन तीन भागों को सही ढंग से सूचीबद्ध करता है?","options":["Pre-trip inspection, basic control (maneuverability), और on-road driving","Written knowledge, vision screening, और on-road driving","Pre-trip inspection, air-brake check, और hazardous-materials handling","Basic control, night driving, और एक written endorsement exam"],"explanation":"ओहायो की CDL skills test तीन भागों से मिलकर बनी है: pre-trip inspection, basic control (maneuverability) test, और on-road driving test। Vision screening और written exams skills test से अलग हैं। स्रोत: Ohio BMV, Commercial Driver (CDL) page."},"84":{"q":"ओहायो आवेदक को CDL skills test शेड्यूल करने या देने से पहले इलेक्ट्रॉनिक रूप से क्या जमा करना आवश्यक है?","options":["Entry-Level Driver Training (ELDT) पूरा करने का प्रमाण, या छूट (exemption) का प्रमाण","दो वर्ष के पूर्व ड्राइविंग अनुभव का प्रमाण","एक हस्ताक्षरित नियोक्ता प्रायोजन पत्र (employer sponsorship letter)","किसी defensive-driving कोर्स में उत्तीर्ण अंक"],"explanation":"ओहायो को skills test शेड्यूल करने या देने से पहले, मांगे गए class/endorsement से मेल खाते FMCSA Entry-Level Driver Training (ELDT) को पूरा करने का इलेक्ट्रॉनिक प्रमाण, या छूट का प्रमाण आवश्यक है। स्रोत: Ohio BMV CDL page / FMCSA ELDT नियम (49 CFR Part 380)."},"85":{"q":"ओहायो की self-certification प्रक्रिया में CDL/CLP आवेदक को कितनी type-of-driving श्रेणियों में से चुनना आवश्यक है?","options":["चार","दो","तीन","पाँच"],"explanation":"ओहायो चालकों को चार श्रेणियों में से एक में self-certify करना आवश्यक है: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: Ohio BMV CDL Self-Certification (form BMV 2159)."},"86":{"q":"एक ओहायो चालक व्यापार के लिए राज्य की सीमाएँ पार करता है और उसे 49 CFR Part 391 के तहत संघीय physical-qualification (चिकित्सा) मानक पूरे करने होते हैं। कौन-सी self-certification श्रेणी लागू होती है?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Non-Excepted Interstate उन चालकों को कवर करता है जो राज्य की सीमाओं के पार संचालन करते हैं और जिन्हें 49 CFR Part 391 की संघीय चिकित्सा आवश्यकताओं को पूरा करना होता है; इन चालकों को एक वैध medical examiner's certificate फ़ाइल में रखना होता है। स्रोत: Ohio BMV self-certification categories (form BMV 2159)."},"87":{"q":"23 जून 2025 से प्रभावी, किसी CDL धारक के DOT medical examiner's certificate की जानकारी Ohio BMV को कैसे प्रदान की जाती है?","options":["FMCSA परीक्षा परिणाम इलेक्ट्रॉनिक रूप से BMV को भेजता है, इसलिए कागज़ी प्रमाणपत्र की अब आवश्यकता नहीं है","चालक को 10 दिनों के भीतर एक notarized कागज़ी प्रति BMV को डाक से भेजनी होगी","medical examiner एक wallet card फैक्स करता है जिसे चालक लैमिनेट करता है","प्रमाणपत्र केवल चालक के नियोक्ता द्वारा अपलोड किया जाता है"],"explanation":"23 जून 2025 से, FMCSA, CLP आवेदकों और CDL धारकों के लिए medical examination परिणाम (और variance जानकारी) इलेक्ट्रॉनिक रूप से Ohio BMV को भेजता है, इसलिए चालक अब कागज़ी Medical Examiner's Certificate जमा नहीं करते। स्रोत: Ohio BMV CDL medical certification notice / FMCSA Medical Examiner's Certification Integration नियम।"},"88":{"q":"चालक के commercial driving के प्रकार की CDL self-certification के लिए कौन-सा Ohio BMV form उपयोग किया जाता है?","options":["BMV 2159 (CDL Self-Certification Authorization)","BMV 2290 (Heavy Vehicle Use Tax form)","BMV 5759 (Hazardous Materials Endorsement form)","BMV 1173 (Vehicle Registration form)"],"explanation":"ओहायो किसी चालक द्वारा चार type-of-driving श्रेणियों में से एक घोषित करने के लिए form BMV 2159, CDL Self-Certification Authorization, का उपयोग करता है। स्रोत: Ohio BMV form BMV 2159."},"89":{"q":"ओहायो की 50-प्रश्न वाली CDL general knowledge test उत्तीर्ण करने के लिए आवश्यक सही उत्तरों की न्यूनतम संख्या क्या है?","options":["40 सही (80%)","35 सही (70%)","45 सही (90%)","30 सही (60%)"],"explanation":"ओहायो CDL knowledge tests उत्तीर्ण करने के लिए कम से कम 80% का स्कोर आवश्यक है; 50-प्रश्न वाली general knowledge test पर इसका अर्थ 40 सही उत्तर है। 80% का मानक endorsement परीक्षाओं पर भी लागू होता है। स्रोत: Ohio CDL manual / Ohio BMV testing standards."},"90":{"q":"Ohio Revised Code 4506.14 के अनुसार, एक मानक (गैर-hazmat) ओहायो CDL अधिकतम कितनी अवधि के लिए जारी किया जा सकता है?","options":["आठ वर्ष","चार वर्ष","पाँच वर्ष","दस वर्ष"],"explanation":"ORC 4506.14 यह प्रावधान करता है कि कोई CDL आठ वर्ष से अधिक अवधि के लिए जारी नहीं किया जा सकता; CDLs लाइसेंसधारी के जन्मदिन से जुड़े होते हैं। हालाँकि, एक hazardous-materials endorsement, जारी करने को चार वर्ष और 180 दिन तक सीमित कर देता है। स्रोत: Ohio Revised Code 4506.14."},"91":{"q":"संघीय background-check (TSA) सीमाओं के कारण, एक hazardous-materials endorsement वाला ओहायो CDL कितनी अवधि से अधिक के लिए जारी नहीं किया जा सकता?","options":["चार वर्ष और 180 दिन","ठीक चार वर्ष","पाँच वर्ष","आठ वर्ष"],"explanation":"ORC 4506.14 एक hazardous-materials endorsement वाले CDL को चार वर्ष और 180 दिन तक सीमित करता है, जो संघीय hazmat security threat assessment चक्र के अनुरूप है। मानक CDLs आठ वर्ष तक चल सकते हैं। स्रोत: Ohio Revised Code 4506.14."},"92":{"q":"ओहायो कानून के तहत, किसी CDL को उसकी समाप्ति तिथि से कितने पहले तक नवीनीकृत किया जा सकता है?","options":["समाप्ति से 180 दिन पहले तक","समाप्ति से 30 दिन पहले तक","समाप्ति से 90 दिन पहले तक","केवल समाप्ति तिथि पर या उसके बाद"],"explanation":"ORC 4506.14 कहता है कि आवश्यक शुल्क के भुगतान पर एक CDL उसकी समाप्ति से 180 दिन पहले से नवीनीकरण योग्य हो जाता है। स्रोत: Ohio Revised Code 4506.14."},"93":{"q":"ओहायो का registrar किसी CDL धारक के लिए नवीनीकरण परीक्षा (renewal examination) को केवल तभी माफ कर सकता है जब आवेदक ऐसा CDL प्रस्तुत करे जो अनसमाप्त (unexpired) हो या आवेदन तिथि से अधिकतम कितने पहले समाप्त हुआ हो?","options":["छह महीने","एक महीना","तीन महीने","एक वर्ष"],"explanation":"ORC 4506.14 registrar को नवीनीकरण परीक्षा माफ करने की अनुमति देता है यदि आवेदक एक अनसमाप्त CDL प्रस्तुत करे, या ऐसा जो आवेदन तिथि से छह महीने से अधिक पहले समाप्त न हुआ हो। उस छूट अवधि के बाद, आमतौर पर दोबारा परीक्षा आवश्यक होती है। स्रोत: Ohio Revised Code 4506.14."},"94":{"q":"केवल INTRASTATE (केवल ओहायो के भीतर) ड्राइविंग तक सीमित ओहायो CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"ओहायो केवल-intrastate संचालन के लिए न्यूनतम CDL आयु 18 निर्धारित करता है; 21 से कम आयु के चालक ओहायो के भीतर ही ड्राइविंग तक सीमित हैं। Interstate संचालन और hazardous-materials ढुलाई के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Ohio BMV CDL requirements."},"95":{"q":"INTERSTATE वाणिज्य में किसी commercial motor vehicle को चलाने या hazardous materials ढोने के लिए ओहायो आवेदक की आयु कम से कम कितनी होनी चाहिए?","options":["21 वर्ष","18 वर्ष","23 वर्ष","25 वर्ष"],"explanation":"ओहायो में लागू संघीय नियम के अनुसार किसी चालक को interstate वाणिज्य में संचालन करने या प्लैकार्ड लगे hazardous materials का परिवहन करने के लिए कम से कम 21 वर्ष का होना आवश्यक है। 18-20 आयु के चालक intrastate ड्राइविंग तक सीमित हैं। स्रोत: Ohio BMV CDL requirements / 49 CFR 391.11."},"96":{"q":"एक वैध ओहायो ड्राइवर लाइसेंस और Social Security number के प्रमाण के अलावा, पहली बार के ओहायो CDL आवेदक को और क्या प्रस्तुत करना आवश्यक है?","options":["U.S. नागरिकता या वैध स्थायी निवास (lawful permanent residency) का प्रमाण","किसी वर्तमान नियोक्ता का notarized पत्र","एक high school diploma या GED प्रमाणपत्र","CDLs धारण करने वाले दो व्यक्तिगत संदर्भ (references)"],"explanation":"ओहायो को पहली बार के CDL आवेदकों से एक वैध ओहायो ड्राइवर लाइसेंस, एक वैध Social Security number, और U.S. नागरिकता या वैध स्थायी निवास का प्रमाण (जैसे, passport, जन्म प्रमाणपत्र, या permanent resident card) आवश्यक है। स्रोत: Ohio BMV, Commercial Driver (CDL) page."},"97":{"q":"एक ओहायो चालक 'Excepted Interstate' के रूप में self-certify करता है। यह श्रेणी उनकी संघीय चिकित्सा आवश्यकताओं के बारे में क्या दर्शाती है?","options":["वे राज्य की सीमाओं के पार ड्राइव करते हैं परंतु उन्हें संघीय (Part 391) चिकित्सा मानक पूरे करना आवश्यक नहीं है","वे केवल ओहायो के भीतर ड्राइव करते हैं और उन्हें राज्य के चिकित्सा मानक पूरे करना आवश्यक है","उन्हें हमेशा एक संघीय medical examiner's certificate साथ रखना होगा","वे किसी भी व्यावसायिक उद्देश्य के लिए CDL का कभी उपयोग नहीं करते"],"explanation":"Excepted Interstate का अर्थ है कि चालक राज्य की सीमाओं के पार संचालन करता है परंतु 49 CFR Part 391 की संघीय physical-qualification आवश्यकताओं से छूट के लिए योग्य है, इसलिए उस संचालन के लिए DOT medical card आवश्यक नहीं है। स्रोत: Ohio BMV self-certification categories (form BMV 2159)."},"98":{"q":"ओहायो CDL skills test देते समय, परीक्षा के लिए उपयोग किए जाने वाले commercial vehicle को उपलब्ध कराने के लिए आमतौर पर कौन ज़िम्मेदार होता है?","options":["आवेदक, जिसे मांगे गए class का प्रतिनिधि वाहन उपलब्ध कराना (या किराए पर लेना) होगा","Ohio BMV, जो परीक्षा वाहनों का एक बेड़ा रखता है","ODOT, जो road tests के लिए वाहन उधार देता है","FMCSA क्षेत्रीय कार्यालय"],"explanation":"ओहायो को आवेदक से परीक्षा की जा रही class का प्रतिनिधित्व करने वाला एक उपयुक्त commercial vehicle उपलब्ध कराना, या इसे किराए पर लेना (अक्सर किसी third-party testing site के माध्यम से) आवश्यक है। BMV परीक्षा वाहन उपलब्ध नहीं कराता। स्रोत: Ohio BMV, Commercial Driver (CDL) page."}},"ar":{"0":{"q":"على الطرق السريعة في أوهايو، ما هو الحد الأقصى القانوني لعرض المركبة، بما في ذلك حمولتها، دون الحصول على تصريح نقل خاص؟","options":["8 أقدام (96 inches)","8 أقدام و6 بوصات (102 inches)","9 أقدام (108 inches)","8 أقدام وبوصتان (98 inches)"],"explanation":"تحدد المادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05) الحد الأقصى لعرض المركبة عند 102 inches (8 أقدام و6 بوصات)، بما في ذلك الحمولة. وأي عرض يزيد على ذلك يتطلب تصريح نقل خاص من ODOT."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة والحمولة على الطرق السريعة في أوهايو دون الحصول على تصريح؟","options":["13 قدمًا و0 بوصة","14 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و6 بوصات"],"explanation":"وفقًا للمادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05)، فإن الحد الأقصى للارتفاع هو 13 قدمًا و6 بوصات (13.5 قدم)، مع الحمولة أو بدونها. والسائق مسؤول عن اجتياز الجسور العلوية والمنشآت بأمان."},"2":{"q":"في أوهايو، ما هو الحد الأقصى لطول نصف المقطورة المُشغّلة ضمن تركيبة قاطرة ونصف مقطورة دون الحصول على تصريح؟","options":["48 قدمًا","53 قدمًا","57 قدمًا","45 قدمًا"],"explanation":"تسمح المادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05) بنصف مقطورة يصل طولها إلى 53 قدمًا عند تشغيلها ضمن تركيبة قاطرة تجارية ونصف مقطورة، بما يتوافق مع معيار الشبكة الوطنية الفيدرالية."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة والحمولة الذي يجوز نقله على الطرق السريعة في أوهايو دون الحصول على تصريح نقل خاص؟","options":["73,280 pounds","80,000 pounds","90,000 pounds","84,000 pounds"],"explanation":"تحدد المادة 5577.04 من قانون أوهايو المنقّح (Ohio Revised Code 5577.04) الحد الأقصى للوزن الإجمالي الكلي المفروض على سطح الطريق عند 80,000 pounds، وهو نفس الحد الفيدرالي للطرق بين الولايات."},"4":{"q":"بموجب قانون أوهايو، لا يجوز أن يتجاوز الوزن على أي محور مفرد للمركبة أي مقدار؟","options":["18,000 pounds","22,400 pounds","20,000 pounds","24,000 pounds"],"explanation":"تحصر المادة 5577.04 من قانون أوهايو المنقّح (Ohio Revised Code 5577.04) الحد الأقصى لوزن المحور المفرد عند 20,000 pounds، بما يطابق المعيار الفيدرالي للمحور المفرد."},"5":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور مزدوجة (تاندم) على نظام الطرق بين الولايات في أوهايو؟","options":["32,000 pounds","36,000 pounds","38,000 pounds","34,000 pounds"],"explanation":"تحدد المادة 5577.04 من قانون أوهايو المنقّح (Ohio Revised Code 5577.04) الحد الأقصى لوزن المحور المزدوج (تاندم) عند 34,000 pounds، بما يتوافق مع الحد الفيدرالي للمحور المزدوج."},"6":{"q":"ما هو الحد الأقصى لطول أي مركبة مفردة (غير مقطورة) بخلاف الحافلة أو المركبة الترفيهية على الطرق السريعة في أوهايو دون الحصول على تصريح؟","options":["40 قدمًا","50 قدمًا","45 قدمًا","53 قدمًا"],"explanation":"تحصر المادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05) طول المركبة المفردة (بخلاف المركبات المدرجة على نحو خاص مثل الحافلات) عند 50 قدمًا."},"7":{"q":"أي جهة حكومية في ولاية أوهايو تصدر تصاريح النقل الخاصة للحمولات ذات الأبعاد الزائدة أو الأوزان الزائدة للتنقل على الطرق السريعة التابعة للولاية والفيدرالية والطرق بين الولايات؟","options":["مكتب أوهايو للمركبات الآلية (Ohio BMV)","دورية الطرق السريعة لولاية أوهايو","لجنة المرافق العامة في أوهايو (PUCO)","إدارة النقل في أوهايو (ODOT)"],"explanation":"تصدر إدارة النقل في أوهايو (ODOT) تصاريح النقل الخاصة، والتي تُعالَج إلكترونيًا عبر نظام تصاريح النقل في أوهايو (ODOT Special Hauling Permits)."},"8":{"q":"في تركيبة قاطرة ونصف مقطورة ومقطورة (مزدوجة) على الطرق السريعة في أوهايو، ما هو الحد الأقصى لطول كل نصف مقطورة أو مقطورة دون الحصول على تصريح؟","options":["28 قدمًا و6 بوصات","33 قدمًا","27 قدمًا","30 قدمًا"],"explanation":"تحصر المادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05) طول كل نصف مقطورة أو مقطورة عند 28 قدمًا و6 بوصات عند تشغيلها ضمن تركيبة تجارية قاطرة ونصف مقطورة ومقطورة، أو قاطرة ونصف مقطورة ونصف مقطورة."},"9":{"q":"تركيبة شاحنة على طريق سريع في أوهايو تتجاوز الحدود القانونية للوزن. أي نوع من التصاريح يجب على المُشغّل الحصول عليه قبل التنقل؟","options":["تظهير لحمولة عريضة على رخصة CDL","تصريح نقل خاص من ODOT","إعفاء فيدرالي من FMCSA للوزن الزائد","شهادة سند طريق صادرة عن المقاطعة"],"explanation":"وفقًا لـ ODOT، فإن أي مركبة أو حمولة تتجاوز الحدود القانونية للأبعاد أو الوزن في أوهايو يجب أن تحصل على تصريح نقل خاص من ODOT قبل التشغيل على الطرق السريعة التابعة للولاية أو الفيدرالية أو الطرق بين الولايات."},"10":{"q":"على الطرق السريعة في أوهايو، ما هو الحد الأقصى للطول لتركيبات المركبات التي لم يُنص عليها على نحو خاص (مثل تركيبة عامة من قاطرة ونصف مقطورة ومقطورة)؟","options":["60 قدمًا","75 قدمًا","65 قدمًا","70 قدمًا"],"explanation":"تحدد المادة 5577.05 من قانون أوهايو المنقّح (Ohio Revised Code 5577.05) حدًا أقصى قدره 65 قدمًا لأي تركيبة أخرى من المركبات لم يُنص عليها على نحو خاص."},"11":{"q":"صيغة الجسر الفيدرالية المعتمدة في قانون أوهايو لمجموعات المحاور المتعددة هي W = 500((LN/(N-1)) + 12N + 36). في هذه الصيغة، ماذا يمثّل الرمز 'L'؟","options":["تقدير الحمولة القانونية للجسر","المسافة بالأقدام بين المحورين الطرفيين (الأول والأخير) للمجموعة","طول أطول مقطورة في التركيبة","إجمالي الوزن الإجمالي المرخّص للمركبة"],"explanation":"في صيغة الجسر المنصوص عليها في المادة 5577.04(C) من قانون أوهايو المنقّح (Ohio Revised Code 5577.04(C))، يمثّل L المسافة بالأقدام بين المحور الأمامي والمحور الخلفي الأبعد للمجموعة، وN عدد المحاور، وW الحد الأقصى المسموح به للوزن الإجمالي."},"12":{"q":"بموجب أحكام الوزن الخاصة في أوهايو، بأي نسبة مئوية يجوز لشاحنة مزرعة أو أخشاب أو فحم أو نفايات صلبة مؤهلة أن تتجاوز حدود الوزن العادية عند النقل من موقع الإنتاج إلى أول نقطة تسليم؟","options":["5 في المائة","10 في المائة","7.5 في المائة","12.5 في المائة"],"explanation":"تسمح المادة 5577.042 من قانون أوهايو المنقّح (Ohio Revised Code 5577.042) لمركبات نقل المزارع والأخشاب والفحم والنفايات الصلبة المؤهلة بتجاوز أحكام الوزن بما لا يزيد على 7.5 في المائة وفق الشروط الموصوفة."},"13":{"q":"خلال أي شهرين لا ينطبق فيهما تفاوت الوزن البالغ 7.5 في المائة في أوهايو على شاحنات المزارع وشاحنات الأخشاب والآلات الزراعية؟","options":["فبراير ومارس","يناير وفبراير","مارس وأبريل","نوفمبر وديسمبر"],"explanation":"تحدد المادة 5577.042 من قانون أوهايو المنقّح (Ohio Revised Code 5577.042) أن التفاوت البالغ 7.5 في المائة لا ينطبق خلال فبراير ومارس على شاحنات المزارع أو شاحنات الأخشاب أو الآلات الزراعية (فترة التجمد/الذوبان الموسمية)."},"14":{"q":"تفاوت الوزن الزراعي/منتجات الغابات البالغ 7.5 في المائة في أوهايو بموجب المادة ORC 5577.042 لا ينطبق على أي من الطرق؟","options":["طرق المقاطعات","الطرق السريعة بين الولايات","طرق البلدات","شوارع البلديات"],"explanation":"تنص المادة 5577.042 من قانون أوهايو المنقّح (Ohio Revised Code 5577.042) على أن التفاوت البالغ 7.5 في المائة لا ينطبق على الطرق السريعة بين الولايات (أو على الطرق الخاضعة لأوزان قصوى مخفّضة على نحو خاص)."},"15":{"q":"بموجب قواعد ODOT، تُصنّف الحمولة على أنها 'حمولة فائقة' (superload) عندما يتجاوز وزنها الإجمالي أي مقدار؟","options":["80,000 pounds","100,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"وفقًا للدليل التشغيلي لـ ODOT، فإن الحمولة الفائقة (superload) هي أي مركبة/حمولة يزيد وزنها الإجمالي على 120,000 pounds (أو عرضها على 14 feet أو ارتفاعها على 14 feet 6 inches)، مما يستلزم مراجعة إضافية مثل تحليل الجسور/الهياكل الإنشائية."},"16":{"q":"على نظام الطرق العام (غير الطرق بين الولايات) في أوهايو، يجوز لمحورين متتاليين تفصل بينهما مسافة تزيد على 4 feet أن يحملا ما يصل إلى 34,000 pounds زائد 1,000 pounds لكل قدم إضافية، ولكن بما لا يزيد على أي حد أقصى؟","options":["38,000 pounds","42,000 pounds","44,000 pounds","40,000 pounds"],"explanation":"تنص المادة 5577.04 من قانون أوهايو المنقّح (Ohio Revised Code 5577.04) على أنه في النظام غير التابع للطرق بين الولايات، يجوز لمحورين متتاليين تفصل بينهما مسافة تزيد على 4 feet أن يحملا 34,000 pounds زائد 1,000 pounds لكل قدم تزيد على 4 feet، بحد أقصى 40,000 pounds."},"17":{"q":"بموجب قواعد المرافقة الخاصة بـ ODOT، تتطلب المركبة/الحمولة التي يزيد عرضها على أي بُعد مرافقة مركبة رائدة (أمامية) واحدة على طريق سريع ذي مسارين في أوهايو؟","options":["12 feet","13 feet","11 feet","10 feet"],"explanation":"وفقًا لمتطلبات المرافقة في تصاريح ODOT، يلزم وجود مركبة رائدة واحدة لأي مركبة/حمولة يزيد عرضها الإجمالي على 13 feet؛ أما الحمولات التي يزيد عرضها على 14 feet 6 inches فتتطلب مرافقة رائدة وخلفية معًا."},"18":{"q":"بموجب قواعد تصاريح ODOT، يُسمح عمومًا للحمولة ذات الأبعاد الزائدة التي يقل عرضها عن 12 feet بالتنقل خلال أي نافذة يومية؟","options":["فقط بين الساعة 9:00 صباحًا و3:00 مساءً","من 30 دقيقة قبل شروق الشمس إلى 30 دقيقة بعد غروبها","من ساعة واحدة بعد شروق الشمس إلى ساعة واحدة قبل غروبها","فقط خلال ساعات النهار الكامل، من الشروق إلى الغروب"],"explanation":"وفقًا لـ ODOT، يجوز للحمولات ذات الأبعاد الزائدة التي يقل عرضها عن 12 feet التنقل سبعة أيام في الأسبوع (باستثناء العطلات) من 30 دقيقة قبل شروق الشمس إلى 30 دقيقة بعد غروبها؛ أما الحمولات التي يبلغ عرضها 12 feet أو أكثر فيجب أن تتبع الأوقات المحددة المنصوص عليها في التصريح."},"19":{"q":"على نظام الطرق بين الولايات في أوهايو، يجوز لمجموعتين متتاليتين من المحاور المزدوجة (تاندم) أن تحمل كل منهما 34,000 pounds شريطة أن تكون المسافة بين المحور الأول والمحور الأخير للمجموعتين لا تقل عن كم قدمًا؟","options":["30 feet","40 feet","36 feet","34 feet"],"explanation":"تسمح المادة 5577.04 من قانون أوهايو المنقّح (Ohio Revised Code 5577.04) لمجموعتين متتاليتين من المحاور المزدوجة (تاندم) بأن تحمل كل منهما 34,000 pounds فقط عندما تكون المسافة الإجمالية بين المحور الأول والمحور الأخير للمجموعتين المتتاليتين 36 feet أو أكثر."},"20":{"q":"في أوهايو، أي فئة من رخصة CDL مطلوبة لتشغيل تركيبة مركبات ذات تصنيف وزن إجمالي مركّب (GCWR) يبلغ 26,001 pounds أو أكثر، شريطة أن يكون للوحدة المقطورة تصنيف وزن إجمالي للمركبة (GVWR) يزيد على 10,000 pounds؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تغطي رخصة CDL من الفئة A في أوهايو المركبات المركّبة ذات تصنيف GCWR يبلغ 26,001 lbs أو أكثر حيث يتجاوز تصنيف GVWR للوحدة المقطورة 10,000 lbs. المصدر: صفحة فئات CDL في Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx) و49 CFR 383.91 كما اعتُمدت في أوهايو."},"21":{"q":"يقود سائق في أوهايو شاحنة مستقيمة مفردة ذات تصنيف GVWR يبلغ 30,000 pounds ولا تجر أي مقطورة يزيد وزنها على 10,000 pounds. أي فئة من رخصة CDL هي المناسبة؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تغطي رخصة CDL من الفئة B في أوهايو أي مركبة مفردة ذات تصنيف GVWR يبلغ 26,001 lbs أو أكثر، ويجوز أن تجر مقطورة لا يتجاوز تصنيف GVWR لها 10,000 lbs. المصدر: صفحة فئات CDL في Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"22":{"q":"بموجب قواعد أوهايو، المركبة التي لا تستوفي عتبات الوزن الخاصة بالفئة A أو B لكنها مصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو مواد خطرة تتطلب لوحات تحذيرية تندرج تحت أي فئة من رخصة CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تنطبق رخصة CDL من الفئة C في أوهايو على المركبات التي تقل عن عتبات وزن الفئة A/B والتي تنقل 16 شخصًا أو أكثر (بما في ذلك السائق) أو مواد خطرة تستلزم لوحات تحذيرية. المصدر: صفحة فئات CDL في Ohio BMV (bmv.ohio.gov/dl-cdl-classes.aspx)."},"23":{"q":"ما هو الحد الأدنى للعمر لإصدار رخصة CDL في أوهايو مقيّدة بالقيادة التجارية داخل الولاية (INTRASTATE) فقط؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"تصدر أوهايو رخصة CDL داخل الولاية فقط بدءًا من سن 18؛ ويقتصر السائقون دون سن 21 على التجارة داخل أوهايو. المصدر: أهلية CDL في Ohio BMV (bmv.ohio.gov) وORC 4506.10."},"24":{"q":"ما هو الحد الأدنى للعمر المطلوب لتشغيل مركبة تجارية في التجارة بين الولايات (INTERSTATE) برخصة CDL من أوهايو؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"تتطلب القيادة التجارية بين الولايات أن يكون عمر السائق 21 عامًا على الأقل. ويحمل سائقو أوهايو الذين تتراوح أعمارهم بين 18 و20 عامًا رخصة CDL داخل الولاية فقط. المصدر: أهلية CDL في Ohio BMV و49 CFR 391.11."},"25":{"q":"أي حرف تظهير مطلوب على رخصة CDL في أوهايو لنقل المواد الخطرة بكميات تتطلب وضع لوحات تحذيرية على المركبة؟","options":["التظهير H","التظهير N","التظهير T","التظهير X"],"explanation":"يُجيز تظهير H (HazMat) نقل المواد الخطرة التي تتطلب لوحات تحذيرية. المصدر: صفحة فئات/تظهيرات CDL في Ohio BMV و49 CFR 383.93."},"26":{"q":"يجب على السائق في أوهايو الذي ينقل السوائل أو الغازات بالجملة في خزان مثبّت بشكل دائم أن يحمل أي تظهير؟","options":["التظهير H","التظهير N","التظهير P","التظهير S"],"explanation":"يُشترط تظهير N (مركبة الخزان) لتشغيل مركبة خزان تحمل مواد سائلة أو غازية بالجملة. المصدر: معلومات التظهير في Ohio BMV و49 CFR 383.93."},"27":{"q":"أي تظهير على رخصة CDL في أوهايو مطلوب لجر مقطورات مزدوجة أو ثلاثية؟","options":["التظهير P","التظهير S","التظهير T","التظهير D"],"explanation":"يُجيز تظهير T تشغيل تركيبات المقطورات المزدوجة/الثلاثية ويُحصل عليه بالنجاح في اختبار المعرفة الخاص بالمقطورات المزدوجة/الثلاثية. المصدر: معلومات التظهير في Ohio BMV و49 CFR 383.93."},"28":{"q":"أي تظهير يحتاجه حامل رخصة CDL في أوهايو لقيادة مركبة تجارية مصممة لنقل 16 راكبًا أو أكثر بما في ذلك السائق (بخلاف الحافلة المدرسية)؟","options":["التظهير N","التظهير P","التظهير T","التظهير H"],"explanation":"يُشترط تظهير P (الركاب) لتشغيل مركبة مصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق. المصدر: معلومات التظهير في Ohio BMV و49 CFR 383.93."},"29":{"q":"في أوهايو، قبل أن يُمكن إصدار تظهير الحافلة المدرسية (S) للسائق، أي تظهير آخر يجب عليه أيضًا الحصول عليه؟","options":["تظهير H (HazMat)","تظهير N (الخزان)","تظهير P (الركاب)","تظهير T (المقطورات المزدوجة/الثلاثية)"],"explanation":"تتطلب القواعد الفيدرالية وقواعد أوهايو أن يقترن تظهير S (الحافلة المدرسية) بتظهير P (الركاب)، نظرًا لأن الحافلة المدرسية تنقل ركابًا. المصدر: معلومات التظهير في Ohio BMV و49 CFR 383.93."},"30":{"q":"قبل منح تظهير HazMat (H)، يجب على المتقدم لرخصة CDL في أوهايو اجتياز أي فحص إضافي بخلاف اختبار المعرفة الكتابي الخاص بـ HazMat؟","options":["تقييم تهديد أمني من TSA يشمل البصمات","اختبار مهارات قيادة ثانٍ في مركبة خزان","فحص نظر تجريه BMV","دورة قيادة دفاعية في قاعة دراسية"],"explanation":"يتطلب تظهير HazMat إجراء تقييم تهديد أمني من إدارة أمن النقل (TSA) مع فحص للخلفية يستند إلى البصمات، إضافة إلى اختبار المعرفة. المصدر: معلومات HazMat في Ohio BMV و49 CFR 1572."},"31":{"q":"يجب على السائق الحصول على تصريح متعلّم تجاري (CLP) في أوهايو والاحتفاظ به لمدة دنيا قبل أن يُسمح له بإجراء اختبار مهارات CDL (اختبار القيادة على الطريق). ما هي مدة الاحتفاظ الدنيا تلك؟","options":["7 days","14 days","30 days","60 days"],"explanation":"تتطلب القاعدة الفيدرالية المعتمدة من أوهايو الاحتفاظ بتصريح CLP لمدة 14 days على الأقل قبل أن يتمكن المتقدم من إجراء اختبار مهارات CDL. المصدر: عملية CDL في Ohio BMV و49 CFR 383.25."},"32":{"q":"عند تشغيل مركبة تجارية بتصريح متعلّم تجاري (CLP) في أوهايو، يجب أن يكون حامل التصريح برفقة من؟","options":["أي سائق مرخّص عمره 25 عامًا أو أكثر","حامل رخصة CDL ذي الفئة/التظهيرات المناسبة جالسًا بجواره","فاحص من BMV فقط","لا أحد، إذا كانت القيادة خلال ساعات النهار"],"explanation":"يجوز لحامل تصريح CLP تشغيل مركبة تجارية فقط عندما يكون برفقة شخص يحمل رخصة CDL صالحة من الفئة والتظهيرات المناسبة، جالسًا بجانب حامل تصريح CLP. المصدر: قواعد CLP في Ohio BMV و49 CFR 383.25."},"33":{"q":"منذ February 7, 2022، يجب على الشخص الذي يحصل على رخصة CDL من الفئة A لأول مرة في أوهايو أن يكمل تدريب السائق المبتدئ (ELDT) المقدّم من جهة هي ماذا؟","options":["مدرجة في سجل مزوّدي التدريب التابع لـ FMCSA","معتمدة من إدارة التعليم في أوهايو","معتمدة فقط من المسجّل النائب المحلي","معتمدة من دورية الطرق السريعة لولاية أوهايو"],"explanation":"يجب أن يُقدَّم تدريب ELDT من مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA، ويجب أن تكون الشهادة في السجل قبل اختبار المهارات/المعرفة. المصدر: قاعدة ELDT التابعة لـ FMCSA (49 CFR 380 subpart F) وtpr.fmcsa.dot.gov."},"34":{"q":"أي من الإجراءات التالية التي تُتخذ لأول مرة لا يُفعّل متطلب تدريب السائق المبتدئ الفيدرالي (ELDT)؟","options":["الحصول على رخصة CDL من الفئة A لأول مرة","الحصول على تظهير الركاب (P) لأول مرة","الحصول على تظهير الخزان (N) لأول مرة","الحصول على تظهير HazMat (H) لأول مرة"],"explanation":"ينطبق تدريب ELDT على رخص CDL من الفئة A/B لأول مرة، والترقية من B إلى A، وتظهيرات P وS وH لأول مرة. أما تظهيرا N (الخزان) وT (المقطورات المزدوجة/الثلاثية) فلا يشملهما تدريب ELDT. المصدر: نطاق تطبيق ELDT التابع لـ FMCSA (tpr.fmcsa.dot.gov/Drivers/Applicability)."},"35":{"q":"ينطبق متطلب ELDT على الأفراد الذين يحصلون على تصريح المتعلّم التجاري الخاص بهم في أو بعد أي تاريخ؟","options":["February 7, 2020","February 7, 2022","January 30, 2021","December 31, 2023"],"explanation":"تنطبق متطلبات تدريب السائق المبتدئ على السائقين الذين يحصلون على تصريح CLP في أو بعد February 7, 2022. المصدر: قاعدة ELDT التابعة لـ FMCSA وtpr.fmcsa.dot.gov."},"36":{"q":"في نموذج الإقرار الذاتي لرخصة CDL في أوهايو، أي فئة تصف السائق الذي يعمل عبر حدود الولايات ويجب أن يستوفي متطلبات الفحص الطبي الفيدرالي من DOT (البطاقة الطبية)؟","options":["معفى بين الولايات (Excepted Interstate)","غير معفى بين الولايات (Non-Excepted Interstate)","معفى داخل الولاية (Excepted Intrastate)","غير معفى داخل الولاية (Non-Excepted Intrastate)"],"explanation":"يعمل السائقون غير المعفيين بين الولايات (Non-Excepted Interstate) في التجارة بين الولايات ويجب أن يستوفوا المعايير الطبية الفيدرالية (Part 391)، مع تقديم شهادة الفاحص الطبي. المصدر: نموذج Ohio BMV رقم BMV 2159 (الإقرار الذاتي لـ CDL) و49 CFR 383.71."},"37":{"q":"ما هي المستندات التي يجب على المتقدم لرخصة CDL لأول مرة في أوهايو تقديمها إلى BMV لإثبات الأهلية؟","options":["إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي الكامل، والإقامة في أوهايو","فقط رخصة قيادة أوهايو الحالية وبطاقة ائتمان","جواز سفر وفاتورتي مرافق، ولكن دون رقم الضمان الاجتماعي","سند ملكية مركبة وإثبات تأمين فقط"],"explanation":"تتطلب أوهايو وثائق إثبات الهوية والوجود القانوني (مثل شهادة الميلاد أو جواز السفر أو بطاقة الإقامة الدائمة)، ورقم الضمان الاجتماعي، وإثبات الإقامة في أوهايو. المصدر: متطلبات مستندات CDL في Ohio BMV (bmv.ohio.gov)."},"38":{"q":"سائق في أوهايو عمره 19 عامًا يرغب في الحصول على رخصة CDL لنقل مواد خطرة تتطلب لوحات تحذيرية. لماذا لا يستطيع هذا السائق الحصول على تظهير HazMat (H)؟","options":["يتطلب نقل HazMat أن يكون العمر 21 عامًا على الأقل","تُصدَر تظهيرات HazMat فقط لسائقي الفئة C","لا تقدّم أوهايو تظهير HazMat","يجب الحصول على تظهير الخزان (N) أولًا"],"explanation":"نقل المواد الخطرة التي تتطلب لوحات تحذيرية قابل للتنفيذ بين الولايات ويتطلب أن يكون عمر السائق 21 عامًا على الأقل؛ ولا يستطيع حاملو رخصة CDL داخل الولاية في أوهايو الذين تتراوح أعمارهم بين 18 و20 عامًا حمل تظهير H. المصدر: أهلية CDL في Ohio BMV و49 CFR 383.93/391.11."},"39":{"q":"في أوهايو، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز أن يكون لدى السائق أثناء تشغيل مركبة تجارية (CMV) قبل اعتباره مختلًّا قانونيًا لأغراض رخصة CDL؟","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"تتبع أوهايو المعيار الفيدرالي للمركبات التجارية: تشغيل مركبة تجارية بتركيز كحول في الدم BAC يبلغ 0.04 percent أو أكثر يُعد مخالفة جسيمة. والعتبة هي نصف حد 0.08 الخاص بالسائقين غير التجاريين. المصدر: دليل CDL في أوهايو / حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.15؛ 49 CFR 383.51."},"40":{"q":"بالحصول على رخصة CDL في أوهايو واستخدامها، يُعتبر السائق قد منح موافقته على الفحص الكيميائي للنفس أو الدم أو البول لتحديد محتوى الكحول أو المخدرات. ماذا يُسمى هذا المبدأ القانوني؟","options":["الموافقة الضمنية","السبب المحتمل","موافقة الإجراءات القانونية الواجبة","الترخيص المشروط"],"explanation":"يعني قانون الموافقة الضمنية في أوهايو أن تشغيل مركبة على طرق أوهايو يشكّل موافقة على الفحص الكيميائي عند التوقيف القانوني بسبب مخالفة كحول/مخدرات. ويترتب على الرفض عقوبات إدارية خاصة به. المصدر: ORC 4511.191؛ دليل CDL في أوهايو."},"41":{"q":"في أوهايو، ما هي مدة إسقاط أهلية CDL الدنيا لأول مخالفة جسيمة للسائق، مثل تركيز BAC يبلغ 0.04+ في مركبة تجارية أو رفض الفحص الكيميائي، أثناء عدم نقل مواد خطرة تتطلب لوحات تحذيرية؟","options":["1 year","60 days","6 months","3 years"],"explanation":"تؤدي أول مخالفة جسيمة (BAC يبلغ 0.04+، أو القيادة تحت تأثير الكحول/المخدرات، أو رفض الفحص، أو مغادرة مكان الحادث، أو استخدام مركبة تجارية في جناية، إلخ) إلى إسقاط أهلية CDL لمدة 1 year في أوهايو. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"42":{"q":"إذا ارتكب سائق في أوهايو أول مخالفة جسيمة (مثل BAC يبلغ 0.04+) أثناء تشغيل مركبة تجارية تحمل لوحات تحذيرية للمواد الخطرة، تُزاد مدة إسقاط الأهلية إلى:","options":["3 years","1 year","5 years","مدى الحياة"],"explanation":"عندما تقع أول مخالفة جسيمة في مركبة تحمل لوحات تحذيرية للمواد الخطرة، يُزاد إسقاط الأهلية المعتاد البالغ 1 year إلى 3 years. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"43":{"q":"ما هي مدة إسقاط أهلية CDL في أوهايو لثاني مخالفة جسيمة (على سبيل المثال، ثاني قيادة تحت تأثير الكحول/المخدرات أو ثاني BAC يبلغ 0.04+ في مركبة تجارية)؟","options":["مدى الحياة","10 years","3 years","5 years"],"explanation":"تؤدي ثاني إدانة بأي مخالفة جسيمة إلى إسقاط أهلية CDL مدى الحياة في أوهايو. وقد يُخفَّض بعض إسقاطات الأهلية مدى الحياة إلى 10 years بعد استيفاء شروط إعادة الإصدار. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"44":{"q":"سائق في أوهايو موقوف قانونيًا بتهمة القيادة تحت تأثير الكحول/المخدرات يرفض الخضوع لفحص النفس الكيميائي. لأغراض رخصة CDL، يؤدي رفض الفحص إلى إسقاط الأهلية لمدة لا تقل عن:","options":["1 year","90 days","60 days","30 days"],"explanation":"يُعامَل رفض الفحص كمخالفة جسيمة لأغراض رخصة CDL، ويترتب عليه إسقاط الأهلية لمدة 1 year (3 years إذا كان ينقل مواد خطرة تتطلب لوحات تحذيرية)، إضافة إلى أي تعليق إداري للرخصة. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"45":{"q":"بموجب قانون الموافقة الضمنية في أوهايو، يواجه حامل رخصة CDL الذي يرفض الفحص الكيميائي أيضًا تعليقًا إداريًا للرخصة. بالنسبة لأول رفض، يكون هذا التعليق الإداري عمومًا:","options":["1 year","90 days","6 months","2 years"],"explanation":"يفرض قانون الموافقة الضمنية في أوهايو تعليقًا إداريًا للرخصة لمدة 1 year لأول رفض لفحص كيميائي، مع مدد أطول لحالات الرفض المتكررة خلال 10 years. وهذا منفصل عن إسقاط أهلية CDL. المصدر: ORC 4511.191."},"46":{"q":"في أوهايو، كم عدد المخالفات المرورية الخطيرة في حوادث منفصلة خلال فترة 3 سنوات التي تُفعّل إسقاط أهلية CDL لمدة 60 يومًا؟","options":["2","3","4","5"],"explanation":"تؤدي الإدانة بمخالفتين مروريتين خطيرتين خلال 3 سنوات (في مركبة تجارية) إلى إسقاط الأهلية لمدة 60 days. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"47":{"q":"يُدان حامل رخصة CDL في أوهايو بثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات. ما هي مدة إسقاط أهلية CDL؟","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي الإدانة بثلاث مخالفات مرورية خطيرة أو أكثر خلال 3 سنوات إلى إسقاط الأهلية لمدة 120 days. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"48":{"q":"بكم يجب أن يتجاوز سائق CDL حد السرعة المعلن ليُحرّر له مخالفة تُحتسب كمخالفة مرورية خطيرة في أوهايو؟","options":["15 mph أو أكثر فوق الحد","10 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","5 mph أو أكثر فوق الحد"],"explanation":"تُصنّف السرعة الزائدة بمقدار 15 mph أو أكثر فوق الحد المعلن كمخالفة مرورية خطيرة لحاملي رخصة CDL. المصدر: دليل CDL في أوهايو؛ ORC 4506.01/4506.16؛ 49 CFR 383.51."},"49":{"q":"أي مما يلي يُصنّف كمخالفة مرورية خطيرة لحامل رخصة CDL في أوهايو؟","options":["السير على نحو قريب جدًا (عدم ترك مسافة كافية)","الوقوف في منطقة ممنوع الوقوف فيها","مصباح لوحة ترخيص غير مضاء","أول مخالفة لحمولة زائدة الوزن"],"explanation":"تشمل المخالفات المرورية الخطيرة السير على نحو قريب جدًا، وتغيير المسار بتهور/على نحو غير منتظم، والسرعة الزائدة بمقدار 15+ mph، والمراسلة النصية أثناء القيادة، وتشغيل مركبة تجارية دون الفئة/التظهير المناسب. أما مخالفات المعدات والوقوف فليست مخالفات خطيرة. المصدر: دليل CDL في أوهايو؛ 49 CFR 383.51."},"50":{"q":"في أوهايو، يُحظر استخدام هاتف محمول باليد أو المراسلة النصية أثناء تشغيل مركبة تجارية. لأغراض رخصة CDL، تُحتسب مثل هذه الإدانة على أنها:","options":["مخالفة مرورية خطيرة","مخالفة جسيمة","مخالفة أمر خارج الخدمة","مخالفة غير قابلة للتسجيل"],"explanation":"تُعد المراسلة النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية مخالفة مرورية خطيرة؛ ومخالفتان خلال 3 سنوات تؤديان إلى إسقاط الأهلية لمدة 60 days، وثلاث مخالفات تؤدي إلى 120 days. المصدر: دليل CDL في أوهايو؛ 49 CFR 383.51 و392.80/392.82."},"51":{"q":"ما هو الحد الأقصى للعقوبة المدنية الفيدرالية للسائق (المطبّقة في أوهايو) لسائق مركبة تجارية يرسل رسائل نصية أثناء قيادة مركبة تجارية؟","options":["حتى $2,750","حتى $500","حتى $1,000","حتى $11,000"],"explanation":"يواجه سائق المركبة التجارية الذي يرسل رسائل نصية أثناء القيادة عقوبة مدنية فيدرالية تصل إلى $2,750؛ أما شركات النقل التي تسمح بذلك فيمكن تغريمها حتى $11,000. وتنطبق هذه القواعد في أوهايو. المصدر: 49 CFR 392.80؛ قاعدة FMCSA لحظر المراسلة النصية."},"52":{"q":"يرتكب حامل رخصة CDL في أوهايو أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع (مثل عدم التوقف حيث يكون مطلوبًا). ما هي مدة إسقاط الأهلية؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع إلى إسقاط أهلية CDL لمدة 60 days. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"53":{"q":"ما هي مدة إسقاط أهلية CDL في أوهايو لثاني مخالفة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات؟","options":["120 days","60 days","180 days","1 year"],"explanation":"تؤدي ثاني مخالفة عند تقاطع السكة الحديدية مع الطريق خلال 3 سنوات إلى إسقاط الأهلية لمدة 120 days. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"54":{"q":"يرتكب حامل رخصة CDL في أوهايو ثالث مخالفة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات. تكون مدة إسقاط الأهلية:","options":["1 year","120 days","180 days","2 years"],"explanation":"تؤدي ثالث مخالفة أو أكثر عند تقاطع السكة الحديدية مع الطريق خلال 3 سنوات إلى إسقاط الأهلية لمدة 1 year (365 days). المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"55":{"q":"ما هي مدة إسقاط أهلية CDL في أوهايو لأول إدانة للسائق بمخالفة أمر خارج الخدمة (OOS)؟","options":["180 days","60 days","1 year","90 days"],"explanation":"تؤدي أول إدانة بمخالفة أمر خارج الخدمة إلى إسقاط الأهلية لمدة لا تقل عن 180 days. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"56":{"q":"في أوهايو، ما هي مدة إسقاط أهلية CDL لثاني مخالفة أمر خارج الخدمة (OOS) في حوادث منفصلة خلال فترة 10 سنوات؟","options":["2 years","1 year","180 days","3 years"],"explanation":"تؤدي ثاني مخالفة أمر خارج الخدمة خلال فترة 10 سنوات إلى إسقاط الأهلية لمدة 2 years. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"57":{"q":"يُدان حامل رخصة CDL في أوهايو بثالث مخالفة أمر خارج الخدمة خلال فترة 10 سنوات. تكون مدة إسقاط الأهلية:","options":["3 years","2 years","180 days","5 years"],"explanation":"تؤدي ثالث مخالفة أمر خارج الخدمة أو أكثر خلال 10 سنوات إلى إسقاط الأهلية لمدة 3 years. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"58":{"q":"يخالف سائق في أوهايو أمر خروج عن الخدمة أثناء نقل مواد خطرة تتطلب لوحات تحذيرية أو تشغيل مركبة مصممة لنقل 16 راكبًا أو أكثر. ما هو إسقاط الأهلية لهذه المخالفة الأولى؟","options":["180 days","60 days","1 year","2 years"],"explanation":"تترتب على أول مخالفة لأمر خارج الخدمة أثناء نقل مواد خطرة تتطلب لوحات تحذيرية أو نقل 16+ راكبًا مدة إسقاط أهلية تبلغ 180 days؛ أما أي مخالفة لاحقة من هذا النوع خلال 10 سنوات فتترتب عليها 3 years. المصدر: حالات إسقاط أهلية CDL في Ohio BMV؛ ORC 4506.16؛ 49 CFR 383.51."},"59":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية أوهايو، عندما تقترب من شاحنة قطر متوقفة، أو مركبة صيانة طرق، أو سيارة شرطة تعرض أضواءً وامضة على طريق سريع يحتوي على مسارين أو أكثر في اتجاهك، فماذا يجب أن تفعل؟","options":["الانتقال إلى مسار غير مجاور للمركبة المتوقفة عندما يكون من الآمن القيام بذلك","التوقف توقفاً كاملاً حتى تتحرك المركبة","إطلاق بوق سيارتك باستمرار أثناء التجاوز","الحفاظ على سرعتك مع تشغيل أضواء التحذير الرباعية"],"explanation":"يتطلب قانون \"أفسح الطريق\" في ولاية أوهايو (ORC 4511.213) من السائق المقترب من مركبة سلامة عامة أو طوارئ أو خدمة طرق أو صيانة متوقفة تعرض أضواءً وامضة أن ينتقل إلى مسار غير مجاور لتلك المركبة عندما يكون هناك مساران على الأقل في الاتجاه نفسه ويكون ذلك آمناً. المصدر: Ohio Revised Code 4511.213."},"60":{"q":"بموجب قانون \"أفسح الطريق\" في ولاية أوهايو، إذا لم تتمكن من تغيير المسار بأمان (على سبيل المثال على طريق ذي مسارين) عند تجاوز مركبة طوارئ متوقفة بأضواء وامضة، فماذا يتطلب القانون؟","options":["المتابعة بحذر واجب، وتخفيف السرعة، والحفاظ على سرعة آمنة مناسبة للظروف","التوقف توقفاً كاملاً والانتظار حتى يشير لك ضابط بالمرور","المتابعة بالسرعة القصوى المسموح بها دون إبطاء","الانحراف إلى الكتف والتوقف"],"explanation":"عندما يكون تغيير المسار مستحيلاً أو غير آمن، يتطلب القانون ORC 4511.213 من السائق المتابعة بحذر واجب، وتخفيف السرعة، والحفاظ على سرعة آمنة مناسبة لظروف الطريق والطقس وحركة المرور. المصدر: Ohio Revised Code 4511.213."},"61":{"q":"في ولاية أوهايو، يجب على السائق الذي ينقل مواد خطرة موضوعة عليها لوحات تحذيرية أو الذي يقود حافلة أن يتوقف قبل ملتقى السكة الحديدية ضمن أي مسافة من أقرب قضيب؟","options":["ما لا يقل عن 15 قدماً وما لا يزيد عن 50 قدماً","ما لا يقل عن 5 أقدام وما لا يزيد عن 25 قدماً","ما لا يقل عن 25 قدماً وما لا يزيد عن 75 قدماً","ما لا يقل عن 10 أقدام وما لا يزيد عن 100 قدم"],"explanation":"يجب على سائق الحافلة أو المركبة التي تعرض لوحات المواد الخطرة أن يتوقف ضمن مسافة 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب عند ملتقى السكة الحديدية، ثم ينظر ويصغي قبل المتابعة. المصدر: دليل CDL لولاية أوهايو / 49 CFR 392.10؛ التوقف الإلزامي مطلوب بموجب ORC 4511.63."},"62":{"q":"أي من المركبات التالية مُطالَبة بالتوقف عند كل ملتقى للسكة الحديدية غير المُعفى في ولاية أوهايو؟","options":["مركبة تنقل مواد يجب وضع لوحات تحذيرية عليها بموجب قواعد المواد الخطرة الفيدرالية","أي شاحنة بيك أب تقطر مقطورة خدمات","أي شاحنة مستقيمة بوزن إجمالي يتجاوز 10,000 رطل","أي مركبة بعجلات خلفية مزدوجة"],"explanation":"يتطلب القانون ORC 4511.63 من سائق أي حافلة، أو أي مركبة مدرسية، أو أي مركبة تنقل مواد يجب وضع لوحات تحذيرية عليها بموجب 49 CFR Parts 100-185 أن يتوقف قبل عبور خط السكة الحديدية. الشاحنات والمقطورات العادية غير خاضعة للتوقف الإلزامي. المصدر: Ohio Revised Code 4511.63."},"63":{"q":"على طريق ذي مسارين في ولاية أوهايو، عندما تواجه حافلة مدرسية متوقفة تقوم بتحميل أو إنزال الأطفال وأضواؤها الحمراء وامضة، يجب أن تتوقف على مسافة لا تقل عن كم من الحافلة؟","options":["لا تقل عن 10 أقدام من مقدمة الحافلة أو مؤخرتها","لا تقل عن 20 قدماً من مقدمة الحافلة أو مؤخرتها","لا تقل عن 30 قدماً من مقدمة الحافلة أو مؤخرتها","لا تقل عن 50 قدماً من مقدمة الحافلة أو مؤخرتها"],"explanation":"يتطلب القانون ORC 4511.75 من السائق الذي يواجه أو يتجاوز حافلة مدرسية متوقفة أن يتوقف على مسافة لا تقل عن 10 أقدام من مقدمة الحافلة أو مؤخرتها وألا يتابع حتى تتحرك الحافلة أو يشير السائق بالمتابعة. المصدر: Ohio Revised Code 4511.75."},"64":{"q":"في ولاية أوهايو، على طريق سريع مقسوم إلى كم من مسارات المرور يمكن لحركة المرور القادمة في الاتجاه المعاكس أن تستمر دون التوقف لحافلة مدرسية متوقفة على الجانب المقابل؟","options":["أربعة مسارات أو أكثر","مساران أو أكثر","ثلاثة مسارات أو أكثر","ستة مسارات أو أكثر"],"explanation":"ينص قانون الحافلات المدرسية في ولاية أوهايو على أنه في الطريق السريع المكون من أربعة مسارات أو أكثر، لا يلزم السائق التوقف لحافلة مدرسية متوقفة على الجانب المقابل؛ فقط حركة المرور المتجهة في الاتجاه نفسه للحافلة يجب أن تتوقف. المصدر: Ohio Revised Code 4511.75."},"65":{"q":"بعد التوقف لحافلة مدرسية في ولاية أوهايو على طريق ذي مسارين، متى يمكنك المتابعة؟","options":["عندما تستأنف الحافلة الحركة أو يشير سائق الحافلة لك بالمتابعة","بمجرد نزول الأطفال عن الطريق","بعد انتظار إلزامي مدته 30 ثانية","كلما بدأت الأضواء الكهرمانية للحافلة بالوميض"],"explanation":"ينص القانون ORC 4511.75 على أن السائق المتوقف يجب ألا يتابع حتى تستأنف الحافلة المدرسية الحركة أو حتى يشير له سائق الحافلة المدرسية بالمتابعة. المصدر: Ohio Revised Code 4511.75."},"66":{"q":"ما هي السرعة القصوى المسموح بها لشاحنة مقطورة على طريق سريع بين الولايات في المناطق الريفية في ولاية أوهايو (ما لم يُعلَن عن حد أدنى)؟","options":["70 ميلاً في الساعة، مثلها مثل سيارات الركاب","55 ميلاً في الساعة، أقل من سيارات الركاب","60 ميلاً في الساعة، أقل من سيارات الركاب","65 ميلاً في الساعة، أقل من سيارات الركاب"],"explanation":"لا تحدد ولاية أوهايو حداً منفصلاً وأدنى للسرعة بالنسبة للشاحنات. بموجب القانون ORC 4511.21، يبلغ الحد الأقصى على الطرق السريعة بين الولايات في المناطق الريفية 70 ميلاً في الساعة، ويمكن للشاحنات التجارية السير بنفس الحد المسموح به للسيارات ما لم يُعلَن عن خلاف ذلك. المصدر: Ohio Revised Code 4511.21؛ قواعد مناطق السرعة لدى ODOT."},"67":{"q":"ما هو الحد الأقصى للسرعة للشاحنات التجارية على المسار الرئيسي لطريق أوهايو السريع المدفوع (Ohio Turnpike)؟","options":["70 ميلاً في الساعة، مثلها مثل مركبات الركاب","65 ميلاً في الساعة للشاحنات بينما يمكن للسيارات السير بسرعة 70","55 ميلاً في الساعة لجميع الشاحنات","60 ميلاً في الساعة للشاحنات بينما يمكن للسيارات السير بسرعة 70"],"explanation":"يعلن طريق أوهايو السريع المدفوع عن حد سرعة قدره 70 ميلاً في الساعة على المسار الرئيسي ينطبق على جميع المركبات، بما في ذلك الشاحنات التجارية؛ ولا تفرض ولاية أوهايو سرعة أدنى منفصلة للشاحنات. المصدر: Ohio Turnpike and Infrastructure Commission؛ ORC 4511.21."},"68":{"q":"على طريق متعدد المسارات في ولاية أوهايو، يُطالَب سائق الشاحنة الذي يسير بسرعة أبطأ من سرعة حركة المرور السائدة عموماً بأن يفعل ماذا؟","options":["القيادة في المسار الأيمن المتاح لحركة المرور، إلا عند التجاوز أو الانعطاف يساراً","البقاء في المسار الأوسط لتجنب المركبات المندمجة","استخدام المسار الأيسر حتى تتمكن حركة المرور الأسرع من الاندماج على اليمين","استخدام أي مسار طالما أن أضواء التحذير الرباعية مشغلة"],"explanation":"يتطلب القانون ORC 4511.25 أن تُقاد المركبة التي تسير بسرعة أبطأ من السرعة القانونية السائدة في المسار الأيمن المتاح لحركة المرور، وعلى مسافة كافية إلى اليمين للسماح بالتجاوز الآمن، إلا عند التجاوز أو الانعطاف يساراً أو عندما يتطلب المسار استخدام مسار آخر. المصدر: Ohio Revised Code 4511.25."},"69":{"q":"عندما تتعطل شاحنة وتتوقف على طريق في ولاية أوهايو، كيف ينبغي وضع أجهزة التحذير الثلاثة (الشُّعَل، أو العاكسات، أو الفوانيس)؟","options":["واحد على بعد نحو 100 قدم أماماً، وواحد على بعد نحو 100 قدم خلفاً، وواحد على جانب حركة المرور","وضع الثلاثة جميعاً مباشرة خلف المركبة في صف واحد","واحد على كل جانب وواحد على سقف المقصورة","واحد على بعد 10 أقدام أماماً، وواحد على بعد 10 أقدام خلفاً، وواحد على الكتف"],"explanation":"يتطلب القانون ORC 4513.28 وضع أجهزة التحذير على بعد نحو 100 قدم أمام المركبة، ونحو 100 قدم خلفها، وواحد على جانب حركة المرور من المركبة المتعطلة. المصدر: Ohio Revised Code 4513.28."},"70":{"q":"كيف يُصنَّف انتهاك المخالفة الأولى لقانون \"أفسح الطريق\" في ولاية أوهايو (ORC 4511.213)؟","options":["جنحة بسيطة مع مضاعفة الغرامة (حتى نحو 300 دولار)","جناية من الدرجة الخامسة","مخالفة مدنية غير متحركة بدون نقاط","جنحة من الدرجة الأولى مع سجن إلزامي"],"explanation":"المخالفة الأولى بموجب ORC 4511.213 هي جنحة بسيطة، لكن يجب على المحكمة فرض غرامة بضعفي المبلغ المعتاد، مما يجعلها تصل إلى نحو 300 دولار. وتتصاعد المخالفات المتكررة خلال سنة إلى جنح من الدرجتين الرابعة والثالثة. المصدر: Ohio Revised Code 4511.213."},"71":{"q":"في ولاية أوهايو، ما هو الحد الأقصى القانوني لعرض المركبة التجارية أو الحمولة قبل أن يصبح تصريح الحجم الزائد مطلوباً؟","options":["8 أقدام و6 بوصات (102 بوصة)","8 أقدام و0 بوصة (96 بوصة)","9 أقدام و0 بوصة (108 بوصات)","10 أقدام و0 بوصة (120 بوصة)"],"explanation":"الحد الأقصى القانوني لعرض المركبة في ولاية أوهايو هو 8 أقدام و6 بوصات (102 بوصة)؛ وأي شيء أعرض من ذلك يتطلب تصريح نقل خاصاً من ODOT. المصدر: ORC 5577.05؛ قواعد تصاريح النقل الخاصة لدى Ohio DOT."},"72":{"q":"في ولاية أوهايو، ما هو الحد الأقصى القانوني لارتفاع المركبة والحمولة قبل أن يصبح التصريح مطلوباً؟","options":["13 قدماً و6 بوصات","12 قدماً و6 بوصات","14 قدماً و0 بوصة","13 قدماً و0 بوصة"],"explanation":"الحد الأقصى القانوني للارتفاع في ولاية أوهايو هو 13 قدماً و6 بوصات؛ والحمولات الأطول من ذلك تتطلب تصريح حجم زائد من ODOT. المصدر: ORC 5577.05؛ دليل تشغيل تصاريح النقل الخاصة لدى Ohio DOT."},"73":{"q":"من الذي يصدر التصريح الخاص الذي يسمح لمركبة ذات حجم زائد أو وزن زائد بالعمل على طرق ولاية أوهايو؟","options":["مدير النقل في ولاية أوهايو (ODOT)","مكتب المركبات الآلية في ولاية أوهايو (BMV)","مأمور المقاطعة لكل مقاطعة على المسار","قائد مركز دورية الطرق السريعة في ولاية أوهايو"],"explanation":"لا يجوز للمركبات التي تتجاوز حدود الحجم أو الوزن القانونية العمل على طريق الولاية إلا بموجب تصريح خطي خاص صادر عن مدير النقل في ولاية أوهايو. المصدر: ORC 4513.34 و5577.04؛ تصاريح النقل الخاصة لدى ODOT."},"74":{"q":"في ولاية أوهايو، ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به دون تصريح وزن زائد، بما يتفق مع الحد الفيدرالي؟","options":["80,000 رطل","73,280 رطلاً","90,000 رطل","100,000 رطل"],"explanation":"تتبع ولاية أوهايو الحد الأقصى الفيدرالي للوزن الإجمالي البالغ 80,000 رطل (الخاضع لمعادلة الجسور الفيدرالية)؛ وتجاوزه يتطلب تصريح وزن زائد من ODOT. المصدر: ORC 5577.04؛ معادلة الجسور الفيدرالية (Federal Bridge Formula)."},"75":{"q":"عندما تقترب مركبة مواد خطرة موضوعة عليها لوحات تحذيرية من ملتقى سكة حديدية في ولاية أوهايو، أي إجراء يكون صحيحاً أثناء عبور القضبان؟","options":["عدم تغيير التروس أثناء وجود أي جزء من المركبة على القضبان","التحول إلى ترس أدنى أثناء العبور للتحكم بشكل أفضل","التوقف في منتصف العبور للتحقق من وجود قطار ثانٍ","إيقاف تشغيل المحرك حتى العبور الكامل للقضبان"],"explanation":"بعد التوقف والنظر والإصغاء، يجب على السائق العبور بترس لا يحتاج إلى تغيير، ويجب ألا يغير التروس أثناء وجود أي جزء من المركبة على القضبان. المصدر: دليل CDL لولاية أوهايو / 49 CFR 392.10؛ ORC 4511.63."},"76":{"q":"على طريق سريع مقسوم بأربعة مسارات في ولاية أوهايو، يجب على الحافلة المدرسية المتوقفة لإنزال الأطفال، حيثما أمكن ذلك، أن تفعل ماذا لتقليل خطر عبور الطريق؟","options":["استقبال الركاب وإنزالهم على جانب الإقامة من الطريق السريع","التوقف في الجزيرة الوسطى حتى يتمكن الأطفال من استخدام الممر العابر","إنزال جميع الركاب على الكتف الأيسر","مطالبة جميع الأطفال بأن يرافقهم السائق عبر الطريق"],"explanation":"على الطرق السريعة المقسومة أو الطرق ذات الأربعة مسارات أو أكثر، يُفترض أن تستقبل الحافلات المدرسية الأطفال وتنزلهم على جانب الإقامة حتى لا يضطر الأطفال إلى عبور الطريق؛ وهذا هو السبب في أن حركة المرور القادمة في الاتجاه المعاكس لا يلزمها التوقف. المصدر: Ohio Revised Code 4511.75؛ لوائح الحافلات المدرسية في ولاية أوهايو."},"77":{"q":"بموجب قانون ولاية أوهايو، عندما توضع علامة قف (STOP) معلنة عند ملتقى سكة حديدية معيَّن على أنه خطير، يجب على السائق أن يتوقف ضمن أي مسافة من أقرب قضيب؟","options":["ما لا يقل عن 15 قدماً ولكن ضمن 50 قدماً","ما لا يقل عن 5 أقدام ولكن ضمن 20 قدماً","ما لا يقل عن 30 قدماً ولكن ضمن 60 قدماً","بالضبط 25 قدماً من أقرب قضيب"],"explanation":"يتطلب القانون ORC 4511.61 من السائق أن يتوقف ضمن خمسين قدماً ولكن ليس أقل من خمس عشرة قدماً من أقرب قضيب عند ملتقى سكة حديدية أُقيمت عنده علامة قف، وألا يتابع حتى يكون الأمر آمناً. المصدر: Ohio Revised Code 4511.61."},"78":{"q":"أي عبارة تصف على نحو أفضل ما إذا كانت ولاية أوهايو تفرض حدوداً للسرعة خاصة بالشاحنات منفصلة عن السيارات؟","options":["تحدد ولاية أوهايو نفس الحدود القصوى للسرعة للشاحنات والسيارات؛ ولا تُسند للشاحنات حداً أدنى منفصلاً على مستوى الولاية","تُحدَّد سرعة الشاحنات دائماً بـ 55 ميلاً في الساعة على مستوى الولاية بغض النظر عن الحد المعلن","يجب أن تسير الشاحنات بسرعة 10 أميال في الساعة أقل من حد السيارات المعلن على جميع الطرق السريعة","يجوز للشاحنات استخدام طريق أوهايو السريع المدفوع فقط وهي ممنوعة من الطرق السريعة بين الولايات"],"explanation":"تطبق ولاية أوهايو نفس الحدود القصوى المعلنة للسرعة على الشاحنات التجارية وسيارات الركاب بموجب ORC 4511.21؛ ولا يوجد حد أدنى منفصل للسرعة للشاحنات على مستوى الولاية، مع أنه لا يزال على السائقين القيادة بسرعة آمنة مناسبة للظروف. المصدر: Ohio Revised Code 4511.21؛ ODOT."},"79":{"q":"أي وكالة حكومية في الولاية تصدر رخص القيادة التجارية (CDLs) في ولاية أوهايو؟","options":["مكتب المركبات الآلية في ولاية أوهايو (BMV)","إدارة النقل في ولاية أوهايو (ODOT)","دورية الطرق السريعة في ولاية أوهايو","الإدارة الفيدرالية لسلامة ناقلات النقل بالمحركات (FMCSA)"],"explanation":"في ولاية أوهايو، يصدر مكتب المركبات الآلية (BMV)، وهو قسم تابع لإدارة السلامة العامة في ولاية أوهايو، جميع رخص القيادة بما في ذلك رخص CDL. وتتولى ODOT الطرق وتصاريح الحجم الزائد/الوزن الزائد، لا الترخيص، أما FMCSA فهي الوكالة الفيدرالية التي تضع المعايير. المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."},"80":{"q":"قبل أن يتمكن المتقدم لرخصة CDL في ولاية أوهايو من إجراء أي اختبار معرفة تجاري، أين يجب إكمال ذلك الاختبار؟","options":["شخصياً في محطة اختبار السائقين التابعة لـ Ohio BMV","عبر الإنترنت من أي حاسوب منزلي","بالبريد باستخدام ورقة إجابات تُحل في المنزل","لدى مزود تدريب ELDT مسجل لدى FMCSA"],"explanation":"تتطلب ولاية أوهايو أن تُجرى اختبارات معرفة CDL (المعرفة العامة، والتصديقات، وإزالة قيد المكابح الهوائية) شخصياً في محطة اختبار السائقين التابعة لـ BMV؛ ولا يمكن إجراؤها عبر الإنترنت. ومزودو ELDT يقدمون التدريب، لا اختبار المعرفة الخاص بالولاية. المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."},"81":{"q":"ما هي مدة صلاحية تصريح المتعلم التجاري (CLP) في ولاية أوهايو بمجرد إصداره؟","options":["12 شهراً","6 أشهر","30 يوماً","24 شهراً"],"explanation":"تنص ولاية أوهايو على أن تصريح CLP صالح لمدة 12 شهراً. (بموجب القاعدة الفيدرالية يمكن تجديده مرة واحدة دون إعادة إجراء اختبار المعرفة العامة.) وتعكس البدائل المضللة فترات تصاريح شائعة لكنها غير صحيحة. المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."},"82":{"q":"بعد الحصول على تصريح CLP في ولاية أوهايو، كم يجب على المتقدم الاحتفاظ به قبل أن يصبح مؤهلاً لإجراء اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","10 أيام على الأقل","60 يوماً على الأقل"],"explanation":"تتطلب اللائحة الفيدرالية، المطبقة في ولاية أوهايو، الاحتفاظ بتصريح CLP لمدة لا تقل عن 14 يوماً قبل أن يتمكن حامله من إجراء اختبار مهارات CDL (اختبار الطريق). المصدر: عملية CDL لدى Ohio BMV / 49 CFR 383.25 (FMCSA)."},"83":{"q":"يُجرى اختبار مهارات CDL في ولاية أوهايو على ثلاثة أجزاء. أي مجموعة تسرد بشكل صحيح هذه الأجزاء الثلاثة؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي (المناورة)، والقيادة على الطريق","اختبار المعرفة الكتابي، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، وفحص المكابح الهوائية، والتعامل مع المواد الخطرة","التحكم الأساسي، والقيادة الليلية، واختبار تصديق كتابي"],"explanation":"يتكون اختبار مهارات CDL في ولاية أوهايو من ثلاثة أجزاء: فحص ما قبل الرحلة، واختبار التحكم الأساسي (المناورة)، واختبار القيادة على الطريق. وفحص النظر والاختبارات الكتابية منفصلة عن اختبار المهارات. المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."},"84":{"q":"ما الذي يجب على المتقدم في ولاية أوهايو تقديمه إلكترونياً قبل أن يتمكن من جدولة اختبار مهارات CDL أو محاولة إجرائه؟","options":["إثبات إكمال تدريب السائق المبتدئ (ELDT)، أو إثبات الإعفاء منه","إثبات خبرة قيادة سابقة لمدة سنتين","خطاب رعاية موقَّع من صاحب العمل","درجة نجاح في دورة قيادة دفاعية"],"explanation":"تتطلب ولاية أوهايو إثباتاً إلكترونياً لإكمال تدريب السائق المبتدئ (ELDT) التابع لـ FMCSA بما يطابق الفئة/التصديق المطلوب، أو إثبات الإعفاء، قبل أن يُجدول اختبار المهارات أو تُحاوَل إجراؤه. المصدر: صفحة CDL لدى Ohio BMV / قاعدة ELDT لدى FMCSA (49 CFR Part 380)."},"85":{"q":"تتطلب عملية الإقرار الذاتي في ولاية أوهايو من المتقدم لرخصة CDL/CLP الاختيار من بين كم فئة من فئات نوع القيادة؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يجب على سائقي ولاية أوهايو الإقرار ذاتياً بإحدى أربع فئات: غير معفى بين الولايات، ومعفى بين الولايات، وغير معفى داخل الولاية، ومعفى داخل الولاية. المصدر: الإقرار الذاتي لـ CDL لدى Ohio BMV (النموذج BMV 2159)."},"86":{"q":"يعبر سائق في ولاية أوهايو حدود الولاية لأغراض العمل ويجب أن يستوفي معايير التأهيل البدني (الطبي) الفيدرالية بموجب 49 CFR Part 391. أي فئة من فئات الإقرار الذاتي تنطبق؟","options":["غير معفى بين الولايات (Non-Excepted Interstate)","معفى بين الولايات (Excepted Interstate)","غير معفى داخل الولاية (Non-Excepted Intrastate)","معفى داخل الولاية (Excepted Intrastate)"],"explanation":"تشمل فئة \"غير معفى بين الولايات\" السائقين الذين يعملون عبر حدود الولايات ويجب أن يستوفوا المتطلبات الطبية الفيدرالية في 49 CFR Part 391؛ ويجب على هؤلاء السائقين الاحتفاظ بشهادة فاحص طبي سارية في الملف. المصدر: فئات الإقرار الذاتي لدى Ohio BMV (النموذج BMV 2159)."},"87":{"q":"اعتباراً من 23 يونيو 2025، كيف تُقدَّم معلومات شهادة الفاحص الطبي DOT الخاصة بحامل رخصة CDL إلى Ohio BMV؟","options":["تنقل FMCSA نتائج الفحص إلكترونياً إلى BMV، لذا لم تعد الشهادة الورقية مطلوبة","يجب على السائق إرسال نسخة ورقية موثَّقة بالبريد إلى BMV خلال 10 أيام","يرسل الفاحص الطبي بالفاكس بطاقة محفظة يقوم السائق بتغليفها","تُرفع الشهادة فقط من قِبل صاحب عمل السائق"],"explanation":"اعتباراً من 23 يونيو 2025، تنقل FMCSA إلكترونياً نتائج الفحص الطبي (ومعلومات الإعفاء) للمتقدمين لتصريح CLP وحاملي رخصة CDL إلى Ohio BMV، لذا لم يعد السائقون يقدمون شهادة فاحص طبي ورقية. المصدر: إشعار الشهادة الطبية لـ CDL لدى Ohio BMV / قاعدة دمج اعتماد شهادة الفاحص الطبي لدى FMCSA."},"88":{"q":"أي نموذج من نماذج Ohio BMV يُستخدم للإقرار الذاتي بنوع القيادة التجارية للسائق في رخصة CDL؟","options":["BMV 2159 (تفويض الإقرار الذاتي لـ CDL)","BMV 2290 (نموذج ضريبة استخدام المركبات الثقيلة)","BMV 5759 (نموذج تصديق المواد الخطرة)","BMV 1173 (نموذج تسجيل المركبة)"],"explanation":"تستخدم ولاية أوهايو النموذج BMV 2159، تفويض الإقرار الذاتي لـ CDL، ليُقر السائق بإحدى فئات نوع القيادة الأربع. المصدر: نموذج Ohio BMV رقم BMV 2159."},"89":{"q":"ما هو الحد الأدنى لعدد الإجابات الصحيحة اللازمة لاجتياز اختبار المعرفة العامة لـ CDL في ولاية أوهايو المكون من 50 سؤالاً؟","options":["40 إجابة صحيحة (80%)","35 إجابة صحيحة (70%)","45 إجابة صحيحة (90%)","30 إجابة صحيحة (60%)"],"explanation":"تتطلب اختبارات معرفة CDL في ولاية أوهايو درجة لا تقل عن 80% للنجاح؛ وفي اختبار المعرفة العامة المكون من 50 سؤالاً يعني ذلك 40 إجابة صحيحة. وينطبق معيار الـ 80% على اختبارات التصديق أيضاً. المصدر: دليل CDL لولاية أوهايو / معايير الاختبار لدى Ohio BMV."},"90":{"q":"وفقاً لقانون أوهايو المنقح 4506.14 (Ohio Revised Code 4506.14)، ما هي أقصى مدة يمكن خلالها إصدار رخصة CDL قياسية (غير خاصة بالمواد الخطرة) في ولاية أوهايو؟","options":["ثماني سنوات","أربع سنوات","خمس سنوات","عشر سنوات"],"explanation":"ينص القانون ORC 4506.14 على أنه لا يجوز إصدار أي رخصة CDL لمدة أطول من ثماني سنوات؛ وترتبط رخص CDL بعيد ميلاد المرخَّص له. غير أن تصديق المواد الخطرة يقصر الإصدار على أربع سنوات و180 يوماً. المصدر: Ohio Revised Code 4506.14."},"91":{"q":"بسبب حدود التحقق من الخلفية الفيدرالي (TSA)، لا يمكن إصدار رخصة CDL في ولاية أوهايو تحمل تصديق المواد الخطرة لمدة أطول من أي فترة؟","options":["أربع سنوات و180 يوماً","أربع سنوات بالضبط","خمس سنوات","ثماني سنوات"],"explanation":"يحدد القانون ORC 4506.14 سقف رخصة CDL التي تحمل تصديق المواد الخطرة بأربع سنوات و180 يوماً، بما يتماشى مع دورة تقييم التهديد الأمني الفيدرالي للمواد الخطرة. ويمكن أن تمتد رخص CDL القياسية حتى ثماني سنوات. المصدر: Ohio Revised Code 4506.14."},"92":{"q":"بموجب قانون ولاية أوهايو، قبل كم من الوقت من تاريخ انتهاء صلاحيتها يمكن تجديد رخصة CDL؟","options":["حتى 180 يوماً قبل انتهاء الصلاحية","حتى 30 يوماً قبل انتهاء الصلاحية","حتى 90 يوماً قبل انتهاء الصلاحية","فقط في تاريخ انتهاء الصلاحية أو بعده"],"explanation":"ينص القانون ORC 4506.14 على أن رخصة CDL قابلة للتجديد ابتداءً من 180 يوماً قبل انتهاء صلاحيتها عند دفع الرسوم المطلوبة. المصدر: Ohio Revised Code 4506.14."},"93":{"q":"يجوز لمسجِّل ولاية أوهايو إعفاء حامل رخصة CDL من اختبار التجديد فقط إذا قدم المتقدم رخصة CDL غير منتهية الصلاحية أو منتهية الصلاحية منذ مدة لا تزيد عن كم قبل تاريخ التقديم؟","options":["ستة أشهر","شهر واحد","ثلاثة أشهر","سنة واحدة"],"explanation":"يسمح القانون ORC 4506.14 للمسجِّل بإعفاء المتقدم من اختبار التجديد إذا قدم رخصة CDL غير منتهية الصلاحية، أو منتهية الصلاحية منذ مدة لا تزيد عن ستة أشهر قبل تاريخ التقديم. وبعد هذه المهلة، تُطلب إعادة الاختبار عموماً. المصدر: Ohio Revised Code 4506.14."},"94":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في ولاية أوهايو مقيَّدة بالقيادة داخل الولاية (داخل أوهايو فقط)؟","options":["18 عاماً","21 عاماً","19 عاماً","16 عاماً"],"explanation":"تحدد ولاية أوهايو الحد الأدنى لسن رخصة CDL بـ 18 عاماً للتشغيل داخل الولاية فقط؛ والسائقون دون 21 عاماً مقيَّدون بالقيادة داخل أوهايو. ويتطلب التشغيل بين الولايات ونقل المواد الخطرة سن 21 عاماً. المصدر: متطلبات CDL لدى Ohio BMV."},"95":{"q":"يجب أن يبلغ المتقدم في ولاية أوهايو من العمر كم على الأقل لقيادة مركبة نقل تجارية في التجارة بين الولايات أو لنقل المواد الخطرة؟","options":["21 عاماً","18 عاماً","23 عاماً","25 عاماً"],"explanation":"تتطلب القاعدة الفيدرالية المطبقة في ولاية أوهايو أن يبلغ السائق من العمر 21 عاماً على الأقل للعمل في التجارة بين الولايات أو لنقل مواد خطرة موضوعة عليها لوحات تحذيرية. والسائقون الذين تتراوح أعمارهم بين 18 و20 عاماً مقيَّدون بالقيادة داخل الولاية. المصدر: متطلبات CDL لدى Ohio BMV / 49 CFR 391.11."},"96":{"q":"إلى جانب رخصة قيادة سارية من ولاية أوهايو وإثبات رقم الضمان الاجتماعي، ما الذي يجب أيضاً على المتقدم لرخصة CDL لأول مرة في ولاية أوهايو تقديمه؟","options":["إثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية","خطاب موثَّق من صاحب عمل حالي","شهادة دبلوم المدرسة الثانوية أو شهادة GED","مرجعين شخصيين يحملان رخص CDL"],"explanation":"تتطلب ولاية أوهايو من المتقدمين لرخصة CDL لأول مرة تقديم رخصة قيادة سارية من ولاية أوهايو، ورقم ضمان اجتماعي ساري، وإثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية (مثل جواز السفر، أو شهادة الميلاد، أو بطاقة الإقامة الدائمة). المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."},"97":{"q":"يُقر سائق في ولاية أوهايو ذاتياً بأنه \"معفى بين الولايات\" (Excepted Interstate). ماذا تشير هذه الفئة بشأن متطلباته الطبية الفيدرالية؟","options":["إنه يقود عبر حدود الولايات لكنه غير مطالب باستيفاء المعايير الطبية الفيدرالية (Part 391)","إنه يقود داخل أوهايو فقط ويجب أن يستوفي المعايير الطبية للولاية","يجب أن يحمل دائماً شهادة فاحص طبي فيدرالية","إنه لا يستخدم رخصة CDL أبداً لأي غرض تجاري"],"explanation":"تعني فئة \"معفى بين الولايات\" أن السائق يعمل عبر حدود الولايات لكنه يتأهل للإعفاء من متطلبات التأهيل البدني الفيدرالية في 49 CFR Part 391، لذا لا تُطلب بطاقة طبية DOT لذلك التشغيل. المصدر: فئات الإقرار الذاتي لدى Ohio BMV (النموذج BMV 2159)."},"98":{"q":"عند إجراء اختبار مهارات CDL في ولاية أوهايو، من المسؤول عموماً عن توفير المركبة التجارية المستخدمة في الاختبار؟","options":["المتقدم، الذي يجب أن يوفر (أو يستأجر) مركبة ممثلة للفئة المطلوبة","Ohio BMV، الذي يحتفظ بأسطول من مركبات الاختبار","ODOT، التي تعير المركبات لاختبارات الطريق","المكتب الإقليمي لـ FMCSA"],"explanation":"تتطلب ولاية أوهايو من المتقدم توفير مركبة تجارية مناسبة ممثلة للفئة التي يُختبر عليها، أو استئجار واحدة (غالباً من خلال موقع اختبار تابع لطرف ثالث). ولا يوفر BMV مركبات الاختبار. المصدر: Ohio BMV، صفحة Commercial Driver (CDL)."}}};
